// Generated by build/build.py - do not edit by hand.
window.QUESTIONS = [{"id": "e01", "title": "Active Premium Subscribers", "difficulty": "Easy", "category": "Filtering", "companies": ["Netflix", "Spotify"], "description": "\n<p>You're an analyst at <strong>Streamio</strong>, a video streaming service. Marketing wants to send a\nthank-you email to everyone on the <code>premium</code> plan whose subscription is currently\n<code>active</code>.</p>\n<p>Write a query that returns the <code>name</code> and <code>country</code> of every active premium\nsubscriber, sorted alphabetically by name.</p>\n<p><strong>Return columns:</strong> <code>name</code>, <code>country</code> — ordered by <code>name</code> ascending.</p>\n", "schema": "\nCREATE TABLE subscribers (\n    sub_id      INTEGER PRIMARY KEY,\n    name        TEXT NOT NULL,\n    country     TEXT NOT NULL,\n    plan        TEXT NOT NULL,      -- 'basic', 'standard', 'premium'\n    status      TEXT NOT NULL,      -- 'active', 'paused', 'cancelled'\n    signup_date TEXT NOT NULL\n);\nINSERT INTO subscribers VALUES\n (1,  'Ava Chen',        'US', 'premium',  'active',    '2024-03-12'),\n (2,  'Liam Patel',      'IN', 'basic',    'active',    '2024-05-01'),\n (3,  'Sofia Rossi',     'IT', 'premium',  'cancelled', '2023-11-20'),\n (4,  'Noah Kim',        'KR', 'standard', 'active',    '2024-01-15'),\n (5,  'Emma Müller',     'DE', 'premium',  'active',    '2024-07-09'),\n (6,  'Lucas Silva',     'BR', 'premium',  'paused',    '2024-02-28'),\n (7,  'Mia Johnson',     'US', 'standard', 'cancelled', '2023-09-05'),\n (8,  'Yuki Tanaka',     'JP', 'premium',  'active',    '2025-01-22'),\n (9,  'Omar Haddad',     'AE', 'basic',    'paused',    '2024-10-30'),\n (10, 'Isabella Lopez',  'MX', 'premium',  'active',    '2024-12-14');\n", "solution": "\nSELECT name, country\nFROM subscribers\nWHERE plan = 'premium' AND status = 'active'\nORDER BY name;\n", "explanation": "\n<p>This is a pure <code>WHERE</code>-clause question. Both conditions must hold at the same time, so they\nare combined with <code>AND</code>. String comparisons in SQL use single quotes.</p>\n<p>The interviewer is checking that you don't confuse <code>AND</code>/<code>OR</code> precedence and that\nyou remember the <code>ORDER BY</code> the prompt asks for. In production you'd also confirm whether\nplan/status values are case-consistent before relying on equality checks.</p>\n", "hints": ["You need two conditions to be true at once — combine them in the WHERE clause.", "String literals use single quotes: plan = 'premium'.", "Don't forget the ORDER BY name the prompt asks for."], "order_matters": true}, {"id": "e02", "title": "Second Highest Salary", "difficulty": "Easy", "category": "Subqueries", "companies": ["Amazon", "Meta", "Adobe"], "description": "\n<p><strong>LedgerPay</strong>, a fintech startup, is benchmarking compensation. HR wants to know the\n<em>second highest distinct salary</em> across the whole company.</p>\n<p>Note that two employees share the top salary — your query must treat duplicate salaries as one value.\nIf you simply sort and take the second row, you'll get the wrong answer.</p>\n<p><strong>Return column:</strong> <code>second_salary</code> (a single row with a single value).</p>\n", "schema": "\nCREATE TABLE employees (\n    emp_id     INTEGER PRIMARY KEY,\n    name       TEXT NOT NULL,\n    department TEXT NOT NULL,\n    salary     INTEGER NOT NULL\n);\nINSERT INTO employees VALUES\n (1, 'Dana Wright',   'Engineering', 120000),\n (2, 'Raj Mehta',     'Engineering', 120000),\n (3, 'Lena Fischer',  'Product',     110000),\n (4, 'Tom Becker',    'Sales',        95000),\n (5, 'Aisha Bello',   'Marketing',    88000),\n (6, 'Chris Novak',   'Support',      61000),\n (7, 'Grace Liu',     'Engineering', 104000);\n", "solution": "\nSELECT MAX(salary) AS second_salary\nFROM employees\nWHERE salary < (SELECT MAX(salary) FROM employees);\n", "explanation": "\n<p>The classic approach: the second highest salary is the maximum of all salaries that are strictly less\nthan the overall maximum. The inner subquery finds the top salary (120000), and the outer\n<code>MAX</code> finds the best salary below it (110000).</p>\n<p>An equally valid approach uses <code>SELECT DISTINCT salary ORDER BY salary DESC LIMIT 1 OFFSET 1</code>.\nThe <code>DISTINCT</code> is essential — without it the duplicate 120000 would be returned. Interviewers\noften follow up with \"what if there is no second salary?\" — the subquery version naturally returns\n<code>NULL</code>.</p>\n", "hints": ["Two employees are tied at the top — sorting and taking row 2 returns the same max again.", "Think: 'the biggest salary that is smaller than the biggest salary'.", "Either MAX with a subquery, or DISTINCT + ORDER BY + LIMIT/OFFSET works."], "order_matters": false}, {"id": "e03", "title": "Customers Who Never Ordered", "difficulty": "Easy", "category": "Joins", "companies": ["Amazon", "Shopify"], "description": "\n<p><strong>Cartly</strong>, an e-commerce marketplace, wants to re-engage signed-up customers who have\nnever placed an order.</p>\n<p>Write a query that returns the <code>name</code> of every customer with <em>zero</em> orders.</p>\n<p><strong>Return column:</strong> <code>name</code> — any order.</p>\n", "schema": "\nCREATE TABLE customers (\n    customer_id INTEGER PRIMARY KEY,\n    name        TEXT NOT NULL,\n    joined_date TEXT NOT NULL\n);\nCREATE TABLE orders (\n    order_id    INTEGER PRIMARY KEY,\n    customer_id INTEGER NOT NULL,\n    amount      REAL NOT NULL,\n    order_date  TEXT NOT NULL\n);\nINSERT INTO customers VALUES\n (1, 'Harper Reed',   '2024-01-03'),\n (2, 'Diego Marin',   '2024-02-17'),\n (3, 'Pria Nair',     '2024-03-09'),\n (4, 'Sam Okafor',    '2024-04-21'),\n (5, 'Elena Petrova', '2024-05-30'),\n (6, 'Jack Murphy',   '2024-06-11');\nINSERT INTO orders VALUES\n (101, 1, 64.50,  '2024-02-01'),\n (102, 1, 19.99,  '2024-03-15'),\n (103, 3, 230.00, '2024-04-02'),\n (104, 5, 12.75,  '2024-06-20'),\n (105, 3, 89.10,  '2024-07-08');\n", "solution": "\nSELECT c.name\nFROM customers c\nLEFT JOIN orders o ON o.customer_id = c.customer_id\nWHERE o.order_id IS NULL;\n", "explanation": "\n<p>A <code>LEFT JOIN</code> keeps every customer; customers with no matching order get <code>NULL</code>\nin all the order columns. Filtering on <code>o.order_id IS NULL</code> isolates exactly those customers\n(Diego, Sam, Jack).</p>\n<p>Alternatives interviewers accept: <code>WHERE customer_id NOT IN (SELECT customer_id FROM orders)</code>\n(careful — this breaks if the subquery can return NULLs) or the safest pattern,\n<code>NOT EXISTS</code> with a correlated subquery.</p>\n", "hints": ["A LEFT JOIN keeps rows from the left table even when there is no match.", "What value do the order columns have for customers with no orders?", "NOT EXISTS or NOT IN (careful with NULLs!) are valid alternatives."], "order_matters": false}, {"id": "e04", "title": "Duplicate Emails", "difficulty": "Easy", "category": "Aggregation", "companies": ["Meta", "Salesforce"], "description": "\n<p>The CRM team at <strong>Salesloop</strong> suspects their contact list has duplicate sign-ups. A\ncontact is a duplicate if the same email appears more than once.</p>\n<p>Write a query returning each email that appears at least twice, along with how many times it appears.</p>\n<p><strong>Return columns:</strong> <code>email</code>, <code>times_seen</code> — any order.</p>\n", "schema": "\nCREATE TABLE contacts (\n    contact_id INTEGER PRIMARY KEY,\n    email      TEXT NOT NULL,\n    created_at TEXT NOT NULL\n);\nINSERT INTO contacts VALUES\n (1, 'jo@example.com',     '2025-01-04'),\n (2, 'amy@example.com',    '2025-01-06'),\n (3, 'jo@example.com',     '2025-01-11'),\n (4, 'kit@example.com',    '2025-01-12'),\n (5, 'amy@example.com',    '2025-02-02'),\n (6, 'jo@example.com',     '2025-02-09'),\n (7, 'lee@example.com',    '2025-02-15'),\n (8, 'zara@example.com',   '2025-03-01'),\n (9, 'kit@example.com',    '2025-03-03');\n", "solution": "\nSELECT email, COUNT(*) AS times_seen\nFROM contacts\nGROUP BY email\nHAVING COUNT(*) > 1;\n", "explanation": "\n<p><code>GROUP BY email</code> collapses the table to one row per email, and <code>COUNT(*)</code> counts\nrows within each group. The filter on the aggregate has to live in <code>HAVING</code>, not\n<code>WHERE</code> — <code>WHERE</code> runs before grouping, so it cannot see the counts.</p>\n<p>The <code>WHERE</code> vs <code>HAVING</code> distinction is one of the most common screening checks in\nSQL interviews.</p>\n", "hints": ["Group the rows so each email becomes one group.", "You need to filter on an aggregate (a count). WHERE can't do that.", "HAVING filters groups after aggregation."], "order_matters": false}, {"id": "e05", "title": "Top 5 Products by Revenue", "difficulty": "Easy", "category": "Aggregation", "companies": ["Amazon", "Walmart", "Flipkart"], "description": "\n<p><strong>Gadgetry</strong>, an electronics retailer, wants a leaderboard of its best-selling products.\nRevenue for a product is the sum of <code>quantity × unit_price</code> across all its order line items.</p>\n<p>Return the top 5 products by total revenue, highest first.</p>\n<p><strong>Return columns:</strong> <code>product_name</code>, <code>revenue</code> — ordered by\n<code>revenue</code> descending, limited to 5 rows.</p>\n", "schema": "\nCREATE TABLE products (\n    product_id INTEGER PRIMARY KEY,\n    name       TEXT NOT NULL,\n    category   TEXT NOT NULL\n);\nCREATE TABLE order_items (\n    item_id    INTEGER PRIMARY KEY,\n    product_id INTEGER NOT NULL,\n    quantity   INTEGER NOT NULL,\n    unit_price REAL NOT NULL\n);\nINSERT INTO products VALUES\n (1, 'Aurora Headphones', 'Audio'),\n (2, 'Pulse Smartwatch',  'Wearables'),\n (3, 'Nimbus Keyboard',   'Accessories'),\n (4, 'Volt Power Bank',   'Accessories'),\n (5, 'Echo Webcam',       'Video'),\n (6, 'Drift Mouse',       'Accessories'),\n (7, 'Beam Projector',    'Video');\nINSERT INTO order_items VALUES\n (1,  1, 2, 129.99),\n (2,  2, 1, 199.00),\n (3,  3, 3,  79.50),\n (4,  1, 1, 129.99),\n (5,  4, 5,  39.99),\n (6,  5, 2,  89.00),\n (7,  7, 1, 449.00),\n (8,  2, 2, 199.00),\n (9,  6, 4,  24.50),\n (10, 3, 1,  79.50),\n (11, 7, 1, 449.00),\n (12, 5, 1,  89.00);\n", "solution": "\nSELECT p.name AS product_name,\n       SUM(oi.quantity * oi.unit_price) AS revenue\nFROM products p\nJOIN order_items oi ON oi.product_id = p.product_id\nGROUP BY p.product_id, p.name\nORDER BY revenue DESC\nLIMIT 5;\n", "explanation": "\n<p>Join products to their line items, compute <code>SUM(quantity * unit_price)</code> per product, then\nsort descending and take 5. Grouping by the primary key (<code>product_id</code>) is safer than grouping\nby name alone, since two products could share a name.</p>\n<p>Note the multiplication happens <em>inside</em> the <code>SUM</code> — a frequent mistake is\n<code>SUM(quantity) * SUM(unit_price)</code>, which is mathematically wrong.</p>\n", "hints": ["Revenue per line item is quantity * unit_price; aggregate that per product.", "The multiplication goes inside SUM(), not outside.", "ORDER BY the aggregate descending, then LIMIT 5."], "order_matters": true}, {"id": "e06", "title": "Daily Completed Rides", "difficulty": "Easy", "category": "Aggregation", "companies": ["Uber", "Lyft", "DoorDash"], "description": "\n<p><strong>Swiftly</strong>, a ride-hailing company, tracks every ride request. Operations wants a daily\nreport of how many rides actually <em>completed</em> (ignore cancelled rides).</p>\n<p><strong>Return columns:</strong> <code>ride_date</code>, <code>completed_rides</code> — ordered by\n<code>ride_date</code> ascending. Days with zero completed rides may be omitted.</p>\n", "schema": "\nCREATE TABLE rides (\n    ride_id   INTEGER PRIMARY KEY,\n    city      TEXT NOT NULL,\n    ride_date TEXT NOT NULL,\n    fare      REAL,\n    status    TEXT NOT NULL   -- 'completed', 'cancelled_by_rider', 'cancelled_by_driver'\n);\nINSERT INTO rides VALUES\n (1,  'Austin',  '2025-04-01', 18.40, 'completed'),\n (2,  'Austin',  '2025-04-01', NULL,  'cancelled_by_rider'),\n (3,  'Dallas',  '2025-04-01', 22.10, 'completed'),\n (4,  'Austin',  '2025-04-02', 9.75,  'completed'),\n (5,  'Dallas',  '2025-04-02', NULL,  'cancelled_by_driver'),\n (6,  'Dallas',  '2025-04-02', 31.00, 'completed'),\n (7,  'Austin',  '2025-04-02', 12.30, 'completed'),\n (8,  'Austin',  '2025-04-03', NULL,  'cancelled_by_rider'),\n (9,  'Dallas',  '2025-04-03', NULL,  'cancelled_by_rider'),\n (10, 'Austin',  '2025-04-04', 27.60, 'completed'),\n (11, 'Dallas',  '2025-04-04', 16.85, 'completed'),\n (12, 'Austin',  '2025-04-04', 8.20,  'completed');\n", "solution": "\nSELECT ride_date, COUNT(*) AS completed_rides\nFROM rides\nWHERE status = 'completed'\nGROUP BY ride_date\nORDER BY ride_date;\n", "explanation": "\n<p>Filter first (<code>WHERE status = 'completed'</code>), then group by day and count. Because the\nfilter is on a raw column — not an aggregate — it belongs in <code>WHERE</code>, which is also more\nefficient since rows are discarded before grouping.</p>\n<p>Note 2025-04-03 disappears from the output entirely: both of its rides were cancelled. Interviewers\nsometimes follow up with \"how would you show that day with a 0?\" — that requires a calendar/date\ndimension table or a recursive date series, a good thing to mention.</p>\n", "hints": ["Filter to completed rides before you group.", "GROUP BY the date column and COUNT the rows in each group.", "This filter belongs in WHERE (raw column), not HAVING (aggregates)."], "order_matters": true}, {"id": "e07", "title": "Earning More Than the Boss", "difficulty": "Easy", "category": "Self-Joins", "companies": ["Google", "Microsoft"], "description": "\n<p>At <strong>Hexaware Labs</strong>, the employees table stores each person's manager as a reference to\nanother row in the same table. The CEO has no manager (<code>manager_id</code> is <code>NULL</code>).</p>\n<p>Find every employee who earns strictly more than their direct manager.</p>\n<p><strong>Return column:</strong> <code>employee</code> (the employee's name) — any order.</p>\n", "schema": "\nCREATE TABLE employees (\n    emp_id     INTEGER PRIMARY KEY,\n    name       TEXT NOT NULL,\n    salary     INTEGER NOT NULL,\n    manager_id INTEGER          -- NULL for the CEO\n);\nINSERT INTO employees VALUES\n (1, 'Priya Sharma',  185000, NULL),\n (2, 'Ben Carter',    140000, 1),\n (3, 'Olivia Stone',  152000, 1),\n (4, 'Marco Ruiz',    149000, 2),\n (5, 'Tina Wong',     131000, 2),\n (6, 'Felix Braun',   158000, 3),\n (7, 'Nora Quinn',    99000,  3),\n (8, 'Dev Anand',     162000, 4);\n", "solution": "\nSELECT e.name AS employee\nFROM employees e\nJOIN employees m ON m.emp_id = e.manager_id\nWHERE e.salary > m.salary;\n", "explanation": "\n<p>A self-join: alias the table twice — <code>e</code> for the employee, <code>m</code> for the manager —\nand join the employee's <code>manager_id</code> to the manager's <code>emp_id</code>. Then compare\nsalaries across the two aliases.</p>\n<p>Marco (149k &gt; Ben's 140k), Felix (158k &gt; Olivia's 152k), and Dev (162k &gt; Marco's 149k) qualify.\nThe CEO is excluded automatically because an inner join drops the row with a <code>NULL</code> manager.</p>\n", "hints": ["Join the table to itself with two different aliases.", "Match employee.manager_id to manager.emp_id.", "An INNER join naturally excludes the CEO (NULL manager)."], "order_matters": false}, {"id": "e08", "title": "Crowd Favorites", "difficulty": "Easy", "category": "Aggregation", "companies": ["Netflix", "IMDb"], "description": "\n<p><strong>Reelgood</strong>, a movie discovery app, wants to surface \"crowd favorites\": movies with an\naverage rating of at least <strong>4.0</strong> from at least <strong>3 ratings</strong> (a high average\nfrom one or two users isn't trustworthy).</p>\n<p><strong>Return columns:</strong> <code>title</code>, <code>avg_rating</code> (rounded to 2 decimal\nplaces) — any order.</p>\n", "schema": "\nCREATE TABLE movies (\n    movie_id INTEGER PRIMARY KEY,\n    title    TEXT NOT NULL\n);\nCREATE TABLE ratings (\n    rating_id INTEGER PRIMARY KEY,\n    movie_id  INTEGER NOT NULL,\n    user_id   INTEGER NOT NULL,\n    rating    INTEGER NOT NULL   -- 1 to 5\n);\nINSERT INTO movies VALUES\n (1, 'Midnight Circuit'),\n (2, 'The Paper Garden'),\n (3, 'Gravity Falls Apart'),\n (4, 'Solstice'),\n (5, 'Iron Harvest');\nINSERT INTO ratings VALUES\n (1,  1, 11, 5), (2,  1, 12, 4), (3,  1, 13, 5), (4,  1, 14, 3),\n (5,  2, 11, 5), (6,  2, 15, 5),\n (7,  3, 12, 4), (8,  3, 13, 4), (9,  3, 16, 5), (10, 3, 17, 4),\n (11, 4, 14, 2), (12, 4, 15, 3), (13, 4, 16, 3),\n (14, 5, 11, 4), (15, 5, 17, 5), (16, 5, 18, 2);\n", "solution": "\nSELECT m.title,\n       ROUND(AVG(r.rating), 2) AS avg_rating\nFROM movies m\nJOIN ratings r ON r.movie_id = m.movie_id\nGROUP BY m.movie_id, m.title\nHAVING AVG(r.rating) >= 4.0 AND COUNT(*) >= 3;\n", "explanation": "\n<p>Both conditions are on aggregates, so both live in <code>HAVING</code>. 'Midnight Circuit' averages\n4.25 over 4 ratings and 'Gravity Falls Apart' averages 4.25 over 4 ratings — they qualify. 'The Paper\nGarden' averages 5.0 but only has 2 ratings, so it's filtered out — exactly the trap the minimum-count\nrule exists to catch.</p>\n<p>Note that <code>AVG</code> of integers returns a float in SQLite; in some engines (e.g. older SQL\nServer) integer division bites here and you'd cast first.</p>\n", "hints": ["You need two aggregate conditions: an average and a count.", "Conditions on aggregates go in HAVING, combined with AND.", "ROUND(AVG(rating), 2) formats the average."], "order_matters": false}, {"id": "e09", "title": "Users and Their Cities", "difficulty": "Easy", "category": "Joins", "companies": ["Meta", "LinkedIn"], "description": "\n<p><strong>Townsquare</strong>, a social app, stores user profiles and (optionally) a home address.\nBuild a directory listing every user and the city they live in. Users who haven't added an address\nshould still appear, with a <code>NULL</code> city.</p>\n<p><strong>Return columns:</strong> <code>name</code>, <code>city</code> — any order.</p>\n", "schema": "\nCREATE TABLE users (\n    user_id INTEGER PRIMARY KEY,\n    name    TEXT NOT NULL\n);\nCREATE TABLE addresses (\n    address_id INTEGER PRIMARY KEY,\n    user_id    INTEGER NOT NULL,\n    city       TEXT NOT NULL,\n    state      TEXT NOT NULL\n);\nINSERT INTO users VALUES\n (1, 'Wren Adler'),\n (2, 'Kofi Mensah'),\n (3, 'Lara Voss'),\n (4, 'Theo Brandt'),\n (5, 'June Park');\nINSERT INTO addresses VALUES\n (1, 2, 'Seattle',  'WA'),\n (2, 3, 'Denver',   'CO'),\n (3, 5, 'Portland', 'OR');\n", "solution": "\nSELECT u.name, a.city\nFROM users u\nLEFT JOIN addresses a ON a.user_id = u.user_id;\n", "explanation": "\n<p>The requirement \"every user must appear, even without a match\" is the textbook signal for a\n<code>LEFT JOIN</code>. An inner join would silently drop Wren and Theo.</p>\n<p>This tests whether you reach for the right join type by reading the requirements, not by habit.\nA common interview follow-up: \"what happens if a user somehow has two addresses?\" — the user would\nappear twice, which is why production queries often deduplicate or pick a primary address.</p>\n", "hints": ["Every user must appear even with no address — which join keeps unmatched rows?", "LEFT JOIN from users to addresses.", "Unmatched rows show NULL for the address columns — that's expected."], "order_matters": false}, {"id": "e10", "title": "Order Size Buckets", "difficulty": "Easy", "category": "CASE Expressions", "companies": ["Shopify", "Stripe"], "description": "\n<p>The growth team at <strong>Bagelbox</strong>, a subscription food service, segments orders into size\nbuckets:</p>\n<ul>\n<li><code>small</code> — amount under $50</li>\n<li><code>medium</code> — amount from $50 to $200 (inclusive on both ends)</li>\n<li><code>large</code> — amount over $200</li>\n</ul>\n<p>Count how many orders fall into each bucket.</p>\n<p><strong>Return columns:</strong> <code>size_category</code>, <code>order_count</code> — any order.</p>\n", "schema": "\nCREATE TABLE orders (\n    order_id   INTEGER PRIMARY KEY,\n    customer_id INTEGER NOT NULL,\n    amount     REAL NOT NULL,\n    order_date TEXT NOT NULL\n);\nINSERT INTO orders VALUES\n (1,  201, 23.50,  '2025-02-01'),\n (2,  202, 50.00,  '2025-02-01'),\n (3,  203, 310.25, '2025-02-02'),\n (4,  201, 75.80,  '2025-02-03'),\n (5,  204, 200.00, '2025-02-04'),\n (6,  205, 12.99,  '2025-02-05'),\n (7,  202, 540.00, '2025-02-06'),\n (8,  206, 49.99,  '2025-02-07'),\n (9,  203, 150.00, '2025-02-08'),\n (10, 207, 201.10, '2025-02-09');\n", "solution": "\nSELECT CASE\n         WHEN amount < 50 THEN 'small'\n         WHEN amount <= 200 THEN 'medium'\n         ELSE 'large'\n       END AS size_category,\n       COUNT(*) AS order_count\nFROM orders\nGROUP BY size_category;\n", "explanation": "\n<p><code>CASE</code> expressions evaluate top-down and stop at the first match, so the second branch\nonly needs <code>amount &lt;= 200</code> — anything under 50 was already captured. The boundary rows are\nthe real test: $50.00 and $200.00 are <em>medium</em>, $201.10 is <em>large</em>, $49.99 is\n<em>small</em>.</p>\n<p>SQLite lets you reference the alias <code>size_category</code> in <code>GROUP BY</code>; in engines\nthat don't, you'd repeat the whole CASE expression or wrap it in a subquery.</p>\n", "hints": ["Build the bucket label with a CASE expression.", "CASE branches evaluate in order — use that to simplify range checks.", "Watch the boundaries: 50 and 200 are both 'medium'."], "order_matters": false}, {"id": "e11", "title": "Revenue by Category", "difficulty": "Easy", "category": "Joins", "companies": ["Walmart", "Target", "Amazon"], "description": "\n<p><strong>Loft &amp; Ladder</strong>, a home goods retailer, needs a category-level revenue report for a\nboard deck. Revenue is <code>quantity × unit_price</code> summed over all line items of products in that\ncategory.</p>\n<p><strong>Return columns:</strong> <code>category</code>, <code>total_revenue</code> (rounded to 2\ndecimals) — ordered by <code>total_revenue</code> descending.</p>\n", "schema": "\nCREATE TABLE products (\n    product_id INTEGER PRIMARY KEY,\n    name       TEXT NOT NULL,\n    category   TEXT NOT NULL\n);\nCREATE TABLE order_items (\n    item_id    INTEGER PRIMARY KEY,\n    product_id INTEGER NOT NULL,\n    quantity   INTEGER NOT NULL,\n    unit_price REAL NOT NULL\n);\nINSERT INTO products VALUES\n (1, 'Oak Bookshelf',    'Furniture'),\n (2, 'Linen Throw',      'Textiles'),\n (3, 'Ceramic Vase',     'Decor'),\n (4, 'Walnut Desk',      'Furniture'),\n (5, 'Wool Rug',         'Textiles'),\n (6, 'Brass Lamp',       'Decor'),\n (7, 'Velvet Cushion',   'Textiles');\nINSERT INTO order_items VALUES\n (1,  1, 1, 249.00),\n (2,  2, 3, 45.50),\n (3,  3, 2, 38.00),\n (4,  4, 1, 599.00),\n (5,  5, 1, 320.00),\n (6,  6, 2, 89.99),\n (7,  7, 4, 29.99),\n (8,  1, 1, 249.00),\n (9,  3, 1, 38.00),\n (10, 2, 2, 45.50);\n", "solution": "\nSELECT p.category,\n       ROUND(SUM(oi.quantity * oi.unit_price), 2) AS total_revenue\nFROM products p\nJOIN order_items oi ON oi.product_id = p.product_id\nGROUP BY p.category\nORDER BY total_revenue DESC;\n", "explanation": "\n<p>Same join-then-aggregate pattern as the product leaderboard, but grouped one level higher — by\ncategory. Furniture totals $1,097.00, Textiles $576.46, Decor $293.98.</p>\n<p>In a real warehouse this would be a star-schema query: fact table (<code>order_items</code>) joined to\na dimension (<code>products</code>), aggregated by a dimension attribute. Saying that out loud in a data\nengineering interview earns points.</p>\n", "hints": ["Join line items to products to get each item's category.", "GROUP BY category, SUM(quantity * unit_price).", "Order by the rounded total, descending."], "order_matters": true}, {"id": "e12", "title": "Stale or Incomplete Accounts", "difficulty": "Easy", "category": "NULL Handling", "companies": ["Dropbox", "Atlassian"], "description": "\n<p><strong>Fileforge</strong>, a cloud storage product, is auditing accounts for cleanup. An account is a\ncleanup candidate if it has <em>no email on file</em> (<code>NULL</code>) <em>or</em> its last login was\nbefore <code>2025-01-01</code>.</p>\n<p>Careful: comparisons with <code>NULL</code> never evaluate to true — <code>email != ''</code> won't\ncatch missing emails.</p>\n<p><strong>Return columns:</strong> <code>account_id</code>, <code>username</code> — any order.</p>\n", "schema": "\nCREATE TABLE accounts (\n    account_id INTEGER PRIMARY KEY,\n    username   TEXT NOT NULL,\n    email      TEXT,              -- NULL if never provided\n    last_login TEXT               -- NULL if never logged in\n);\nINSERT INTO accounts VALUES\n (1, 'sky_walker',  'sky@mail.com',   '2025-03-14'),\n (2, 'pixel_pete',  NULL,             '2025-04-02'),\n (3, 'quietfox',    'fox@mail.com',   '2024-08-19'),\n (4, 'mango_dev',   'mango@mail.com', '2025-05-21'),\n (5, 'lostuser99',  NULL,             '2024-02-11'),\n (6, 'nova_r',      'nova@mail.com',  '2024-12-31'),\n (7, 'beta_tester', 'beta@mail.com',  '2025-01-01');\n", "solution": "\nSELECT account_id, username\nFROM accounts\nWHERE email IS NULL\n   OR last_login < '2025-01-01';\n", "explanation": "\n<p>The two correct ingredients: <code>IS NULL</code> (never <code>= NULL</code>, which is always unknown)\nand a plain string comparison on ISO-8601 dates, which sort correctly as text.</p>\n<p>Edge rows: <code>nova_r</code> logged in 2024-12-31 → included; <code>beta_tester</code> logged in\nexactly 2025-01-01 → excluded (\"before\" is strict). <code>pixel_pete</code> has a recent login but no\nemail → included via the OR branch. NULL three-valued logic is among the most reliable sources of\nproduction bugs, which is why interviewers love it.</p>\n", "hints": ["= NULL never matches anything. What's the correct operator?", "ISO dates (YYYY-MM-DD) compare correctly as plain strings.", "It's an OR — either condition alone qualifies the account."], "order_matters": false}, {"id": "e13", "title": "Users Across Two Platforms", "difficulty": "Easy", "category": "Set Operations", "companies": ["Spotify", "Snap"], "description": "\n<p><strong>Chirper</strong> ships separate iOS and Android builds, and (regrettably) the events land in\ntwo separate tables. Product wants one deduplicated list of every user who was active on\n<em>either</em> platform.</p>\n<p>A user who appears in both tables — or several times in one — must appear exactly once.</p>\n<p><strong>Return column:</strong> <code>user_id</code> — ordered ascending.</p>\n", "schema": "\nCREATE TABLE ios_events (\n    event_id   INTEGER PRIMARY KEY,\n    user_id    INTEGER NOT NULL,\n    event_date TEXT NOT NULL\n);\nCREATE TABLE android_events (\n    event_id   INTEGER PRIMARY KEY,\n    user_id    INTEGER NOT NULL,\n    event_date TEXT NOT NULL\n);\nINSERT INTO ios_events VALUES\n (1, 501, '2025-05-01'),\n (2, 502, '2025-05-01'),\n (3, 501, '2025-05-02'),\n (4, 504, '2025-05-03'),\n (5, 506, '2025-05-04');\nINSERT INTO android_events VALUES\n (1, 502, '2025-05-01'),\n (2, 503, '2025-05-02'),\n (3, 505, '2025-05-02'),\n (4, 503, '2025-05-03'),\n (5, 506, '2025-05-05');\n", "solution": "\nSELECT user_id FROM ios_events\nUNION\nSELECT user_id FROM android_events\nORDER BY user_id;\n", "explanation": "\n<p><code>UNION</code> stacks two result sets <em>and removes duplicates</em> — both across the two tables\n(users 502 and 506 appear in each) and within one table (501 has two iOS events). Its sibling\n<code>UNION ALL</code> keeps duplicates and is much cheaper, since it skips the dedup step.</p>\n<p>The interview talking point: default to <code>UNION ALL</code> in pipelines unless you specifically\nneed dedup — on billions of rows the implicit DISTINCT of <code>UNION</code> is an expensive surprise.\nExpected output: 501–506, six rows.</p>\n", "hints": ["Two tables with the same shape need to be stacked vertically — that's a set operation, not a join.", "UNION vs UNION ALL: one of them deduplicates.", "A single ORDER BY at the end sorts the combined result."], "order_matters": true}, {"id": "e14", "title": "Finding Refund Tickets", "difficulty": "Easy", "category": "String Functions", "companies": ["Zendesk", "Shopify"], "description": "\n<p>The support team at <strong>Parcelry</strong> triages tickets by keyword. Find every ticket whose\nsubject mentions <code>refund</code> in <em>any</em> capitalization — \"Refund\", \"REFUND\", and\n\"refund\" all count, and the word can appear anywhere in the subject.</p>\n<p><strong>Return columns:</strong> <code>ticket_id</code>, <code>subject</code> — any order.</p>\n", "schema": "\nCREATE TABLE tickets (\n    ticket_id  INTEGER PRIMARY KEY,\n    subject    TEXT NOT NULL,\n    created_at TEXT NOT NULL\n);\nINSERT INTO tickets VALUES\n (1, 'Refund for damaged package',           '2025-06-01'),\n (2, 'Where is my order?',                   '2025-06-01'),\n (3, 'Please process my REFUND immediately', '2025-06-02'),\n (4, 'Change delivery address',              '2025-06-02'),\n (5, 'partial refund request',               '2025-06-03'),\n (6, 'App crashes on login',                 '2025-06-03'),\n (7, 'Refunding my subscription fee',        '2025-06-04'),\n (8, 'Damaged box, want money back',         '2025-06-04');\n", "solution": "\nSELECT ticket_id, subject\nFROM tickets\nWHERE LOWER(subject) LIKE '%refund%';\n", "explanation": "\n<p>Lowercasing the column first makes the match case-insensitive in any engine, and the\n<code>%</code> wildcards on both sides mean \"anywhere in the string.\" Note that ticket 7\n(\"Refund<em>ing</em>\") matches too — substring matching doesn't respect word boundaries, and ticket 8\n(\"want money back\") doesn't match at all despite clearly being a refund request.</p>\n<p>Both make the real-world point interviewers want to hear: keyword <code>LIKE</code> filters are crude.\nWord-boundary regexes, full-text indexes, or a classifier are the production answers — but\n<code>LIKE</code> is still the first tool for quick triage. (SQLite's <code>LIKE</code> happens to be\ncase-insensitive for ASCII already; <code>LOWER()</code> makes your intent portable.)</p>\n", "hints": ["LIKE with % wildcards matches substrings: '%word%'.", "Normalize case first — LOWER(subject) — so any capitalization matches.", "No need for OR chains; one normalized pattern covers all variants."], "order_matters": false}, {"id": "e15", "title": "Cheapest and Priciest per Category", "difficulty": "Easy", "category": "Aggregation", "companies": ["eBay", "Craigslist"], "description": "\n<p><strong>Swapmeet</strong>, a second-hand marketplace, shows a price range on every category page:\nthe cheapest and most expensive active listing.</p>\n<p><strong>Return columns:</strong> <code>category</code>, <code>min_price</code>,\n<code>max_price</code> — ordered by <code>category</code> ascending.</p>\n", "schema": "\nCREATE TABLE listings (\n    listing_id INTEGER PRIMARY KEY,\n    category   TEXT NOT NULL,\n    title      TEXT NOT NULL,\n    price      REAL NOT NULL\n);\nINSERT INTO listings VALUES\n (1,  'Bikes',   'Vintage road bike',     280.00),\n (2,  'Bikes',   'Kids mountain bike',     95.00),\n (3,  'Bikes',   'Carbon gravel bike',   1450.00),\n (4,  'Cameras', 'Film SLR with lens',    175.00),\n (5,  'Cameras', 'Action cam',             89.50),\n (6,  'Cameras', 'Mirrorless body',       640.00),\n (7,  'Laptops', '13-inch ultrabook',     520.00),\n (8,  'Laptops', 'Gaming laptop',         980.00),\n (9,  'Laptops', 'Old netbook',            60.00),\n (10, 'Bikes',   'Folding commuter',      330.00);\n", "solution": "\nSELECT category,\n       MIN(price) AS min_price,\n       MAX(price) AS max_price\nFROM listings\nGROUP BY category\nORDER BY category;\n", "explanation": "\n<p>Multiple aggregates over the same groups in a single pass — <code>MIN</code> and <code>MAX</code>\nside by side. Bikes: 95–1450, Cameras: 89.50–640, Laptops: 60–980.</p>\n<p>The natural follow-up an interviewer will ask: \"now give me the <em>title</em> of the cheapest listing\nper category.\" That's a different problem — <code>MIN(price)</code> with <code>title</code> in the SELECT\nis non-deterministic in most engines — and the answer is a window function\n(<code>ROW_NUMBER() ... ORDER BY price</code>), which the medium set drills.</p>\n", "hints": ["One GROUP BY can feed several aggregate functions at once.", "MIN(price) and MAX(price) in the same SELECT.", "No HAVING needed — nothing is being filtered."], "order_matters": true}, {"id": "e16", "title": "Orders by Day of Week", "difficulty": "Easy", "category": "Date/Time", "companies": ["DoorDash", "Domino's"], "description": "\n<p><strong>Bagelbox</strong> suspects weekends drive most of its orders and wants order counts by day of\nweek to plan kitchen staffing.</p>\n<p>In SQLite, <code>strftime('%w', date)</code> returns the weekday as a string, <code>'0'</code> =\nSunday through <code>'6'</code> = Saturday.</p>\n<p><strong>Return columns:</strong> <code>weekday_num</code>, <code>order_count</code> — ordered by\n<code>weekday_num</code> ascending. Weekdays with no orders may be omitted.</p>\n", "schema": "\nCREATE TABLE orders (\n    order_id   INTEGER PRIMARY KEY,\n    order_date TEXT NOT NULL,\n    amount     REAL NOT NULL\n);\nINSERT INTO orders VALUES\n (1,  '2025-06-01', 32.50),  -- Sunday\n (2,  '2025-06-02', 18.00),  -- Monday\n (3,  '2025-06-06', 45.25),  -- Friday\n (4,  '2025-06-07', 38.10),  -- Saturday\n (5,  '2025-06-07', 22.75),  -- Saturday\n (6,  '2025-06-08', 29.00),  -- Sunday\n (7,  '2025-06-08', 51.30),  -- Sunday\n (8,  '2025-06-09', 16.45),  -- Monday\n (9,  '2025-06-13', 33.20),  -- Friday\n (10, '2025-06-14', 27.85),  -- Saturday\n (11, '2025-06-14', 40.00),  -- Saturday\n (12, '2025-06-15', 35.60);  -- Sunday\n", "solution": "\nSELECT strftime('%w', order_date) AS weekday_num,\n       COUNT(*) AS order_count\nFROM orders\nGROUP BY weekday_num\nORDER BY weekday_num;\n", "explanation": "\n<p>Grouping by a <em>derived expression</em> rather than a raw column — the bread and butter of date\nanalytics. Sunday (0) → 4 orders, Monday (1) → 2, Friday (5) → 2, Saturday (6) → 4: the weekend\nhypothesis holds.</p>\n<p>Every warehouse has its own spelling — <code>EXTRACT(DOW FROM ...)</code> in Postgres,\n<code>DAYOFWEEK</code> in BigQuery (which is 1-based!), <code>DATE_PART</code> in Snowflake/Redshift.\nThe off-by-one between engines is a genuinely common production bug; saying so in an interview signals\nexperience. Tuesday–Thursday have no orders and vanish from the output — joining against a\n0-to-6 calendar would fill them in.</p>\n", "hints": ["Extract the weekday from each date, then group by that expression.", "SQLite: strftime('%w', order_date) — '0' is Sunday.", "COUNT(*) per group; order by the weekday value."], "order_matters": true}, {"id": "m01", "title": "Top Earner in Each Department", "difficulty": "Medium", "category": "Window Functions", "companies": ["Amazon", "Microsoft", "Apple"], "description": "\n<p>HR at <strong>Vantage Systems</strong> wants the highest-paid employee in every department for a comp\nreview. If two people tie for the top salary in a department, return <em>both</em>.</p>\n<p><strong>Return columns:</strong> <code>dept_name</code>, <code>employee</code>, <code>salary</code> —\nany order.</p>\n", "schema": "\nCREATE TABLE departments (\n    dept_id   INTEGER PRIMARY KEY,\n    dept_name TEXT NOT NULL\n);\nCREATE TABLE employees (\n    emp_id  INTEGER PRIMARY KEY,\n    name    TEXT NOT NULL,\n    salary  INTEGER NOT NULL,\n    dept_id INTEGER NOT NULL\n);\nINSERT INTO departments VALUES\n (1, 'Engineering'), (2, 'Sales'), (3, 'Design');\nINSERT INTO employees VALUES\n (1, 'Ira Glass',     142000, 1),\n (2, 'Mona Diaz',     155000, 1),\n (3, 'Kyle Renner',   155000, 1),\n (4, 'Suki Ito',      121000, 1),\n (5, 'Pat Boyle',      98000, 2),\n (6, 'Gail Strand',   104000, 2),\n (7, 'Ravi Kapoor',    87000, 2),\n (8, 'Fern Ellis',    112000, 3),\n (9, 'Drew Holt',     109000, 3);\n", "solution": "\nWITH ranked AS (\n    SELECT d.dept_name,\n           e.name AS employee,\n           e.salary,\n           RANK() OVER (PARTITION BY e.dept_id ORDER BY e.salary DESC) AS rnk\n    FROM employees e\n    JOIN departments d ON d.dept_id = e.dept_id\n)\nSELECT dept_name, employee, salary\nFROM ranked\nWHERE rnk = 1;\n", "explanation": "\n<p><code>RANK() OVER (PARTITION BY dept ORDER BY salary DESC)</code> restarts the ranking inside each\ndepartment. <code>RANK</code> (not <code>ROW_NUMBER</code>) is the right tool because it assigns the same\nrank to ties — Mona and Kyle both rank 1 in Engineering and both must be returned.</p>\n<p>A correlated-subquery version (<code>WHERE salary = (SELECT MAX(salary) ... same dept)</code>) is also\naccepted in interviews; mention the window-function form, since it scans the table once instead of once\nper row.</p>\n", "hints": ["You need a per-group maximum that keeps ties.", "PARTITION BY department in a window function restarts the calculation per department.", "RANK() keeps ties at 1; ROW_NUMBER() would arbitrarily drop one of them."], "order_matters": false}, {"id": "m02", "title": "Monthly Active Users", "difficulty": "Medium", "category": "Date/Time", "companies": ["Meta", "Snap", "TikTok"], "description": "\n<p><strong>Chirper</strong>, a social network, defines Monthly Active Users (MAU) as the number of\n<em>distinct</em> users who triggered at least one event in a calendar month.</p>\n<p>Compute MAU for every month present in the events table.</p>\n<p><strong>Return columns:</strong> <code>month</code> (format <code>YYYY-MM</code>), <code>mau</code> —\nordered by <code>month</code> ascending.</p>\n", "schema": "\nCREATE TABLE events (\n    event_id   INTEGER PRIMARY KEY,\n    user_id    INTEGER NOT NULL,\n    event_type TEXT NOT NULL,\n    event_time TEXT NOT NULL     -- 'YYYY-MM-DD HH:MM:SS'\n);\nINSERT INTO events VALUES\n (1,  101, 'post',  '2025-01-03 09:12:00'),\n (2,  102, 'like',  '2025-01-05 14:30:00'),\n (3,  101, 'like',  '2025-01-18 11:02:00'),\n (4,  103, 'post',  '2025-01-22 19:45:00'),\n (5,  101, 'post',  '2025-02-01 08:00:00'),\n (6,  104, 'like',  '2025-02-09 16:20:00'),\n (7,  104, 'post',  '2025-02-09 16:25:00'),\n (8,  102, 'post',  '2025-02-14 10:10:00'),\n (9,  105, 'like',  '2025-02-27 21:05:00'),\n (10, 103, 'like',  '2025-03-02 12:00:00'),\n (11, 103, 'post',  '2025-03-15 13:30:00'),\n (12, 106, 'post',  '2025-03-20 18:40:00'),\n (13, 101, 'like',  '2025-03-28 07:55:00');\n", "solution": "\nSELECT strftime('%Y-%m', event_time) AS month,\n       COUNT(DISTINCT user_id) AS mau\nFROM events\nGROUP BY month\nORDER BY month;\n", "explanation": "\n<p>Two ideas combine here: truncating a timestamp to its month (<code>strftime('%Y-%m', ...)</code> in\nSQLite; <code>DATE_TRUNC</code> in Postgres/Snowflake) and counting <em>distinct</em> users rather than\nevents. User 104 fires two events in February but counts once — <code>COUNT(*)</code> would inflate MAU,\na bug that has shipped to real dashboards more than once.</p>\n<p>January MAU is 3, February 4, March 3.</p>\n", "hints": ["Truncate the timestamp to a month bucket — strftime('%Y-%m', event_time).", "A user with five events in a month still counts once.", "COUNT(DISTINCT user_id), grouped by the month expression."], "order_matters": true}, {"id": "m03", "title": "Leaderboard with Dense Ranking", "difficulty": "Medium", "category": "Window Functions", "companies": ["Activision", "Roblox", "Google"], "description": "\n<p><strong>Blockfall</strong>, a mobile game, shows a global leaderboard. Players with equal points share\nthe same rank, and ranks must have <em>no gaps</em> (if two players tie at rank 2, the next player is\nrank 3, not 4).</p>\n<p><strong>Return columns:</strong> <code>player</code>, <code>points</code>, <code>player_rank</code> —\nordered by <code>player_rank</code> ascending, then <code>player</code> ascending.</p>\n", "schema": "\nCREATE TABLE scores (\n    score_id INTEGER PRIMARY KEY,\n    player   TEXT NOT NULL,\n    points   INTEGER NOT NULL\n);\nINSERT INTO scores VALUES\n (1, 'frostbyte',   2840),\n (2, 'lunarmoth',   3120),\n (3, 'pixelpunk',   2840),\n (4, 'quasar_kid',  1990),\n (5, 'renegade7',   3120),\n (6, 'softcrash',   2210),\n (7, 'tetra',       1990),\n (8, 'voidwalker',  2750);\n", "solution": "\nSELECT player,\n       points,\n       DENSE_RANK() OVER (ORDER BY points DESC) AS player_rank\nFROM scores\nORDER BY player_rank, player;\n", "explanation": "\n<p>The \"no gaps\" requirement is the tell for <code>DENSE_RANK()</code>. The three ranking functions differ\nonly in how they treat ties: <code>ROW_NUMBER</code> breaks ties arbitrarily (1,2,3,4),\n<code>RANK</code> leaves gaps (1,1,3), <code>DENSE_RANK</code> doesn't (1,1,2).</p>\n<p>Here lunarmoth and renegade7 tie at 3120 → rank 1, voidwalker (2750) → rank 3 with <code>RANK</code>\nbut rank 2 with <code>DENSE_RANK</code> — the data is built so the wrong function produces a visibly\nwrong answer.</p>\n", "hints": ["Three ranking functions exist: ROW_NUMBER, RANK, DENSE_RANK. They differ on ties.", "'No gaps after ties' picks one of them specifically.", "Remember the final ORDER BY — output order is part of the spec here."], "order_matters": true}, {"id": "m04", "title": "Warmer Than the Day Before", "difficulty": "Medium", "category": "Self-Joins", "companies": ["Google", "Palantir"], "description": "\n<p>A weather station logs one temperature reading per day — but the sensor sometimes fails, so some days\nare <em>missing</em>. Find every date whose temperature was strictly higher than the reading on the\n<em>previous calendar day</em>. If the previous calendar day is missing, the date doesn't qualify.</p>\n<p>⚠️ A plain <code>LAG()</code> over the ordered rows compares against the <em>previous row</em>, which\nmay be several days earlier — the data contains a gap to catch exactly that mistake.</p>\n<p><strong>Return column:</strong> <code>reading_date</code> — any order.</p>\n", "schema": "\nCREATE TABLE readings (\n    reading_date TEXT PRIMARY KEY,\n    temp_c       REAL NOT NULL\n);\nINSERT INTO readings VALUES\n ('2025-03-01', 11.5),\n ('2025-03-02', 13.0),\n ('2025-03-03', 12.1),\n ('2025-03-04', 15.4),\n -- 2025-03-05 missing: sensor failure\n ('2025-03-06', 19.0),\n ('2025-03-07', 17.2),\n ('2025-03-08', 18.9);\n", "solution": "\nSELECT today.reading_date\nFROM readings today\nJOIN readings yesterday\n  ON yesterday.reading_date = date(today.reading_date, '-1 day')\nWHERE today.temp_c > yesterday.temp_c;\n", "explanation": "\n<p>The join condition does the date arithmetic explicitly: a row only qualifies if a reading exists for\nexactly one calendar day earlier. 2025-03-06 (19.0°) is <em>not</em> returned even though it's warmer\nthan the last available reading, because 2025-03-05 is missing.</p>\n<p>A <code>LAG()</code> solution is fine <em>if</em> you also check the lagged date:\n<code>LAG(reading_date)</code> must equal <code>date(reading_date, '-1 day')</code>. Interviewers use the\ngap to separate candidates who think about data quality from those who pattern-match.</p>\n", "hints": ["'Previous calendar day' is not the same as 'previous row' when days are missing.", "Self-join the table to itself, offsetting the date by one day in the join condition.", "SQLite: date(reading_date, '-1 day'). If you use LAG, also lag the date and verify it."], "order_matters": false}, {"id": "m05", "title": "Latest Status per Shipment", "difficulty": "Medium", "category": "Window Functions", "companies": ["FedEx", "Flexport", "Amazon"], "description": "\n<p><strong>Parcelry</strong>, a logistics platform, stores an append-only event log: every status change\nof every shipment is a new row. The tracking page needs each shipment's <em>current</em> (most recent)\nstatus.</p>\n<p>This \"latest record per entity\" pattern is one of the most common real-world data engineering tasks —\nevent logs, CDC streams, and SCD tables all need it.</p>\n<p><strong>Return columns:</strong> <code>shipment_id</code>, <code>status</code> — any order.</p>\n", "schema": "\nCREATE TABLE shipment_events (\n    event_id    INTEGER PRIMARY KEY,\n    shipment_id INTEGER NOT NULL,\n    status      TEXT NOT NULL,\n    event_time  TEXT NOT NULL\n);\nINSERT INTO shipment_events VALUES\n (1,  501, 'label_created', '2025-05-01 08:00:00'),\n (2,  501, 'picked_up',     '2025-05-01 14:30:00'),\n (3,  501, 'in_transit',    '2025-05-02 06:15:00'),\n (4,  501, 'delivered',     '2025-05-04 11:42:00'),\n (5,  502, 'label_created', '2025-05-02 09:10:00'),\n (6,  502, 'picked_up',     '2025-05-03 10:05:00'),\n (7,  502, 'in_transit',    '2025-05-03 22:48:00'),\n (8,  503, 'label_created', '2025-05-04 16:20:00'),\n (9,  504, 'label_created', '2025-05-01 12:00:00'),\n (10, 504, 'picked_up',     '2025-05-02 09:30:00'),\n (11, 504, 'in_transit',    '2025-05-02 18:55:00'),\n (12, 504, 'out_for_delivery', '2025-05-05 07:25:00');\n", "solution": "\nWITH numbered AS (\n    SELECT shipment_id,\n           status,\n           ROW_NUMBER() OVER (\n               PARTITION BY shipment_id\n               ORDER BY event_time DESC\n           ) AS rn\n    FROM shipment_events\n)\nSELECT shipment_id, status\nFROM numbered\nWHERE rn = 1;\n", "explanation": "\n<p><code>ROW_NUMBER()</code> partitioned by shipment and ordered by time <em>descending</em> stamps the\nnewest event of each shipment with 1; keep those rows. This is the canonical deduplication idiom in\nwarehouses (BigQuery's <code>QUALIFY rn = 1</code>, Snowflake's same).</p>\n<p>The tempting shortcut <code>GROUP BY shipment_id</code> + <code>MAX(event_time)</code> needs a join\nback to fetch the status — selecting <code>status</code> alongside <code>MAX(event_time)</code> without\nthat join is non-deterministic in most engines (SQLite happens to allow it as a documented quirk, but\ndon't rely on it in interviews).</p>\n", "hints": ["You want exactly one row per shipment — the newest one.", "ROW_NUMBER() OVER (PARTITION BY shipment_id ORDER BY event_time DESC).", "Wrap it in a CTE and keep rows where the row number is 1."], "order_matters": false}, {"id": "m06", "title": "Running Revenue Total", "difficulty": "Medium", "category": "Window Functions", "companies": ["Stripe", "Square", "PayPal"], "description": "\n<p>Finance at <strong>Brewline</strong>, a coffee subscription company, wants a chart of cumulative\nrevenue through the month: for each day, the day's revenue plus everything before it.</p>\n<p><strong>Return columns:</strong> <code>sale_date</code>, <code>revenue</code>,\n<code>running_total</code> — ordered by <code>sale_date</code> ascending.</p>\n", "schema": "\nCREATE TABLE daily_revenue (\n    sale_date TEXT PRIMARY KEY,\n    revenue   REAL NOT NULL\n);\nINSERT INTO daily_revenue VALUES\n ('2025-06-01', 1240.00),\n ('2025-06-02',  980.50),\n ('2025-06-03', 1530.25),\n ('2025-06-04',  640.00),\n ('2025-06-05', 2210.75),\n ('2025-06-06', 1875.00),\n ('2025-06-07',  990.40);\n", "solution": "\nSELECT sale_date,\n       revenue,\n       SUM(revenue) OVER (ORDER BY sale_date) AS running_total\nFROM daily_revenue\nORDER BY sale_date;\n", "explanation": "\n<p>A windowed <code>SUM</code> with only an <code>ORDER BY</code> (no <code>PARTITION BY</code>) defaults\nto the frame <em>unbounded preceding → current row</em>, which is exactly a running total. No self-join,\nno correlated subquery needed.</p>\n<p>The pre-window-function way — joining the table to itself on <code>b.sale_date &lt;=\na.sale_date</code> — still works and is worth knowing, but it's O(n²) and interviewers expect you to\nreach for the window function first.</p>\n", "hints": ["This is an aggregate that doesn't collapse rows — that's a window function.", "SUM(...) OVER (ORDER BY sale_date).", "With ORDER BY in the window, the default frame is 'everything up to this row'."], "order_matters": true}, {"id": "m07", "title": "Repeat Customer Rate", "difficulty": "Medium", "category": "Aggregation", "companies": ["DoorDash", "Instacart", "Uber Eats"], "description": "\n<p><strong>Forkful</strong>, a food delivery app, tracks loyalty with one number: of all customers who\nhave ever ordered, what percentage ordered <em>more than once</em>?</p>\n<p><strong>Return column:</strong> <code>repeat_rate</code> — a single value, as a percentage rounded to\n1 decimal place (e.g. <code>57.1</code>).</p>\n", "schema": "\nCREATE TABLE orders (\n    order_id    INTEGER PRIMARY KEY,\n    customer_id INTEGER NOT NULL,\n    order_date  TEXT NOT NULL,\n    total       REAL NOT NULL\n);\nINSERT INTO orders VALUES\n (1,  11, '2025-03-01', 24.10),\n (2,  12, '2025-03-01', 31.75),\n (3,  11, '2025-03-04', 18.20),\n (4,  13, '2025-03-05', 42.00),\n (5,  14, '2025-03-06', 15.60),\n (6,  12, '2025-03-09', 27.35),\n (7,  15, '2025-03-10', 22.90),\n (8,  11, '2025-03-12', 19.99),\n (9,  16, '2025-03-15', 38.40),\n (10, 17, '2025-03-18', 11.25),\n (11, 13, '2025-03-21', 29.80),\n (12, 16, '2025-03-25', 17.10);\n", "solution": "\nWITH per_customer AS (\n    SELECT customer_id, COUNT(*) AS order_count\n    FROM orders\n    GROUP BY customer_id\n)\nSELECT ROUND(100.0 * SUM(CASE WHEN order_count >= 2 THEN 1 ELSE 0 END) / COUNT(*), 1)\n         AS repeat_rate\nFROM per_customer;\n", "explanation": "\n<p>Two layers of aggregation: first collapse orders to one row per customer with their order count, then\naggregate <em>that</em> to a single rate. 7 customers ordered; 4 of them (11, 12, 13, 16) ordered twice\nor more → 57.1%.</p>\n<p>The <code>100.0</code> (not <code>100</code>) matters: it forces floating-point division. With integer\noperands many engines — SQLite included for <code>/</code> on two integers — would truncate to 0.\nConditional aggregation (<code>SUM(CASE WHEN ...)</code>) is a pattern you'll reuse constantly.</p>\n", "hints": ["First aggregate to one row per customer (their order count), then aggregate again.", "SUM(CASE WHEN cnt >= 2 THEN 1 ELSE 0 END) counts repeat customers.", "Multiply by 100.0 — integer division would give you 0."], "order_matters": false}, {"id": "m08", "title": "Frequently Bought Together", "difficulty": "Medium", "category": "Self-Joins", "companies": ["Amazon", "Instacart"], "description": "\n<p><strong>Snackrack</strong>, an online grocer, wants \"frequently bought together\" suggestions. Two\nproducts are a candidate pair if they appear in the same order at least <strong>2 distinct orders</strong>.</p>\n<p>Return each qualifying pair once, with the products in alphabetical order within the pair\n(<code>product_a &lt; product_b</code>), and the number of orders containing both.</p>\n<p><strong>Return columns:</strong> <code>product_a</code>, <code>product_b</code>,\n<code>orders_together</code> — any order.</p>\n", "schema": "\nCREATE TABLE products (\n    product_id INTEGER PRIMARY KEY,\n    name       TEXT NOT NULL\n);\nCREATE TABLE order_items (\n    order_id   INTEGER NOT NULL,\n    product_id INTEGER NOT NULL,\n    PRIMARY KEY (order_id, product_id)\n);\nINSERT INTO products VALUES\n (1, 'Almond Butter'),\n (2, 'Banana Chips'),\n (3, 'Cold Brew'),\n (4, 'Dark Chocolate'),\n (5, 'Granola');\nINSERT INTO order_items VALUES\n (901, 1), (901, 2), (901, 5),\n (902, 1), (902, 5),\n (903, 3), (903, 4),\n (904, 1), (904, 2),\n (905, 3), (905, 4), (905, 5),\n (906, 2), (906, 5),\n (907, 1), (907, 5);\n", "solution": "\nSELECT pa.name AS product_a,\n       pb.name AS product_b,\n       COUNT(DISTINCT i1.order_id) AS orders_together\nFROM order_items i1\nJOIN order_items i2\n  ON i2.order_id = i1.order_id\nJOIN products pa ON pa.product_id = i1.product_id\nJOIN products pb ON pb.product_id = i2.product_id\nWHERE pa.name < pb.name\nGROUP BY pa.name, pb.name\nHAVING COUNT(DISTINCT i1.order_id) >= 2;\n", "explanation": "\n<p>Self-joining <code>order_items</code> on the order id produces every pairing of items within an order.\nThe filter <code>pa.name &lt; pb.name</code> kills two birds: it removes self-pairs (a product with\nitself) and keeps exactly one of the two mirror orderings (A,B vs B,A).</p>\n<p>Qualifying pairs: Almond Butter + Granola (3 orders), Almond Butter + Banana Chips (2),\nBanana Chips + Granola (2), Cold Brew + Dark Chocolate (2). This is the same shape as co-occurrence /\nmarket-basket queries on much bigger data, where you'd add frequency cutoffs before the join.</p>\n", "hints": ["Self-join order_items to itself on order_id to form pairs within an order.", "Use an inequality (a < b) to avoid self-pairs and mirrored duplicates.", "Count DISTINCT orders, and filter with HAVING >= 2."], "order_matters": false}, {"id": "m09", "title": "Each Customer's Second Order", "difficulty": "Medium", "category": "Window Functions", "companies": ["Airbnb", "Booking.com"], "description": "\n<p>Growth at <strong>Stayfinder</strong>, a vacation rental marketplace, studies the \"second booking\" —\nthe moment a customer becomes a repeat user. For every customer who has made at least two bookings,\nreturn their <em>second-earliest</em> booking.</p>\n<p><strong>Return columns:</strong> <code>customer_id</code>, <code>booking_id</code>,\n<code>booking_date</code> — any order.</p>\n", "schema": "\nCREATE TABLE bookings (\n    booking_id  INTEGER PRIMARY KEY,\n    customer_id INTEGER NOT NULL,\n    booking_date TEXT NOT NULL,\n    nightly_rate REAL NOT NULL\n);\nINSERT INTO bookings VALUES\n (1, 71, '2024-11-02', 145.00),\n (2, 72, '2024-11-15', 210.00),\n (3, 71, '2025-01-10', 132.00),\n (4, 73, '2025-01-12', 95.00),\n (5, 72, '2025-02-03', 188.00),\n (6, 71, '2025-03-22', 176.00),\n (7, 74, '2025-04-01', 230.00),\n (8, 73, '2025-04-18', 110.00),\n (9, 72, '2025-05-09', 205.00);\n", "solution": "\nWITH numbered AS (\n    SELECT booking_id,\n           customer_id,\n           booking_date,\n           ROW_NUMBER() OVER (\n               PARTITION BY customer_id\n               ORDER BY booking_date\n           ) AS rn\n    FROM bookings\n)\nSELECT customer_id, booking_id, booking_date\nFROM numbered\nWHERE rn = 2;\n", "explanation": "\n<p>The mirror image of \"latest record per group\": number each customer's bookings chronologically\n(ascending this time) and keep row 2. Customer 74 has only one booking and drops out naturally — no\nspecial-casing needed.</p>\n<p>This generalizes to \"nth event per entity,\" which shows up in activation analysis (second session,\nthird purchase) all the time. <code>ROW_NUMBER</code> is correct here rather than <code>RANK</code>\nbecause each customer's dates are unique; if same-day bookings were possible you'd add a tiebreaker\ncolumn to the window's ORDER BY.</p>\n", "hints": ["Number each customer's bookings in date order.", "PARTITION BY customer_id, ORDER BY booking_date ascending.", "Keep the rows numbered 2 — customers with one booking never get a 2."], "order_matters": false}, {"id": "m10", "title": "Signup Funnel by Channel", "difficulty": "Medium", "category": "Joins", "companies": ["HubSpot", "Dropbox", "Canva"], "description": "\n<p><strong>Briefly</strong>, a SaaS note-taking app, runs ads on several channels. For each channel,\nmarketing wants: total visits, how many of those visits converted to a signup, and the conversion rate.</p>\n<p>Every signup links back to the visit it came from. Channels with zero signups must still appear.</p>\n<p><strong>Return columns:</strong> <code>channel</code>, <code>visits</code>, <code>signups</code>,\n<code>conversion_rate</code> (percentage, 1 decimal) — ordered by <code>conversion_rate</code> descending.</p>\n", "schema": "\nCREATE TABLE visits (\n    visit_id   INTEGER PRIMARY KEY,\n    channel    TEXT NOT NULL,    -- 'search', 'social', 'email', 'referral'\n    visit_date TEXT NOT NULL\n);\nCREATE TABLE signups (\n    signup_id  INTEGER PRIMARY KEY,\n    visit_id   INTEGER NOT NULL,\n    signup_date TEXT NOT NULL\n);\nINSERT INTO visits VALUES\n (1,  'search',   '2025-05-01'), (2,  'search',   '2025-05-01'),\n (3,  'social',   '2025-05-01'), (4,  'email',    '2025-05-02'),\n (5,  'search',   '2025-05-02'), (6,  'social',   '2025-05-02'),\n (7,  'referral', '2025-05-03'), (8,  'search',   '2025-05-03'),\n (9,  'email',    '2025-05-03'), (10, 'social',   '2025-05-04'),\n (11, 'search',   '2025-05-04'), (12, 'email',    '2025-05-04'),\n (13, 'social',   '2025-05-05'), (14, 'referral', '2025-05-05'),\n (15, 'search',   '2025-05-05');\nINSERT INTO signups VALUES\n (1, 2,  '2025-05-01'),\n (2, 5,  '2025-05-02'),\n (3, 4,  '2025-05-02'),\n (4, 8,  '2025-05-03'),\n (5, 12, '2025-05-04'),\n (6, 10, '2025-05-04');\n", "solution": "\nSELECT v.channel,\n       COUNT(*) AS visits,\n       COUNT(s.signup_id) AS signups,\n       ROUND(100.0 * COUNT(s.signup_id) / COUNT(*), 1) AS conversion_rate\nFROM visits v\nLEFT JOIN signups s ON s.visit_id = v.visit_id\nGROUP BY v.channel\nORDER BY conversion_rate DESC;\n", "explanation": "\n<p>The key trick: after a <code>LEFT JOIN</code>, <code>COUNT(*)</code> counts all rows (every visit)\nwhile <code>COUNT(s.signup_id)</code> counts only rows where the join matched — because <code>COUNT</code>\nof a column skips NULLs. One query, both funnel stages.</p>\n<p>Email converts at 66.7% (2/3), search 50% (3/6), social 25% (1/4), referral 0% (0/2) — and referral\nstill appears, which an inner join would have broken. Funnel queries like this are a staple of analytics\nengineering interviews.</p>\n", "hints": ["LEFT JOIN keeps channels with zero signups in the result.", "COUNT(*) vs COUNT(column): one counts rows, the other skips NULLs.", "100.0 * matched / total, rounded to 1 decimal."], "order_matters": true}, {"id": "m11", "title": "Average Days to First Order", "difficulty": "Medium", "category": "Date/Time", "companies": ["Shopify", "Etsy", "Wayfair"], "description": "\n<p><strong>Mosaic Market</strong>, a handmade-goods marketplace, measures activation speed: on average,\nhow many days pass between a user signing up and placing their <em>first</em> order? Users who never\nordered are excluded.</p>\n<p><strong>Return column:</strong> <code>avg_days_to_first_order</code> — a single value rounded to\n1 decimal place.</p>\n", "schema": "\nCREATE TABLE users (\n    user_id     INTEGER PRIMARY KEY,\n    signup_date TEXT NOT NULL\n);\nCREATE TABLE orders (\n    order_id   INTEGER PRIMARY KEY,\n    user_id    INTEGER NOT NULL,\n    order_date TEXT NOT NULL,\n    total      REAL NOT NULL\n);\nINSERT INTO users VALUES\n (1, '2025-01-05'),\n (2, '2025-01-10'),\n (3, '2025-01-12'),\n (4, '2025-02-01'),\n (5, '2025-02-14'),\n (6, '2025-03-03');\nINSERT INTO orders VALUES\n (1, 1, '2025-01-07', 49.00),\n (2, 1, '2025-01-20', 25.50),\n (3, 2, '2025-02-09', 120.00),\n (4, 3, '2025-01-12', 15.75),\n (5, 5, '2025-03-02', 60.20),\n (6, 2, '2025-03-15', 35.00),\n (7, 5, '2025-04-11', 78.90);\n", "solution": "\nWITH first_orders AS (\n    SELECT user_id, MIN(order_date) AS first_order_date\n    FROM orders\n    GROUP BY user_id\n)\nSELECT ROUND(\n         AVG(julianday(f.first_order_date) - julianday(u.signup_date)),\n         1\n       ) AS avg_days_to_first_order\nFROM first_orders f\nJOIN users u ON u.user_id = f.user_id;\n", "explanation": "\n<p>Step one: reduce orders to each user's <em>first</em> order with <code>MIN(order_date)</code> — using\nall orders would skew the average badly (user 1's later order on 01-20 must not count). Step two: date\ndifference, averaged. SQLite uses <code>julianday()</code> arithmetic; Postgres would be\n<code>first_order_date - signup_date</code>, BigQuery <code>DATE_DIFF</code>.</p>\n<p>Gaps: user 1 → 2 days, user 2 → 30, user 3 → 0 (ordered the day they signed up — same-day must count\nas 0, not be dropped), user 5 → 16. Average = 12.0. Users 4 and 6 never ordered and are excluded by the\ninner join.</p>\n", "hints": ["First collapse orders to MIN(order_date) per user.", "An INNER JOIN to users drops the never-ordered users automatically.", "Date difference in SQLite: julianday(a) - julianday(b)."], "order_matters": false}, {"id": "m12", "title": "Daily Cancellation Rate", "difficulty": "Medium", "category": "CASE Expressions", "companies": ["Uber", "Lyft", "Grab"], "description": "\n<p>Ops at <strong>Swiftly</strong> (the ride-hailing company from the easy set) monitors marketplace\nhealth via the daily cancellation rate: of all trips requested on a day, what percentage were cancelled\n(by either side)?</p>\n<p><strong>Return columns:</strong> <code>trip_date</code>, <code>cancellation_rate</code> (percentage,\n1 decimal) — ordered by <code>trip_date</code> ascending.</p>\n", "schema": "\nCREATE TABLE trips (\n    trip_id   INTEGER PRIMARY KEY,\n    trip_date TEXT NOT NULL,\n    status    TEXT NOT NULL  -- 'completed', 'cancelled_by_driver', 'cancelled_by_rider'\n);\nINSERT INTO trips VALUES\n (1,  '2025-05-10', 'completed'),\n (2,  '2025-05-10', 'cancelled_by_rider'),\n (3,  '2025-05-10', 'completed'),\n (4,  '2025-05-10', 'completed'),\n (5,  '2025-05-11', 'cancelled_by_driver'),\n (6,  '2025-05-11', 'cancelled_by_rider'),\n (7,  '2025-05-11', 'completed'),\n (8,  '2025-05-12', 'completed'),\n (9,  '2025-05-12', 'completed'),\n (10, '2025-05-12', 'completed'),\n (11, '2025-05-13', 'cancelled_by_driver'),\n (12, '2025-05-13', 'completed'),\n (13, '2025-05-13', 'completed'),\n (14, '2025-05-13', 'cancelled_by_rider');\n", "solution": "\nSELECT trip_date,\n       ROUND(\n         100.0 * SUM(CASE WHEN status LIKE 'cancelled%' THEN 1 ELSE 0 END) / COUNT(*),\n         1\n       ) AS cancellation_rate\nFROM trips\nGROUP BY trip_date\nORDER BY trip_date;\n", "explanation": "\n<p>Conditional aggregation again: the <code>CASE</code> turns each row into a 1 or 0, the <code>SUM</code>\ncounts cancellations, and <code>COUNT(*)</code> is the denominator — all in one pass, no subqueries or\njoins. <code>LIKE 'cancelled%'</code> covers both cancellation reasons.</p>\n<p>Rates: 25.0, 66.7, 0.0, 50.0. Note 2025-05-12 correctly shows 0.0 rather than disappearing — a\n<code>WHERE status LIKE 'cancelled%'</code> approach would lose that day entirely. When a metric needs\n\"x per total,\" filter inside the aggregate, not in WHERE.</p>\n", "hints": ["Don't filter cancellations in WHERE — you'd lose the denominator (and zero-rate days).", "SUM(CASE WHEN ... THEN 1 ELSE 0 END) / COUNT(*).", "Both cancellation statuses start with 'cancelled'."], "order_matters": true}, {"id": "m13", "title": "Above-Average Spenders", "difficulty": "Medium", "category": "Subqueries", "companies": ["Apple", "Best Buy"], "description": "\n<p><strong>Tonebox</strong>, an audio gear store, defines VIPs as customers whose lifetime spend is\nstrictly greater than the <em>average lifetime spend</em> (averaged across customers who have ordered).</p>\n<p>Careful: that's the average of <em>per-customer totals</em>, not the average order amount.</p>\n<p><strong>Return columns:</strong> <code>name</code>, <code>total_spent</code> — ordered by\n<code>total_spent</code> descending.</p>\n", "schema": "\nCREATE TABLE customers (\n    customer_id INTEGER PRIMARY KEY,\n    name        TEXT NOT NULL\n);\nCREATE TABLE orders (\n    order_id    INTEGER PRIMARY KEY,\n    customer_id INTEGER NOT NULL,\n    amount      REAL NOT NULL\n);\nINSERT INTO customers VALUES\n (1, 'Marisol Vega'),\n (2, 'Henrik Olsen'),\n (3, 'Asha Gupta'),\n (4, 'Leo Costa'),\n (5, 'Faye Ndiaye');\nINSERT INTO orders VALUES\n (1,  1, 120.00),\n (2,  1, 340.00),\n (3,  2, 89.00),\n (4,  3, 410.00),\n (5,  3, 95.00),\n (6,  3, 230.00),\n (7,  4, 60.00),\n (8,  4, 75.00),\n (9,  5, 180.00),\n (10, 1, 55.00);\n", "solution": "\nWITH totals AS (\n    SELECT customer_id, SUM(amount) AS total\n    FROM orders\n    GROUP BY customer_id\n)\nSELECT c.name,\n       t.total AS total_spent\nFROM totals t\nJOIN customers c ON c.customer_id = t.customer_id\nWHERE t.total > (SELECT AVG(total) FROM totals)\nORDER BY total_spent DESC;\n", "explanation": "\n<p>The CTE computes lifetime spend per customer; the scalar subquery averages those totals (avg of 515,\n89, 735, 135, 180 = 330.80). Asha (735) and Marisol (515) clear the bar.</p>\n<p>The distinction the question hinges on: <code>AVG(amount)</code> over raw orders is 165.40 — a\ndifferent number answering a different question. Mixing up grain (per-order vs per-customer) is one of\nthe most common analytical mistakes, and interviewers deliberately phrase questions to test it.</p>\n", "hints": ["Compute per-customer totals first (CTE or subquery).", "The threshold is AVG over those totals — not AVG(amount) over orders.", "Compare each customer's total against the scalar subquery."], "order_matters": true}, {"id": "m14", "title": "Customers Who Bought Every Category", "difficulty": "Medium", "category": "Aggregation", "companies": ["Costco", "Amazon"], "description": "\n<p><strong>Pantryland</strong>, a wholesale club, wants to identify its most diversified shoppers:\ncustomers who have purchased from <em>every</em> product category the store carries.</p>\n<p>This pattern is called <em>relational division</em> — \"find entities related to ALL members of a\nset.\"</p>\n<p><strong>Return column:</strong> <code>name</code> — any order.</p>\n", "schema": "\nCREATE TABLE products (\n    product_id INTEGER PRIMARY KEY,\n    name       TEXT NOT NULL,\n    category   TEXT NOT NULL\n);\nCREATE TABLE customers (\n    customer_id INTEGER PRIMARY KEY,\n    name        TEXT NOT NULL\n);\nCREATE TABLE purchases (\n    purchase_id INTEGER PRIMARY KEY,\n    customer_id INTEGER NOT NULL,\n    product_id  INTEGER NOT NULL\n);\nINSERT INTO products VALUES\n (1, 'Trail Mix',      'Snacks'),\n (2, 'Sparkling Water','Beverages'),\n (3, 'Paper Towels',   'Household'),\n (4, 'Dark Roast',     'Beverages'),\n (5, 'Pita Chips',     'Snacks'),\n (6, 'Dish Soap',      'Household');\nINSERT INTO customers VALUES\n (1, 'Rosa Linden'),\n (2, 'Max Okada'),\n (3, 'Ines Farah'),\n (4, 'Coby Mitchell');\nINSERT INTO purchases VALUES\n (1,  1, 1), (2,  1, 2), (3,  1, 3),\n (4,  2, 1), (5,  2, 5), (6,  2, 1),\n (7,  3, 4), (8,  3, 5), (9,  3, 6), (10, 3, 2),\n (11, 4, 3), (12, 4, 4);\n", "solution": "\nSELECT c.name\nFROM customers c\nJOIN purchases pu ON pu.customer_id = c.customer_id\nJOIN products  pr ON pr.product_id = pu.product_id\nGROUP BY c.customer_id, c.name\nHAVING COUNT(DISTINCT pr.category) =\n       (SELECT COUNT(DISTINCT category) FROM products);\n", "explanation": "\n<p>Relational division via counting: if a customer's purchases span as many <em>distinct</em> categories\nas exist in total (3 here), they've covered them all. Rosa (Snacks, Beverages, Household) and Ines\n(Beverages, Snacks, Household) qualify; Max bought 3 items but only 2 distinct categories.</p>\n<p>The <code>DISTINCT</code> inside the count is load-bearing — Max's duplicate Trail Mix purchase would\notherwise be counted twice. The scalar subquery keeps the query correct even when a new category is added\nlater, instead of hard-coding 3.</p>\n", "hints": ["Count how many distinct categories each customer has purchased from.", "Compare it to the total number of distinct categories (a scalar subquery).", "COUNT(DISTINCT ...) — duplicates within a category must not inflate the count."], "order_matters": false}, {"id": "m15", "title": "Quarterly Sales Pivot", "difficulty": "Medium", "category": "CASE Expressions", "companies": ["Oracle", "SAP", "Salesforce"], "description": "\n<p>The sales VP at <strong>Fieldstone</strong> wants the classic spreadsheet view: one row per product,\none column per quarter of 2025, revenue in the cells. SQL has no spreadsheet pivot button — you build it\nwith conditional aggregation.</p>\n<p>Quarters: Q1 = Jan–Mar, Q2 = Apr–Jun, Q3 = Jul–Sep, Q4 = Oct–Dec. Products with no sales in a quarter\nmust show <code>0</code>, not NULL.</p>\n<p><strong>Return columns:</strong> <code>product</code>, <code>q1</code>, <code>q2</code>,\n<code>q3</code>, <code>q4</code> — ordered by <code>product</code> ascending.</p>\n", "schema": "\nCREATE TABLE sales (\n    sale_id   INTEGER PRIMARY KEY,\n    product   TEXT NOT NULL,\n    sale_date TEXT NOT NULL,\n    amount    REAL NOT NULL\n);\nINSERT INTO sales VALUES\n (1,  'Alpha Kit', '2025-01-15', 1200.00),\n (2,  'Alpha Kit', '2025-02-20',  800.00),\n (3,  'Beta Pack', '2025-03-05', 1500.00),\n (4,  'Alpha Kit', '2025-04-12',  950.00),\n (5,  'Beta Pack', '2025-05-30',  700.00),\n (6,  'Beta Pack', '2025-06-18',  650.00),\n (7,  'Alpha Kit', '2025-08-09', 1100.00),\n (8,  'Beta Pack', '2025-09-27',  900.00),\n (9,  'Alpha Kit', '2025-11-11', 1400.00),\n (10, 'Alpha Kit', '2025-12-02',  600.00);\n", "solution": "\nSELECT product,\n       SUM(CASE WHEN strftime('%m', sale_date) IN ('01','02','03') THEN amount ELSE 0 END) AS q1,\n       SUM(CASE WHEN strftime('%m', sale_date) IN ('04','05','06') THEN amount ELSE 0 END) AS q2,\n       SUM(CASE WHEN strftime('%m', sale_date) IN ('07','08','09') THEN amount ELSE 0 END) AS q3,\n       SUM(CASE WHEN strftime('%m', sale_date) IN ('10','11','12') THEN amount ELSE 0 END) AS q4\nFROM sales\nGROUP BY product\nORDER BY product;\n", "explanation": "\n<p>Each output column is a <code>SUM</code> whose <code>CASE</code> only \"lets through\" rows from the\nright quarter — everything else contributes the <code>ELSE 0</code>. Four filtered sums in one scan turn\nrows into columns: that's a pivot.</p>\n<p>The <code>ELSE 0</code> handles the spec's \"0, not NULL\" — Beta Pack has no Q4 sales, and without it\n<code>SUM</code> over no matching rows would yield NULL. Some engines have a native\n<code>PIVOT</code> keyword (Snowflake, SQL Server), but conditional aggregation is the portable form and\nthe one interviews test. Expected: Alpha Kit 2000/950/1100/2000, Beta Pack 1500/1350/900/0.</p>\n", "hints": ["One column per quarter = one SUM(CASE WHEN month-in-quarter THEN amount ELSE 0 END) each.", "strftime('%m', sale_date) gives the month as '01'…'12'.", "ELSE 0 (not omitted) is what turns empty quarters into 0 instead of NULL."], "order_matters": true}, {"id": "m16", "title": "Products That Got Cheaper", "difficulty": "Medium", "category": "Window Functions", "companies": ["Amazon", "Wayfair", "Booking.com"], "description": "\n<p><strong>Gearloft</strong>, an outdoor equipment store, keeps a full price history: every price change\nis a new row. Marketing wants a \"price drop\" badge for products whose <em>current</em> (latest) price is\nlower than their <em>original</em> (earliest) price.</p>\n<p><strong>Return columns:</strong> <code>name</code>, <code>first_price</code>,\n<code>last_price</code> — any order.</p>\n", "schema": "\nCREATE TABLE products (\n    product_id INTEGER PRIMARY KEY,\n    name       TEXT NOT NULL\n);\nCREATE TABLE price_history (\n    change_id  INTEGER PRIMARY KEY,\n    product_id INTEGER NOT NULL,\n    price      REAL NOT NULL,\n    changed_at TEXT NOT NULL\n);\nINSERT INTO products VALUES\n (1, 'Trailrunner Shoes'),\n (2, 'City Backpack'),\n (3, 'Thermal Bottle'),\n (4, 'Rain Jacket');\nINSERT INTO price_history VALUES\n (1,  1, 120.00, '2025-01-10'),\n (2,  1, 110.00, '2025-03-02'),\n (3,  1,  95.00, '2025-05-15'),\n (4,  2,  60.00, '2025-01-12'),\n (5,  2,  75.00, '2025-04-20'),\n (6,  3,  25.00, '2025-02-01'),\n (7,  3,  25.00, '2025-03-18'),\n (8,  3,  22.00, '2025-06-01'),\n (9,  4,  80.00, '2025-02-14');\n", "solution": "\nWITH bounds AS (\n    SELECT DISTINCT\n           product_id,\n           FIRST_VALUE(price) OVER (PARTITION BY product_id ORDER BY changed_at)      AS first_price,\n           FIRST_VALUE(price) OVER (PARTITION BY product_id ORDER BY changed_at DESC) AS last_price\n    FROM price_history\n)\nSELECT p.name,\n       b.first_price,\n       b.last_price\nFROM bounds b\nJOIN products p ON p.product_id = b.product_id\nWHERE b.last_price < b.first_price;\n", "explanation": "\n<p>Two <code>FIRST_VALUE</code> windows — one ordered ascending (earliest price), one descending (latest\nprice) — attach both endpoints to every row; <code>DISTINCT</code> collapses each product to one row.\nTrailrunner Shoes (120 → 95) and Thermal Bottle (25 → 22) qualify; City Backpack went up; Rain Jacket\nnever changed, and <code>&lt;</code> being strict correctly excludes it.</p>\n<p>Why not <code>LAST_VALUE</code> ascending? Its default window frame ends at the <em>current row</em>,\nso it returns the row's own price, not the partition's last — the most notorious window-function gotcha.\nReversing the sort and using <code>FIRST_VALUE</code> sidesteps it. (MIN/MAX over <code>changed_at</code>\nwith a self-join is a fine non-window alternative.)</p>\n", "hints": ["You need each product's earliest price and latest price side by side.", "FIRST_VALUE ordered ASC gives the earliest; FIRST_VALUE ordered DESC gives the latest.", "LAST_VALUE has a default-frame trap — avoid it or fix the frame explicitly."], "order_matters": false}, {"id": "m17", "title": "Cross-Platform Power Users", "difficulty": "Medium", "category": "Aggregation", "companies": ["Netflix", "Disney+", "Spotify"], "description": "\n<p><strong>Streamio</strong> logs every playback with the platform it ran on. Product wants users who\nhave streamed on <em>both</em> <code>mobile</code> and <code>tv</code> — they're the strongest\nsubscribers and the target for a new cross-device feature.</p>\n<p><strong>Return column:</strong> <code>user_id</code> — ordered ascending.</p>\n", "schema": "\nCREATE TABLE playbacks (\n    playback_id INTEGER PRIMARY KEY,\n    user_id     INTEGER NOT NULL,\n    platform    TEXT NOT NULL,    -- 'mobile', 'tv', 'web'\n    played_at   TEXT NOT NULL\n);\nINSERT INTO playbacks VALUES\n (1,  1, 'mobile', '2025-05-01'),\n (2,  1, 'tv',     '2025-05-02'),\n (3,  2, 'mobile', '2025-05-01'),\n (4,  2, 'mobile', '2025-05-03'),\n (5,  3, 'tv',     '2025-05-02'),\n (6,  3, 'web',    '2025-05-04'),\n (7,  4, 'mobile', '2025-05-03'),\n (8,  4, 'web',    '2025-05-04'),\n (9,  4, 'tv',     '2025-05-06'),\n (10, 5, 'web',    '2025-05-05'),\n (11, 6, 'tv',     '2025-05-05'),\n (12, 6, 'mobile', '2025-05-07'),\n (13, 6, 'tv',     '2025-05-08');\n", "solution": "\nSELECT user_id\nFROM playbacks\nWHERE platform IN ('mobile', 'tv')\nGROUP BY user_id\nHAVING COUNT(DISTINCT platform) = 2\nORDER BY user_id;\n", "explanation": "\n<p>Filter to the two platforms of interest, group by user, and require <em>both</em> to be present:\n<code>COUNT(DISTINCT platform) = 2</code>. The <code>DISTINCT</code> is essential — user 6 has two tv\nplaybacks, and counting rows instead of distinct platforms would wrongly admit a tv-only user with two\nevents. Users 1, 4, 6 qualify; user 2 is mobile-only, user 3's second platform is web.</p>\n<p>Equivalent formulations worth knowing: <code>INTERSECT</code> between the mobile users and the tv\nusers, or a self-join. The HAVING-count version generalizes best (\"users active on all N platforms\") and\nis the same relational-division pattern as \"bought every category\" from the medium set.</p>\n", "hints": ["Restrict to the two platforms first, then look at each user's variety.", "HAVING COUNT(DISTINCT platform) = 2 demands both platforms be present.", "Without DISTINCT, two playbacks on the same platform would slip through."], "order_matters": true}, {"id": "m18", "title": "Revenue Share Within Category", "difficulty": "Medium", "category": "Window Functions", "companies": ["Amazon", "Etsy", "Mercado Libre"], "description": "\n<p>Category managers at <strong>Loft &amp; Ladder</strong> don't just want product revenue — they want\neach product's <em>share of its category</em>: what percent of the category's total revenue does each\nproduct contribute?</p>\n<p><strong>Return columns:</strong> <code>category</code>, <code>name</code>, <code>revenue</code>,\n<code>category_share_pct</code> (1 decimal) — ordered by <code>category</code> ascending, then\n<code>revenue</code> descending.</p>\n", "schema": "\nCREATE TABLE products (\n    product_id INTEGER PRIMARY KEY,\n    name       TEXT NOT NULL,\n    category   TEXT NOT NULL\n);\nCREATE TABLE order_items (\n    item_id    INTEGER PRIMARY KEY,\n    product_id INTEGER NOT NULL,\n    quantity   INTEGER NOT NULL,\n    unit_price REAL NOT NULL\n);\nINSERT INTO products VALUES\n (1, 'Oak Bookshelf',  'Furniture'),\n (2, 'Walnut Desk',    'Furniture'),\n (3, 'Linen Throw',    'Textiles'),\n (4, 'Wool Rug',       'Textiles'),\n (5, 'Velvet Cushion', 'Textiles');\nINSERT INTO order_items VALUES\n (1, 1, 2, 250.00),\n (2, 2, 1, 600.00),\n (3, 1, 1, 250.00),\n (4, 3, 4,  45.00),\n (5, 4, 1, 320.00),\n (6, 5, 5,  30.00),\n (7, 4, 1, 320.00),\n (8, 3, 2,  45.00);\n", "solution": "\nWITH revenue AS (\n    SELECT p.category,\n           p.name,\n           SUM(oi.quantity * oi.unit_price) AS revenue\n    FROM products p\n    JOIN order_items oi ON oi.product_id = p.product_id\n    GROUP BY p.product_id, p.category, p.name\n)\nSELECT category,\n       name,\n       revenue,\n       ROUND(100.0 * revenue / SUM(revenue) OVER (PARTITION BY category), 1)\n         AS category_share_pct\nFROM revenue\nORDER BY category, revenue DESC;\n", "explanation": "\n<p>The percent-of-total pattern: aggregate first (per-product revenue), then use a windowed\n<code>SUM ... PARTITION BY category</code> as the denominator — it computes each category's total\n<em>without collapsing the rows</em>, which a GROUP BY would do. Mixing aggregation grain\n(per product) with a coarser denominator (per category) in one query is exactly what window functions\nexist for.</p>\n<p>Furniture totals 1350 — Bookshelf 750 (55.6%), Desk 600 (44.4%). Textiles totals 1060 — Rug 640\n(60.4%), Throw 270 (25.5%), Cushion 150 (14.2%). Sanity-check the output by verifying each category's\nshares sum to ~100% (rounding can leave them a tenth off) — a habit interviewers explicitly look for.\nThe same window-as-denominator move powers \"% of company headcount per department\" and every other\nshare-of-whole metric.</p>\n", "hints": ["Two grains at once: revenue per product, total per category. Aggregate then window.", "SUM(revenue) OVER (PARTITION BY category) is the denominator, computed per row.", "100.0 * numerator / denominator, ROUND to 1 decimal."], "order_matters": true}, {"id": "h01", "title": "Longest Login Streak", "difficulty": "Hard", "category": "Gaps & Islands", "companies": ["Duolingo", "Meta", "LinkedIn"], "description": "\n<p><strong>Linguini</strong>, a language-learning app, gamifies daily practice with streaks. For each\nuser, find the length of their <em>longest run of consecutive calendar days</em> with at least one login.\nA user may log in multiple times on the same day — that still counts as one day.</p>\n<p><strong>Return columns:</strong> <code>user_id</code>, <code>longest_streak</code> — ordered by\n<code>user_id</code> ascending.</p>\n", "schema": "\nCREATE TABLE logins (\n    login_id   INTEGER PRIMARY KEY,\n    user_id    INTEGER NOT NULL,\n    login_date TEXT NOT NULL\n);\nINSERT INTO logins VALUES\n (1,  1, '2025-04-01'),\n (2,  1, '2025-04-02'),\n (3,  1, '2025-04-02'),   -- duplicate day\n (4,  1, '2025-04-03'),\n (5,  1, '2025-04-07'),\n (6,  1, '2025-04-08'),\n (7,  2, '2025-04-01'),\n (8,  2, '2025-04-03'),\n (9,  2, '2025-04-05'),\n (10, 3, '2025-04-10'),\n (11, 3, '2025-04-11'),\n (12, 3, '2025-04-12'),\n (13, 3, '2025-04-13'),\n (14, 3, '2025-04-13'),   -- duplicate day\n (15, 3, '2025-04-14');\n", "solution": "\nWITH days AS (\n    SELECT DISTINCT user_id, login_date\n    FROM logins\n),\nanchored AS (\n    SELECT user_id,\n           login_date,\n           date(login_date,\n                '-' || ROW_NUMBER() OVER (PARTITION BY user_id ORDER BY login_date) || ' day'\n           ) AS anchor\n    FROM days\n),\nstreaks AS (\n    SELECT user_id, anchor, COUNT(*) AS streak_len\n    FROM anchored\n    GROUP BY user_id, anchor\n)\nSELECT user_id, MAX(streak_len) AS longest_streak\nFROM streaks\nGROUP BY user_id\nORDER BY user_id;\n", "explanation": "\n<p>The classic <em>gaps and islands</em> trick. For consecutive dates, <code>date - row_number</code> is\nconstant: 04-01−1, 04-02−2, 04-03−3 all land on the same anchor date. The moment a day is skipped, the\nanchor jumps — so grouping by (user, anchor) groups exactly the consecutive runs, and\n<code>COUNT(*)</code> is each run's length.</p>\n<p>Two traps are planted in the data: duplicate same-day logins (the <code>DISTINCT</code> CTE is\nmandatory, otherwise row numbers shift and streaks shatter) — and user 2, who never has two consecutive\ndays (answer: 1). Expected: user 1 → 3, user 2 → 1, user 3 → 5.</p>\n", "hints": ["Deduplicate to one row per user per day first — duplicates break everything that follows.", "For consecutive dates, date minus row_number (in days) is a constant. Group on it.", "In SQLite: date(login_date, '-' || rn || ' day'). Then COUNT per group, MAX per user."], "order_matters": true}, {"id": "h02", "title": "Month-over-Month Revenue Growth", "difficulty": "Hard", "category": "Window Functions", "companies": ["Stripe", "Snowflake", "Datadog"], "description": "\n<p>The CFO of <strong>Cloudloom</strong>, a B2B SaaS company, wants the standard board-deck table:\nrevenue per month and percentage growth vs the previous month. The first month has no prior month —\nits growth must be <code>NULL</code>, not 0.</p>\n<p><strong>Return columns:</strong> <code>month</code> (<code>YYYY-MM</code>), <code>revenue</code>,\n<code>growth_pct</code> (1 decimal, NULL for the first month) — ordered by <code>month</code> ascending.</p>\n", "schema": "\nCREATE TABLE payments (\n    payment_id INTEGER PRIMARY KEY,\n    paid_at    TEXT NOT NULL,\n    amount     REAL NOT NULL\n);\nINSERT INTO payments VALUES\n (1,  '2025-01-08', 4200.00),\n (2,  '2025-01-19', 3100.00),\n (3,  '2025-01-27', 1850.00),\n (4,  '2025-02-04', 5300.00),\n (5,  '2025-02-15', 2750.00),\n (6,  '2025-02-22', 4925.00),\n (7,  '2025-03-03', 3600.00),\n (8,  '2025-03-11', 2240.00),\n (9,  '2025-03-29', 3110.00),\n (10, '2025-04-06', 6480.00),\n (11, '2025-04-17', 5275.00),\n (12, '2025-04-25', 3945.00);\n", "solution": "\nWITH monthly AS (\n    SELECT strftime('%Y-%m', paid_at) AS month,\n           SUM(amount) AS revenue\n    FROM payments\n    GROUP BY month\n)\nSELECT month,\n       revenue,\n       ROUND(\n         100.0 * (revenue - LAG(revenue) OVER (ORDER BY month))\n               / LAG(revenue) OVER (ORDER BY month),\n         1\n       ) AS growth_pct\nFROM monthly\nORDER BY month;\n", "explanation": "\n<p>Aggregate to monthly grain first, <em>then</em> apply <code>LAG()</code> — window functions can't see\nrows that grouping hasn't produced yet, so the CTE ordering matters. <code>LAG(revenue)</code> fetches\nthe previous month's value; the growth formula is <code>(current − previous) / previous</code>.</p>\n<p>For January, <code>LAG</code> returns <code>NULL</code> and NULL propagates through the arithmetic —\nexactly the required output, for free. Growth: Feb +41.8%, Mar −31.0%, Apr +75.4%. Knowing that MoM/WoW\ngrowth is just \"GROUP BY then LAG\" makes a whole family of interview questions mechanical.</p>\n", "hints": ["Two stages: aggregate to monthly revenue, then compare each row to the previous one.", "LAG(revenue) OVER (ORDER BY month) reads the prior month's value.", "Don't special-case the first month — NULL arithmetic handles it."], "order_matters": true}, {"id": "h03", "title": "Median Salary per Company", "difficulty": "Hard", "category": "Window Functions", "companies": ["Google", "Bloomberg", "Two Sigma"], "description": "\n<p><strong>Salarywise</strong>, a compensation benchmarking site, needs the median salary at each company.\nThere is no <code>MEDIAN()</code> function in most SQL engines — you must build it.</p>\n<p>For a company with an odd number of employees the median is the middle value; for an even number it's\nthe average of the two middle values.</p>\n<p><strong>Return columns:</strong> <code>company</code>, <code>median_salary</code> — ordered by\n<code>company</code> ascending.</p>\n", "schema": "\nCREATE TABLE salaries (\n    record_id INTEGER PRIMARY KEY,\n    company   TEXT NOT NULL,\n    salary    INTEGER NOT NULL\n);\nINSERT INTO salaries VALUES\n (1,  'Acme',    60000),\n (2,  'Acme',    72000),\n (3,  'Acme',    85000),\n (4,  'Acme',    91000),\n (5,  'Acme',   130000),\n (6,  'Bolt',    54000),\n (7,  'Bolt',    66000),\n (8,  'Bolt',    78000),\n (9,  'Bolt',    98000),\n (10, 'Corex',   88000),\n (11, 'Corex',   92000),\n (12, 'Corex',  104000),\n (13, 'Corex',  115000),\n (14, 'Corex',  150000),\n (15, 'Corex',  162000);\n", "solution": "\nWITH ranked AS (\n    SELECT company,\n           salary,\n           ROW_NUMBER() OVER (PARTITION BY company ORDER BY salary) AS rn,\n           COUNT(*)     OVER (PARTITION BY company) AS cnt\n    FROM salaries\n)\nSELECT company,\n       AVG(salary) AS median_salary\nFROM ranked\nWHERE rn IN ((cnt + 1) / 2, (cnt + 2) / 2)\nGROUP BY company\nORDER BY company;\n", "explanation": "\n<p>Rank salaries within each company and also attach the company's row count via\n<code>COUNT(*) OVER</code>. With integer division, <code>(cnt+1)/2</code> and <code>(cnt+2)/2</code>\nelegantly cover both parities: for cnt=5 both give 3 (the single middle row); for cnt=4 they give 2 and 3\n(the two middle rows). <code>AVG</code> over one row is that row; over two rows it's their midpoint.</p>\n<p>Acme (5 rows) → 85000; Bolt (4 rows) → (66000+78000)/2 = 72000; Corex (6 rows) →\n(104000+115000)/2 = 109500. An alternative phrasing uses <code>ABS(rn - (cnt+1)/2.0) &lt; 1</code> or\n<code>rn BETWEEN cnt/2.0 AND cnt/2.0 + 1</code> — any correct middle-row selection is accepted.</p>\n", "hints": ["Number the rows per company in salary order, and grab each company's total count in the same pass (COUNT(*) OVER).", "The median rows are the middle one (odd count) or middle two (even count).", "With integer division, (cnt+1)/2 and (cnt+2)/2 select exactly those rows. AVG them."], "order_matters": true}, {"id": "h04", "title": "Counting Browsing Sessions", "difficulty": "Hard", "category": "Sessionization", "companies": ["Amazon", "Airbnb", "Pinterest"], "description": "\n<p><strong>Wanderlust</strong>, a travel booking site, has a raw clickstream of page views. Analytics\ndefines a <em>session</em> the standard way: a user's pageview starts a new session if it occurs more\nthan <strong>30 minutes</strong> after their previous pageview (or if it's their first pageview ever).</p>\n<p>Count the number of sessions for each user.</p>\n<p><strong>Return columns:</strong> <code>user_id</code>, <code>sessions</code> — ordered by\n<code>user_id</code> ascending.</p>\n", "schema": "\nCREATE TABLE pageviews (\n    view_id   INTEGER PRIMARY KEY,\n    user_id   INTEGER NOT NULL,\n    view_time TEXT NOT NULL    -- 'YYYY-MM-DD HH:MM:SS'\n);\nINSERT INTO pageviews VALUES\n (1,  1, '2025-05-01 09:00:00'),\n (2,  1, '2025-05-01 09:05:00'),\n (3,  1, '2025-05-01 09:20:00'),\n (4,  1, '2025-05-01 11:00:00'),\n (5,  1, '2025-05-01 11:10:00'),\n (6,  1, '2025-05-02 15:30:00'),\n (7,  2, '2025-05-01 10:00:00'),\n (8,  2, '2025-05-01 10:29:00'),\n (9,  2, '2025-05-01 10:58:00'),\n (10, 2, '2025-05-01 12:45:00'),\n (11, 3, '2025-05-03 08:15:00');\n", "solution": "\nWITH gaps AS (\n    SELECT user_id,\n           view_time,\n           (julianday(view_time) -\n            julianday(LAG(view_time) OVER (PARTITION BY user_id ORDER BY view_time))\n           ) * 24 * 60 AS gap_minutes\n    FROM pageviews\n)\nSELECT user_id,\n       SUM(CASE WHEN gap_minutes IS NULL OR gap_minutes > 30 THEN 1 ELSE 0 END) AS sessions\nFROM gaps\nGROUP BY user_id\nORDER BY user_id;\n", "explanation": "\n<p>Sessionization in two moves: (1) <code>LAG</code> computes each pageview's gap from the user's previous\nview; (2) a pageview is a <em>session start</em> when that gap is NULL (first view ever) or exceeds 30\nminutes. Counting session starts counts sessions.</p>\n<p>User 2 is the subtle case: views at 10:00, 10:29, 10:58 form <em>one</em> session — each consecutive\ngap is 29 minutes even though the first and last views are 58 minutes apart. The gap rule chains. Then\n12:45 starts a second session. Expected: user 1 → 3, user 2 → 2, user 3 → 1. The same flag, cumulatively\nsummed, yields session <em>ids</em> — the standard warehouse pattern for building session tables from\nraw events.</p>\n", "hints": ["Compute each view's gap from the user's previous view with LAG.", "A session starts where the gap is NULL or > 30 minutes. Count session starts.", "Minutes between timestamps in SQLite: (julianday(a) - julianday(b)) * 24 * 60."], "order_matters": true}, {"id": "h05", "title": "Day-1 Retention by Signup Date", "difficulty": "Hard", "category": "Retention", "companies": ["Meta", "TikTok", "Duolingo"], "description": "\n<p><strong>Loopine</strong>, a short-video app, tracks Day-1 retention: of the users who signed up on a\ngiven date, what percentage came back (any activity) <em>exactly the next day</em>?</p>\n<p>For each signup date, return the number of signups and the Day-1 retention percentage. A user with\nseveral activity events on the next day must count only once.</p>\n<p><strong>Return columns:</strong> <code>signup_date</code>, <code>signups</code>,\n<code>d1_retention_pct</code> (1 decimal) — ordered by <code>signup_date</code> ascending.</p>\n", "schema": "\nCREATE TABLE users (\n    user_id     INTEGER PRIMARY KEY,\n    signup_date TEXT NOT NULL\n);\nCREATE TABLE activity (\n    activity_id   INTEGER PRIMARY KEY,\n    user_id       INTEGER NOT NULL,\n    activity_date TEXT NOT NULL\n);\nINSERT INTO users VALUES\n (1, '2025-06-01'),\n (2, '2025-06-01'),\n (3, '2025-06-01'),\n (4, '2025-06-02'),\n (5, '2025-06-02'),\n (6, '2025-06-03'),\n (7, '2025-06-03'),\n (8, '2025-06-03'),\n (9, '2025-06-03');\nINSERT INTO activity VALUES\n (1,  1, '2025-06-01'),\n (2,  1, '2025-06-02'),\n (3,  1, '2025-06-02'),   -- same user, same day: must count once\n (4,  2, '2025-06-02'),\n (5,  3, '2025-06-04'),   -- came back, but not on day 1\n (6,  4, '2025-06-03'),\n (7,  5, '2025-06-05'),\n (8,  6, '2025-06-04'),\n (9,  7, '2025-06-04'),\n (10, 7, '2025-06-04'),   -- duplicate again\n (11, 8, '2025-06-06'),\n (12, 9, '2025-06-04');\n", "solution": "\nWITH day1 AS (\n    SELECT DISTINCT user_id, activity_date\n    FROM activity\n)\nSELECT u.signup_date,\n       COUNT(*) AS signups,\n       ROUND(\n         100.0 * SUM(CASE WHEN d.user_id IS NOT NULL THEN 1 ELSE 0 END) / COUNT(*),\n         1\n       ) AS d1_retention_pct\nFROM users u\nLEFT JOIN day1 d\n  ON d.user_id = u.user_id\n AND d.activity_date = date(u.signup_date, '+1 day')\nGROUP BY u.signup_date\nORDER BY u.signup_date;\n", "explanation": "\n<p>The join condition carries the retention logic: match a user's activity only when it lands exactly one\nday after their signup. The <code>LEFT JOIN</code> keeps non-returning users in the denominator, and\ndeduplicating activity first (the <code>day1</code> CTE) prevents user 1's two next-day events from\ncounting twice — without it, June 1 would report a retention above 100%.</p>\n<p>Expected: 06-01 → 3 signups, 66.7% (users 1, 2 returned; user 3 came back too late); 06-02 → 2\nsignups, 50.0%; 06-03 → 4 signups, 75.0%. Generalizing the join offset gives D7/D30 retention, and\ngrouping by signup week/month gives cohort curves — this one query shape powers entire growth dashboards.</p>\n", "hints": ["Put the 'exactly next day' condition in the JOIN, not the WHERE — you need a LEFT JOIN that keeps everyone.", "Deduplicate activity to (user, day) before joining, or one user can count twice.", "date(signup_date, '+1 day') computes the target date."], "order_matters": true}, {"id": "h06", "title": "Top 3 Products per Category (Keep Ties)", "difficulty": "Hard", "category": "Window Functions", "companies": ["Amazon", "Walmart", "Alibaba"], "description": "\n<p><strong>Casacart</strong>, a home goods marketplace, prints a quarterly report: the top 3 products by\nrevenue <em>within each category</em>. If products tie at a qualifying rank, all of them appear (so a\ncategory can show more than 3 rows).</p>\n<p><strong>Return columns:</strong> <code>category</code>, <code>product_name</code>,\n<code>revenue</code> — ordered by <code>category</code> ascending, <code>revenue</code> descending,\n<code>product_name</code> ascending.</p>\n", "schema": "\nCREATE TABLE products (\n    product_id INTEGER PRIMARY KEY,\n    name       TEXT NOT NULL,\n    category   TEXT NOT NULL\n);\nCREATE TABLE sales (\n    sale_id    INTEGER PRIMARY KEY,\n    product_id INTEGER NOT NULL,\n    amount     REAL NOT NULL\n);\nINSERT INTO products VALUES\n (1, 'Cloud Sofa',      'Furniture'),\n (2, 'Birch Side Table','Furniture'),\n (3, 'Loft Bed Frame',  'Furniture'),\n (4, 'Pine Wardrobe',   'Furniture'),\n (5, 'Halo Floor Lamp', 'Lighting'),\n (6, 'Dot Desk Lamp',   'Lighting'),\n (7, 'Ray Pendant',     'Lighting'),\n (8, 'Glow Sconce',     'Lighting'),\n (9, 'Nest Wool Rug',   'Lighting');\nINSERT INTO sales VALUES\n (1,  1, 3200.00),\n (2,  1, 2800.00),\n (3,  2,  450.00),\n (4,  2,  450.00),\n (5,  3, 1900.00),\n (6,  4,  900.00),   -- Furniture rank 4: ties with nothing, must be excluded\n (7,  5,  780.00),\n (8,  6,  340.00),\n (9,  7,  560.00),\n (10, 8,  340.00),   -- Glow Sconce ties Dot Desk Lamp at rank 3: both stay\n (11, 9,  120.00);\n", "solution": "\nWITH revenue AS (\n    SELECT p.category,\n           p.name AS product_name,\n           SUM(s.amount) AS revenue\n    FROM products p\n    JOIN sales s ON s.product_id = p.product_id\n    GROUP BY p.product_id, p.category, p.name\n),\nranked AS (\n    SELECT category,\n           product_name,\n           revenue,\n           DENSE_RANK() OVER (\n               PARTITION BY category\n               ORDER BY revenue DESC\n           ) AS rnk\n    FROM revenue\n)\nSELECT category, product_name, revenue\nFROM ranked\nWHERE rnk <= 3\nORDER BY category, revenue DESC, product_name;\n", "explanation": "\n<p>Three stages stacked in CTEs: aggregate sales to product revenue, rank within category, filter. The\n\"keep ties\" requirement selects <code>DENSE_RANK</code> over <code>ROW_NUMBER</code> (which would\narbitrarily drop one of the tied lamps) and over <code>RANK</code> (which works here but can skip rank 3\nentirely after a tie at 2 — worth being able to explain the difference).</p>\n<p>In Lighting, Dot Desk Lamp and Glow Sconce tie at 340 for rank 3, so the category returns 4 rows.\nIn Furniture, Pine Wardrobe at rank 4 is excluded. Top-N-per-group is probably the single most-asked\nwindow function pattern in data engineering interviews.</p>\n", "hints": ["Aggregate to per-product revenue first, then rank within each category.", "Ties must survive: which ranking function assigns equal ranks without gaps?", "Filter rank <= 3 in an outer query — window results can't go in WHERE directly."], "order_matters": true}, {"id": "h07", "title": "Cumulative Distinct Users", "difficulty": "Hard", "category": "Window Functions", "companies": ["Snowflake", "Databricks", "Netflix"], "description": "\n<p><strong>Festwire</strong>, an event ticketing platform, wants a \"total unique customers ever\" line for\nits growth chart: for each date with activity, the count of distinct users seen <em>on or before</em>\nthat date.</p>\n<p>Hard part: <code>COUNT(DISTINCT ...)</code> is not allowed inside a window in SQLite (or BigQuery, or\nmost engines). You need another way.</p>\n<p><strong>Return columns:</strong> <code>event_date</code>, <code>cumulative_users</code> — ordered by\n<code>event_date</code> ascending.</p>\n", "schema": "\nCREATE TABLE events (\n    event_id   INTEGER PRIMARY KEY,\n    user_id    INTEGER NOT NULL,\n    event_date TEXT NOT NULL\n);\nINSERT INTO events VALUES\n (1,  101, '2025-02-01'),\n (2,  102, '2025-02-01'),\n (3,  101, '2025-02-03'),\n (4,  103, '2025-02-03'),\n (5,  102, '2025-02-05'),\n (6,  104, '2025-02-05'),\n (7,  105, '2025-02-05'),\n (8,  101, '2025-02-08'),\n (9,  103, '2025-02-08'),\n (10, 106, '2025-02-09'),\n (11, 104, '2025-02-09'),\n (12, 101, '2025-02-12');\n", "solution": "\nWITH first_seen AS (\n    SELECT user_id, MIN(event_date) AS first_date\n    FROM events\n    GROUP BY user_id\n),\nnew_per_day AS (\n    SELECT first_date AS d, COUNT(*) AS new_users\n    FROM first_seen\n    GROUP BY first_date\n),\nall_dates AS (\n    SELECT DISTINCT event_date AS d\n    FROM events\n)\nSELECT a.d AS event_date,\n       SUM(COALESCE(n.new_users, 0)) OVER (ORDER BY a.d) AS cumulative_users\nFROM all_dates a\nLEFT JOIN new_per_day n ON n.d = a.d\nORDER BY a.d;\n", "explanation": "\n<p>The reframe that unlocks it: a user contributes to the cumulative distinct count only on their\n<em>first</em> day. So compute each user's first-seen date, count new users per day, and take a running\nsum of that — an ordinary windowed <code>SUM</code>, no distinct needed.</p>\n<p>The <code>all_dates</code> CTE matters: 2025-02-08 and 2025-02-12 have activity but zero <em>new</em>\nusers, yet must still appear (with the running total flat at 5 and 6). Expected: 2, 3, 5, 5, 6, 6.\nThis first-seen trick is how production pipelines compute cumulative uniques at scale, where\nre-scanning all history per day would be prohibitive.</p>\n", "hints": ["A user only increments the cumulative distinct count once — on which day?", "MIN(event_date) per user → count of first-appearances per day → running SUM.", "Don't lose dates where no NEW user appeared; they still need an output row."], "order_matters": true}, {"id": "h08", "title": "7-Day Rolling Average Sales", "difficulty": "Hard", "category": "Window Functions", "companies": ["Netflix", "Spotify", "Robinhood"], "description": "\n<p><strong>Plateful</strong>, a meal-kit company, smooths its noisy daily sales with a trailing 7-day\naverage (today plus the 6 previous days). Only output dates that have a <em>full</em> 7-day window — the\nfirst 6 days don't have enough history and would distort the chart.</p>\n<p>The table has one row per day with no gaps.</p>\n<p><strong>Return columns:</strong> <code>sale_date</code>, <code>rolling_avg_7d</code> (2 decimals) —\nordered by <code>sale_date</code> ascending.</p>\n", "schema": "\nCREATE TABLE daily_sales (\n    sale_date TEXT PRIMARY KEY,\n    revenue   REAL NOT NULL\n);\nINSERT INTO daily_sales VALUES\n ('2025-03-01', 1850.00),\n ('2025-03-02', 2100.00),\n ('2025-03-03', 1740.00),\n ('2025-03-04', 1995.00),\n ('2025-03-05', 2300.00),\n ('2025-03-06', 2650.00),\n ('2025-03-07', 2480.00),\n ('2025-03-08', 1900.00),\n ('2025-03-09', 2050.00),\n ('2025-03-10', 2210.00),\n ('2025-03-11', 1875.00),\n ('2025-03-12', 2425.00),\n ('2025-03-13', 2760.00),\n ('2025-03-14', 2590.00);\n", "solution": "\nWITH windowed AS (\n    SELECT sale_date,\n           AVG(revenue) OVER (\n               ORDER BY sale_date\n               ROWS BETWEEN 6 PRECEDING AND CURRENT ROW\n           ) AS avg7,\n           ROW_NUMBER() OVER (ORDER BY sale_date) AS rn\n    FROM daily_sales\n)\nSELECT sale_date,\n       ROUND(avg7, 2) AS rolling_avg_7d\nFROM windowed\nWHERE rn >= 7\nORDER BY sale_date;\n", "explanation": "\n<p>An explicit window frame — <code>ROWS BETWEEN 6 PRECEDING AND CURRENT ROW</code> — defines the\ntrailing 7-row window. Because the data is guaranteed gap-free, 7 rows = 7 days; with gaps you'd need a\ndate-based frame (<code>RANGE</code>/date spine), a great point to raise in an interview.</p>\n<p>The second window function (<code>ROW_NUMBER</code>) handles the \"full window only\" requirement:\nrows 1–6 average over fewer than 7 days, so they're cut. Output runs 03-07 through 03-14, starting at\n2159.29. Knowing frame clauses (<code>ROWS</code> vs <code>RANGE</code>, <code>PRECEDING</code> /\n<code>FOLLOWING</code>) separates people who really know window functions from those who've only used\ndefaults.</p>\n", "hints": ["AVG over a window frame: ROWS BETWEEN 6 PRECEDING AND CURRENT ROW.", "The first 6 rows have incomplete windows — they must be excluded.", "ROW_NUMBER in the same CTE gives you a clean way to skip them (rn >= 7)."], "order_matters": true}, {"id": "h09", "title": "Customer Value Quartiles", "difficulty": "Hard", "category": "Window Functions", "companies": ["American Express", "Capital One", "Klarna"], "description": "\n<p>The CRM team at <strong>Vaultpay</strong>, a payments company, segments customers into four equal-sized\nvalue tiers by lifetime spend. Quartile 1 is the <em>highest</em>-spending group.</p>\n<p>For each quartile, report how many customers it contains and their average lifetime spend.</p>\n<p><strong>Return columns:</strong> <code>quartile</code>, <code>customers</code>,\n<code>avg_spend</code> (2 decimals) — ordered by <code>quartile</code> ascending.</p>\n", "schema": "\nCREATE TABLE orders (\n    order_id    INTEGER PRIMARY KEY,\n    customer_id INTEGER NOT NULL,\n    amount      REAL NOT NULL\n);\nINSERT INTO orders VALUES\n (1,  1, 250.00), (2,  1, 130.00),\n (3,  2, 90.00),\n (4,  3, 480.00), (5,  3, 220.00), (6,  3, 310.00),\n (7,  4, 45.00),  (8,  4, 30.00),\n (9,  5, 660.00),\n (10, 6, 150.00), (11, 6, 95.00),\n (12, 7, 520.00), (13, 7, 410.00),\n (14, 8, 75.00),\n (15, 9, 320.00), (16, 9, 185.00),\n (17, 10, 28.00), (18, 10, 19.00),\n (19, 11, 740.00), (20, 11, 380.00),\n (21, 12, 210.00);\n", "solution": "\nWITH totals AS (\n    SELECT customer_id, SUM(amount) AS total_spend\n    FROM orders\n    GROUP BY customer_id\n),\ntiled AS (\n    SELECT total_spend,\n           NTILE(4) OVER (ORDER BY total_spend DESC) AS quartile\n    FROM totals\n)\nSELECT quartile,\n       COUNT(*) AS customers,\n       ROUND(AVG(total_spend), 2) AS avg_spend\nFROM tiled\nGROUP BY quartile\nORDER BY quartile;\n", "explanation": "\n<p><code>NTILE(4)</code> deals rows into 4 buckets as evenly as possible — with 12 customers, exactly 3\nper quartile. Ordering <em>descending</em> makes quartile 1 the top spenders, as specified. Then a\nregular <code>GROUP BY</code> over the bucket label summarizes each tier.</p>\n<p>Per-customer totals (desc): 1120, 1010, 930, 660, 505, 380, 245, 210, 90, 75, 75, 47. Quartile\naverages: 1020.00, 515.00, 181.67, 65.67. Worth knowing: when rows don't divide evenly, NTILE makes the\nfirst buckets one row larger — and for value-based (rather than equal-count) tiers you'd reach for\nPERCENT_RANK or CUME_DIST instead. Interviewers love that distinction.</p>\n", "hints": ["First collapse orders to lifetime spend per customer.", "NTILE(4) OVER (ORDER BY total DESC) deals customers into 4 equal buckets.", "Then GROUP BY the bucket number and aggregate."], "order_matters": true}, {"id": "h10", "title": "True Watch Time (Merge Overlapping Intervals)", "difficulty": "Hard", "category": "Gaps & Islands", "companies": ["Netflix", "YouTube", "Twitch"], "description": "\n<p><strong>Streamio</strong> (the streaming service again) logs viewing sessions as intervals of minutes:\n<code>start_min</code> to <code>end_min</code>. Sessions can <em>overlap</em> — a user might watch on two\ndevices, or a crashed player can double-log. Total watch time must count overlapping minutes\n<strong>once</strong>.</p>\n<p>Compute each user's true total watch time in minutes. Back-to-back intervals (one ends exactly when\nthe next starts) count as continuous. Simply summing the durations will overcount.</p>\n<p><strong>Return columns:</strong> <code>user_id</code>, <code>total_minutes</code> — ordered by\n<code>user_id</code> ascending.</p>\n", "schema": "\nCREATE TABLE view_sessions (\n    session_id INTEGER PRIMARY KEY,\n    user_id    INTEGER NOT NULL,\n    start_min  INTEGER NOT NULL,\n    end_min    INTEGER NOT NULL\n);\nINSERT INTO view_sessions VALUES\n (1, 1, 10,  50),\n (2, 1, 40,  90),    -- overlaps previous\n (3, 1, 90,  120),   -- back-to-back: continuous\n (4, 1, 200, 230),\n (5, 2, 0,   60),\n (6, 2, 10,  30),    -- fully contained\n (7, 2, 100, 140),\n (8, 3, 15,  45),\n (9, 3, 50,  70),\n (10,3, 60,  65);    -- contained in previous\n", "solution": "\nWITH ordered AS (\n    SELECT user_id,\n           start_min,\n           end_min,\n           MAX(end_min) OVER (\n               PARTITION BY user_id\n               ORDER BY start_min, end_min\n               ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING\n           ) AS prev_max_end\n    FROM view_sessions\n),\nflagged AS (\n    SELECT user_id,\n           start_min,\n           end_min,\n           CASE WHEN prev_max_end IS NULL OR start_min > prev_max_end\n                THEN 1 ELSE 0 END AS is_new_island\n    FROM ordered\n),\nislands AS (\n    SELECT user_id,\n           start_min,\n           end_min,\n           SUM(is_new_island) OVER (\n               PARTITION BY user_id\n               ORDER BY start_min, end_min\n           ) AS island_id\n    FROM flagged\n)\nSELECT user_id,\n       SUM(island_end - island_start) AS total_minutes\nFROM (\n    SELECT user_id,\n           island_id,\n           MIN(start_min) AS island_start,\n           MAX(end_min)   AS island_end\n    FROM islands\n    GROUP BY user_id, island_id\n)\nGROUP BY user_id\nORDER BY user_id;\n", "explanation": "\n<p>Interval merging, the hardest common flavor of gaps-and-islands. The crucial subtlety: you must compare\neach interval's start against the <em>running maximum</em> end of all earlier intervals\n(<code>MAX(end_min) OVER ... 1 PRECEDING</code>), not just the previous row's end — a long interval can\nswallow several later ones (user 2's 0–60 contains 10–30). A new island starts when\n<code>start &gt; prev_max_end</code>; strict inequality makes back-to-back intervals merge, as specified.</p>\n<p>Cumulative-summing the island flags assigns island ids; each island contributes\n<code>MAX(end) − MIN(start)</code>. Expected: user 1 → 110 + 30 = 140; user 2 → 60 + 40 = 100;\nuser 3 → 30 + 20 = 50. This exact computation appears in real pipelines for ad exposure time, device\nuptime, and billable compute merging.</p>\n", "hints": ["Sort each user's intervals by start; an interval merges into the current block unless it starts after everything so far has ended.", "'Everything so far has ended' = running MAX(end_min) over preceding rows — not LAG(end_min). Contained intervals break LAG.", "Flag new blocks, cumulative-sum the flags to get block ids, then sum MAX(end) - MIN(start) per block."], "order_matters": true}, {"id": "h11", "title": "Org Chart Depth", "difficulty": "Hard", "category": "Recursive CTEs", "companies": ["Microsoft", "Workday", "Rippling"], "description": "\n<p><strong>Hexaware Labs</strong> (from the easy set) wants each employee's <em>level</em> in the org\nchart: the CEO is level 1, their direct reports level 2, and so on. The hierarchy is arbitrarily deep,\nso a fixed number of self-joins can't solve it — you need recursion.</p>\n<p><strong>Return columns:</strong> <code>name</code>, <code>level</code> — ordered by\n<code>level</code> ascending, then <code>name</code> ascending.</p>\n", "schema": "\nCREATE TABLE employees (\n    emp_id     INTEGER PRIMARY KEY,\n    name       TEXT NOT NULL,\n    manager_id INTEGER          -- NULL for the CEO\n);\nINSERT INTO employees VALUES\n (1, 'Priya Sharma', NULL),\n (2, 'Ben Carter',   1),\n (3, 'Olivia Stone', 1),\n (4, 'Marco Ruiz',   2),\n (5, 'Tina Wong',    2),\n (6, 'Felix Braun',  3),\n (7, 'Nora Quinn',   4),\n (8, 'Dev Anand',    4),\n (9, 'June Park',    6);\n", "solution": "\nWITH RECURSIVE org AS (\n    SELECT emp_id, name, 1 AS level\n    FROM employees\n    WHERE manager_id IS NULL\n\n    UNION ALL\n\n    SELECT e.emp_id, e.name, org.level + 1\n    FROM employees e\n    JOIN org ON e.manager_id = org.emp_id\n)\nSELECT name, level\nFROM org\nORDER BY level, name;\n", "explanation": "\n<p>A recursive CTE has two parts glued by <code>UNION ALL</code>: the <em>anchor</em> (the CEO, level 1)\nand the <em>recursive member</em>, which joins the table back to the rows produced so far — each pass\nfinds the next layer of reports and stamps it <code>level + 1</code>. Recursion stops automatically when\na pass adds no rows.</p>\n<p>Expected: Priya 1; Ben, Olivia 2; Felix, Marco, Tina 3; Dev, June, Nora 4. This is <em>the</em>\ncanonical recursive-CTE question — org charts, category trees, dependency graphs all reduce to it. Two\ninterview extensions worth rehearsing: building the full path string\n(<code>path || ' > ' || name</code>), and cycle protection (a corrupted row making someone their own\nancestor recurses forever — Postgres has <code>CYCLE</code> clauses; elsewhere you cap depth).</p>\n", "hints": ["Arbitrary depth rules out self-joins — WITH RECURSIVE is the tool.", "Anchor: the row with manager_id IS NULL, at level 1.", "Recursive step: join employees to the CTE on manager_id = cte.emp_id, level + 1."], "order_matters": true}, {"id": "h12", "title": "Three Sold-Out Nights in a Row", "difficulty": "Hard", "category": "Gaps & Islands", "companies": ["Ticketmaster", "Live Nation", "Airbnb"], "description": "\n<p><strong>The Velvet Room</strong>, a music venue, runs one show per night. A show is <em>sold out</em>\nwhen <code>tickets_sold ≥ capacity</code>. The booking team wants every date that was part of a run of\n<strong>3 or more consecutive sold-out nights</strong> — the signal to raise prices.</p>\n<p>Unlike the streak-length question, here you must return the <em>dates themselves</em> — every date\ninside a qualifying run.</p>\n<p><strong>Return column:</strong> <code>show_date</code> — ordered ascending.</p>\n", "schema": "\nCREATE TABLE shows (\n    show_date    TEXT PRIMARY KEY,\n    tickets_sold INTEGER NOT NULL,\n    capacity     INTEGER NOT NULL\n);\nINSERT INTO shows VALUES\n ('2025-06-01',  80, 100),\n ('2025-06-02', 100, 100),\n ('2025-06-03', 105, 100),\n ('2025-06-04', 100, 100),\n ('2025-06-05',  70, 100),\n ('2025-06-06', 100, 100),\n ('2025-06-07', 110, 100),\n ('2025-06-08',  95, 100),\n ('2025-06-09', 100, 100),\n ('2025-06-10', 120, 100),\n ('2025-06-11', 100, 100),\n ('2025-06-12', 101, 100);\n", "solution": "\nWITH sold_out AS (\n    SELECT show_date\n    FROM shows\n    WHERE tickets_sold >= capacity\n),\nanchored AS (\n    SELECT show_date,\n           date(show_date,\n                '-' || ROW_NUMBER() OVER (ORDER BY show_date) || ' day') AS anchor\n    FROM sold_out\n),\nruns AS (\n    SELECT anchor, COUNT(*) AS run_len\n    FROM anchored\n    GROUP BY anchor\n)\nSELECT a.show_date\nFROM anchored a\nJOIN runs r ON r.anchor = a.anchor\nWHERE r.run_len >= 3\nORDER BY a.show_date;\n", "explanation": "\n<p>Same gaps-and-islands anchor trick as the login-streak question (<code>date − row_number</code> is\nconstant within a consecutive run), with one extra move: after measuring each run's length, join\n<em>back</em> to the anchored rows to recover the individual dates of qualifying runs. Aggregate, then\nre-attach — a two-step you'll reuse constantly.</p>\n<p>The runs: Jun 2–4 (3 nights ✓), Jun 6–7 (2 ✗), Jun 9–12 (4 ✓). Expected output: 06-02, 06-03, 06-04,\n06-09, 06-10, 06-11, 06-12. This is the venue-flavored version of a famous interview classic usually\nposed about stadium attendance; the window-free variant (joining each row to its ±1 and ±2 neighbors)\nalso works but doesn't generalize to \"N or more\".</p>\n", "hints": ["Filter to sold-out dates first; the problem is then purely about consecutive dates.", "date − row_number is constant within a consecutive run — group on that anchor.", "Count each run's length, then JOIN BACK to the per-date rows to output dates in runs ≥ 3."], "order_matters": true}, {"id": "h13", "title": "Completed the Funnel in Order", "difficulty": "Hard", "category": "Aggregation", "companies": ["Shopify", "Amazon", "Pinterest"], "description": "\n<p><strong>Cartly</strong> defines a <em>clean conversion</em> strictly: a user must <code>view</code> a\nproduct, <em>then</em> <code>cart</code> it, <em>then</em> <code>purchase</code> — in that chronological\norder, based on each step's <strong>first</strong> occurrence. A user who purchases first and views later\n(a re-order from email, say) doesn't count.</p>\n<p>Find every user who completed the funnel in order.</p>\n<p><strong>Return column:</strong> <code>user_id</code> — ordered ascending.</p>\n", "schema": "\nCREATE TABLE events (\n    event_id   INTEGER PRIMARY KEY,\n    user_id    INTEGER NOT NULL,\n    event_type TEXT NOT NULL,    -- 'view', 'cart', 'purchase'\n    event_time TEXT NOT NULL\n);\nINSERT INTO events VALUES\n (1,  1, 'view',     '2025-05-01 10:00:00'),\n (2,  1, 'cart',     '2025-05-01 10:05:00'),\n (3,  1, 'purchase', '2025-05-01 10:20:00'),\n (4,  2, 'cart',     '2025-05-02 11:00:00'),\n (5,  2, 'view',     '2025-05-02 11:10:00'),\n (6,  2, 'purchase', '2025-05-02 11:30:00'),\n (7,  3, 'view',     '2025-05-03 09:15:00'),\n (8,  3, 'cart',     '2025-05-03 09:40:00'),\n (9,  4, 'purchase', '2025-05-04 08:00:00'),\n (10, 4, 'view',     '2025-05-04 08:30:00'),\n (11, 4, 'cart',     '2025-05-04 08:45:00'),\n (12, 5, 'view',     '2025-05-05 09:00:00'),\n (13, 5, 'view',     '2025-05-05 09:10:00'),\n (14, 5, 'cart',     '2025-05-05 09:30:00'),\n (15, 5, 'cart',     '2025-05-05 09:45:00'),\n (16, 5, 'purchase', '2025-05-05 09:50:00');\n", "solution": "\nWITH firsts AS (\n    SELECT user_id,\n           MIN(CASE WHEN event_type = 'view'     THEN event_time END) AS first_view,\n           MIN(CASE WHEN event_type = 'cart'     THEN event_time END) AS first_cart,\n           MIN(CASE WHEN event_type = 'purchase' THEN event_time END) AS first_purchase\n    FROM events\n    GROUP BY user_id\n)\nSELECT user_id\nFROM firsts\nWHERE first_view < first_cart\n  AND first_cart < first_purchase\nORDER BY user_id;\n", "explanation": "\n<p>Conditional aggregation pivots each user's event log into one row with three timestamps:\n<code>MIN(CASE WHEN type = X THEN time END)</code> is \"first occurrence of X\" (the CASE yields NULL for\nother rows, and MIN ignores NULLs). Then the funnel condition is two plain comparisons.</p>\n<p>The missing-step case needs no special handling: if a user never purchased, <code>first_purchase</code>\nis NULL, and <code>first_cart &lt; NULL</code> is unknown — the row is filtered out by three-valued\nlogic. Expected: users 1 and 5 (user 5's duplicate views/carts are absorbed by MIN; user 2 carted before\nviewing; user 3 never purchased; user 4 purchased first). Ordered-funnel analysis is a staple at any\ncompany with a checkout flow, and this MIN-pivot beats the three-way self-join most candidates reach for.</p>\n", "hints": ["Get each step's FIRST timestamp per user: MIN(CASE WHEN type = '...' THEN event_time END).", "MIN skips the NULLs the CASE produces for other event types.", "Then just compare: first_view < first_cart < first_purchase. NULLs (missing steps) self-eliminate."], "order_matters": true}, {"id": "h14", "title": "Top Spender of Each Month", "difficulty": "Hard", "category": "Window Functions", "companies": ["American Express", "Uber", "Revolut"], "description": "\n<p><strong>Vaultpay</strong> runs a monthly VIP program: the customer who spent the most that month gets\nrewards. For each month, find the top spender — and when customers tie for the top spot, include\n<em>all</em> of them.</p>\n<p>Two layers to get right: first aggregate to (month, customer) spend, then rank <em>within each\nmonth</em>.</p>\n<p><strong>Return columns:</strong> <code>month</code> (<code>YYYY-MM</code>), <code>name</code>,\n<code>monthly_spend</code> — ordered by <code>month</code> ascending, then <code>name</code> ascending.</p>\n", "schema": "\nCREATE TABLE customers (\n    customer_id INTEGER PRIMARY KEY,\n    name        TEXT NOT NULL\n);\nCREATE TABLE payments (\n    payment_id  INTEGER PRIMARY KEY,\n    customer_id INTEGER NOT NULL,\n    paid_at     TEXT NOT NULL,\n    amount      REAL NOT NULL\n);\nINSERT INTO customers VALUES\n (1, 'Aldo Reyes'),\n (2, 'Bea Tan'),\n (3, 'Cleo Marsh'),\n (4, 'Dmitri Volkov');\nINSERT INTO payments VALUES\n (1,  1, '2025-01-05', 120.00),\n (2,  1, '2025-01-22', 180.00),\n (3,  2, '2025-01-09', 250.00),\n (4,  3, '2025-01-30', 140.00),\n (5,  1, '2025-02-03', 200.00),\n (6,  2, '2025-02-11', 90.00),\n (7,  2, '2025-02-25', 110.00),\n (8,  3, '2025-02-14', 75.00),\n (9,  4, '2025-02-20', 125.00),\n (10, 2, '2025-03-08', 300.00),\n (11, 3, '2025-03-15', 220.00),\n (12, 4, '2025-03-19', 160.00),\n (13, 4, '2025-03-28', 140.00),\n (14, 1, '2025-03-31', 95.00);\n", "solution": "\nWITH monthly AS (\n    SELECT strftime('%Y-%m', p.paid_at) AS month,\n           c.name,\n           SUM(p.amount) AS monthly_spend\n    FROM payments p\n    JOIN customers c ON c.customer_id = p.customer_id\n    GROUP BY month, c.customer_id, c.name\n),\nranked AS (\n    SELECT month,\n           name,\n           monthly_spend,\n           RANK() OVER (PARTITION BY month ORDER BY monthly_spend DESC) AS rnk\n    FROM monthly\n)\nSELECT month, name, monthly_spend\nFROM ranked\nWHERE rnk = 1\nORDER BY month, name;\n", "explanation": "\n<p>Aggregate-then-rank, with the partition on the <em>derived</em> month column: the first CTE rolls\npayments up to (month, customer) totals, the second ranks within each month, keeping ties via\n<code>RANK</code>.</p>\n<p>February is the trap: Aldo and Bea both total exactly 200.00, so both are returned —\n<code>ROW_NUMBER</code> would silently crown one of them, and which one would be nondeterministic.\nExpected: Jan → Aldo (300); Feb → Aldo and Bea (200 each); Mar → Bea and Dmitri (300 each). Five rows\ntotal. The same shape answers \"top product per store per week\" and a dozen other leaderboard-with-ties\nquestions.</p>\n", "hints": ["Grain first: SUM to (month, customer) before any ranking.", "RANK() OVER (PARTITION BY month ORDER BY spend DESC), keep rank 1.", "Two months contain exact ties — RANK keeps them, ROW_NUMBER would not."], "order_matters": true}, {"id": "ip01", "title": "Customer Retention Cohort", "difficulty": "Hard", "category": "Window Functions & Cohorts", "companies": ["Stripe", "Shopify", "Square"], "source": "Original (inspired by LeetCode #1158)", "description": "\n<p>At <strong>PayFlow</strong>, a payments processor, you need to analyze customer retention over time.\nA cohort is defined by the month customers first appeared. For each cohort, calculate what percentage \nof customers returned in each subsequent month.</p>\n<p>Example: If 100 customers first appeared in Jan, and 45 of them made a transaction in Feb, \nthe retention rate for Jan cohort in Feb is 45%.</p>\n<p><strong>Return columns:</strong> <code>cohort_month</code>, <code>months_active</code> (0=first month, 1=second, etc.), \n<code>cohort_size</code>, <code>returning_customers</code>, <code>retention_rate</code> (as %)</p>\n", "schema": "\nCREATE TABLE transactions (\n    txn_id      INTEGER PRIMARY KEY,\n    customer_id INTEGER NOT NULL,\n    txn_date    TEXT NOT NULL,  -- YYYY-MM-DD\n    amount      DECIMAL NOT NULL\n);\nINSERT INTO transactions VALUES\n (1, 101, '2024-01-15', 50.00),\n (2, 102, '2024-01-20', 75.50),\n (3, 103, '2024-01-25', 100.00),\n (4, 101, '2024-02-10', 60.00),\n (5, 102, '2024-02-18', 80.00),\n (6, 104, '2024-02-05', 45.00),\n (7, 101, '2024-03-12', 55.00),\n (8, 105, '2024-03-08', 90.00),\n (9, 102, '2024-03-20', 70.00),\n (10, 104, '2024-03-15', 50.00);\n", "solution": "\nWITH cohorts AS (\n    SELECT customer_id,\n           STRFTIME('%Y-%m', MIN(txn_date)) AS cohort_month,\n           STRFTIME('%Y-%m', txn_date) AS txn_month\n    FROM transactions\n    GROUP BY customer_id, txn_month\n)\nSELECT cohort_month,\n       (JULIANDAY(txn_month) - JULIANDAY(cohort_month)) / 30.5 AS months_active,\n       COUNT(DISTINCT CASE WHEN txn_month = cohort_month THEN customer_id END) AS cohort_size,\n       COUNT(DISTINCT customer_id) AS returning_customers,\n       ROUND(100.0 * COUNT(DISTINCT customer_id) / \n             COUNT(DISTINCT CASE WHEN txn_month = cohort_month THEN customer_id END), 1) AS retention_rate\nFROM cohorts\nWHERE txn_month >= cohort_month\nGROUP BY cohort_month, months_active\nORDER BY cohort_month, months_active;\n", "explanation": "\n<p>This is a classic cohort analysis pattern. The key insight is to:</p>\n<ol>\n<li>Identify each customer's <code>cohort_month</code> (first appearance month)</li>\n<li>For each transaction month, calculate how many months have passed</li>\n<li>At each \"age\" of the cohort, count how many original members are still active</li>\n</ol>\n<p>The interviewer checks: (1) CTE usage, (2) window function thinking, (3) date arithmetic, \n(4) aggregation with conditions.</p>\n", "hints": ["Use a CTE to define each customer's first month (cohort_month).", "Calculate month offset from the cohort month to the transaction month.", "Count distinct customers at each cohort age to measure retention."], "order_matters": false}, {"id": "ip02", "title": "Median Salary by Department", "difficulty": "Medium", "category": "Statistical Functions", "companies": ["Google", "Facebook", "LinkedIn"], "source": "Original (inspired by LeetCode #618)", "description": "\n<p><strong>TalentHub</strong> HR wants the median salary in each department. Unlike average, median \nis resistant to outliers and gives a better sense of typical compensation.</p>\n<p><strong>Return columns:</strong> <code>department</code>, <code>median_salary</code>. \nOrder by department name.</p>\n", "schema": "\nCREATE TABLE employees (\n    emp_id     INTEGER PRIMARY KEY,\n    name       TEXT NOT NULL,\n    department TEXT NOT NULL,\n    salary     INTEGER NOT NULL\n);\nINSERT INTO employees VALUES\n (1, 'Alice', 'Engineering', 95000),\n (2, 'Bob', 'Engineering', 105000),\n (3, 'Charlie', 'Engineering', 115000),\n (4, 'Dana', 'Sales', 60000),\n (5, 'Eve', 'Sales', 70000),\n (6, 'Frank', 'Sales', 80000),\n (7, 'Grace', 'Sales', 250000),\n (8, 'Henry', 'Marketing', 50000),\n (9, 'Iris', 'Marketing', 55000);\n", "solution": "\nWITH ranked AS (\n    SELECT department,\n           salary,\n           COUNT(*) OVER (PARTITION BY department) AS dept_count,\n           ROW_NUMBER() OVER (PARTITION BY department ORDER BY salary) AS row_num\n    FROM employees\n)\nSELECT department,\n       AVG(salary) AS median_salary\nFROM ranked\nWHERE row_num IN (CEIL(dept_count / 2.0), FLOOR(dept_count / 2.0) + 1)\nGROUP BY department\nORDER BY department;\n", "explanation": "\n<p>SQLite doesn't have a built-in MEDIAN function, so we use window functions to find the middle value(s).\nFor odd-length groups, there's one middle; for even-length, we average the two middles (or the interviewer \nmay accept just one).</p>\n<p>The interviewer checks: (1) window function mastery, (2) understanding of median math, (3) edge cases \n(even vs. odd count).</p>\n", "hints": ["Use ROW_NUMBER to rank salaries within each department.", "The median is the middle row (for odd count) or average of two middle rows (even count).", "Filter rows that match the middle position(s)."], "order_matters": false}, {"id": "ip03", "title": "Active User Streaks", "difficulty": "Hard", "category": "Gap & Island Detection", "companies": ["Netflix", "Discord", "Duolingo"], "source": "Original (inspired by LeetCode #1354)", "description": "\n<p>At <strong>LearnerPlus</strong>, an online learning platform, you want to find users with \n<em>consecutive active days</em> (a streak). Calculate the longest streak for each user and \nwhen it started.</p>\n<p>A user is \"active\" on a day if they accessed the platform.</p>\n<p><strong>Return columns:</strong> <code>user_id</code>, <code>streak_start_date</code>, <code>streak_length</code>.\nOrder by user_id, then by streak_start_date.</p>\n", "schema": "\nCREATE TABLE user_activity (\n    user_id INTEGER NOT NULL,\n    activity_date TEXT NOT NULL,  -- YYYY-MM-DD\n    PRIMARY KEY (user_id, activity_date)\n);\nINSERT INTO user_activity VALUES\n (1, '2024-01-01'), (1, '2024-01-02'), (1, '2024-01-03'), (1, '2024-01-05'),\n (2, '2024-01-01'), (2, '2024-01-02'), (2, '2024-01-04'), (2, '2024-01-05'), (2, '2024-01-06'),\n (3, '2024-01-02'), (3, '2024-01-04'), (3, '2024-01-05');\n", "solution": "\nWITH gaps AS (\n    SELECT user_id,\n           activity_date,\n           JULIANDAY(activity_date) - ROW_NUMBER() OVER (PARTITION BY user_id ORDER BY activity_date) AS gap\n    FROM user_activity\n),\nstreaks AS (\n    SELECT user_id,\n           MIN(activity_date) AS streak_start_date,\n           COUNT(*) AS streak_length,\n           ROW_NUMBER() OVER (PARTITION BY user_id ORDER BY COUNT(*) DESC) AS rank_by_length\n    FROM gaps\n    GROUP BY user_id, gap\n)\nSELECT user_id, streak_start_date, streak_length\nFROM streaks\nWHERE rank_by_length = 1\nORDER BY user_id, streak_start_date;\n", "explanation": "\n<p>This is the classic \"gap and island\" pattern. The trick:</p>\n<ol>\n<li>When consecutive dates exist, the difference (JULIANDAY - ROW_NUMBER) is constant.</li>\n<li>Non-consecutive dates create a different gap value — a new \"island\".</li>\n<li>Group by this gap to find each streak.</li>\n<li>Filter for the longest streak per user.</li>\n</ol>\n<p>Interviewers test: (1) creative date math, (2) window functions, (3) gap detection logic.</p>\n", "hints": ["Compute JULIANDAY(date) - ROW_NUMBER() — consecutive dates have the same result.", "Group by this gap value to find islands of consecutive days.", "Use a window function to rank streaks by length and take the longest."], "order_matters": false}, {"id": "ip04", "title": "Top-N Per Group with Tie-Handling", "difficulty": "Medium", "category": "Window Functions", "companies": ["Uber", "Airbnb", "DoorDash"], "source": "Original (inspired by LeetCode #176)", "description": "\n<p><strong>RideShare+</strong> wants the top 2 most-rated drivers in each city. If drivers tie \nfor 2nd place (or higher), include all of them.</p>\n<p><strong>Return columns:</strong> <code>city</code>, <code>driver_id</code>, <code>rating</code>.\nOrder by city, then rating (descending).</p>\n", "schema": "\nCREATE TABLE drivers (\n    driver_id INTEGER PRIMARY KEY,\n    city      TEXT NOT NULL,\n    rating    DECIMAL NOT NULL\n);\nINSERT INTO drivers VALUES\n (1, 'NYC', 4.9), (2, 'NYC', 4.8), (3, 'NYC', 4.8), (4, 'NYC', 4.7),\n (5, 'LA', 4.95), (6, 'LA', 4.9), (7, 'LA', 4.85), (8, 'LA', 4.85);\n", "solution": "\nWITH ranked AS (\n    SELECT city,\n           driver_id,\n           rating,\n           DENSE_RANK() OVER (PARTITION BY city ORDER BY rating DESC) AS rnk\n    FROM drivers\n)\nSELECT city, driver_id, rating\nFROM ranked\nWHERE rnk <= 2\nORDER BY city, rating DESC;\n", "explanation": "\n<p>Use <code>DENSE_RANK()</code> instead of <code>RANK()</code> to handle ties correctly. \nDENSE_RANK gives the same rank to tied values and doesn't skip numbers, so if two drivers \ntie for 2nd, they both get rank 2, and we correctly include both.</p>\n<p>If you used RANK(), the second tie would be rank 3, causing the third place to be skipped.</p>\n", "hints": ["Use DENSE_RANK to handle ties — it doesn't skip rank numbers.", "RANK() would skip a number after a tie; DENSE_RANK() doesn't.", "Filter WHERE rnk <= 2 to get top 2 per city."], "order_matters": false}, {"id": "ip05", "title": "Product Sales Over Time with Running Total", "difficulty": "Medium", "category": "Window Functions", "companies": ["Amazon", "Shopify", "eBay"], "source": "Original (inspired by LeetCode #1398)", "description": "\n<p><strong>Merchandise Co.</strong> wants to track cumulative sales by product over time. \nFor each product-month combination, show the month, revenue, and running total revenue since the product launched.</p>\n<p><strong>Return columns:</strong> <code>product_id</code>, <code>month</code>, <code>revenue</code>, \n<code>cumulative_revenue</code>. Order by product_id, then month.</p>\n", "schema": "\nCREATE TABLE sales (\n    product_id INTEGER NOT NULL,\n    sale_month TEXT NOT NULL,  -- YYYY-MM\n    revenue INTEGER NOT NULL,\n    PRIMARY KEY (product_id, sale_month)\n);\nINSERT INTO sales VALUES\n (1, '2024-01', 5000), (1, '2024-02', 4500), (1, '2024-03', 6000),\n (2, '2024-02', 8000), (2, '2024-03', 7500), (2, '2024-04', 9000);\n", "solution": "\nSELECT product_id,\n       sale_month AS month,\n       revenue,\n       SUM(revenue) OVER (PARTITION BY product_id ORDER BY sale_month) AS cumulative_revenue\nFROM sales\nORDER BY product_id, sale_month;\n", "explanation": "\n<p>A straightforward window function: <code>SUM() OVER (PARTITION BY ... ORDER BY ...)</code> \ncomputes a running total within each product. The ORDER BY is crucial — it defines the window's \nrange (all rows from the start up to the current row).</p>\n<p>Interviewers test: (1) understanding of window frames, (2) ORDER BY in window functions, \n(3) practical data analysis.</p>\n", "hints": ["Use SUM() OVER to compute a running total.", "PARTITION BY product_id to compute separately for each product.", "ORDER BY month to define the cumulative range."], "order_matters": false}, {"id": "ext01", "title": "Employee Highest Salary in Department", "difficulty": "Medium", "category": "Window Functions", "companies": ["Microsoft", "Amazon"], "source": "Pattern from SQLZoo & LeetCode", "source_url": "https://sqlzoo.net/wiki/SELECT_from_World_Tutorial", "description": "\n<p>Find the employee who earns the highest salary in their department. \nThis combines JOIN with window functions — a classic pattern across interview platforms.</p>\n<p><strong>Learn more:</strong> <a href=\"https://sqlzoo.net/wiki/SELECT_from_World_Tutorial\">SQLZoo Tutorial</a></p>\n", "schema": "\nCREATE TABLE departments (\n    dept_id   INTEGER PRIMARY KEY,\n    dept_name TEXT NOT NULL\n);\nCREATE TABLE employees (\n    emp_id  INTEGER PRIMARY KEY,\n    name    TEXT NOT NULL,\n    salary  INTEGER NOT NULL,\n    dept_id INTEGER NOT NULL\n);\nINSERT INTO departments VALUES (1, 'Engineering'), (2, 'Sales');\nINSERT INTO employees VALUES\n (1, 'Alice', 100000, 1), (2, 'Bob', 90000, 1),\n (3, 'Charlie', 80000, 2), (4, 'Dana', 95000, 2);\n", "solution": "\nWITH max_salary AS (\n    SELECT dept_id, MAX(salary) AS max_sal\n    FROM employees\n    GROUP BY dept_id\n)\nSELECT e.emp_id, e.name, e.salary, d.dept_name\nFROM employees e\nJOIN departments d ON d.dept_id = e.dept_id\nJOIN max_salary m ON m.dept_id = e.dept_id AND m.max_sal = e.salary\nORDER BY d.dept_name;\n", "explanation": "\n<p>Find max salary per department, then join back to get employee details. \nThis pattern appears frequently across interview platforms and tests your ability \nto combine subqueries/CTEs with joins.</p>\n<p><strong>Attribution:</strong> This pattern is covered extensively in SQLZoo and similar tutorial sites.</p>\n", "hints": ["Find the maximum salary for each department first.", "Join back to employees table to get the matching employee."], "order_matters": false}, {"id": "ext02", "title": "Customer Orders Analysis", "difficulty": "Easy", "category": "Aggregation & Joins", "companies": ["Shopify", "eBay"], "source": "Common interview pattern", "source_url": "https://sqlzoo.net/wiki/SELECT_from_Nobel_Tutorial", "description": "\n<p>List each customer with their total number of orders and total spent amount.\nThis is a fundamental business query and appears in most interview curricula.</p>\n<p><strong>Learn more:</strong> <a href=\"https://sqlzoo.net/wiki/SELECT_from_Nobel_Tutorial\">SQLZoo Aggregation Tutorial</a></p>\n", "schema": "\nCREATE TABLE customers (\n    cust_id INTEGER PRIMARY KEY,\n    name    TEXT NOT NULL\n);\nCREATE TABLE orders (\n    order_id INTEGER PRIMARY KEY,\n    cust_id  INTEGER NOT NULL,\n    amount   DECIMAL NOT NULL\n);\nINSERT INTO customers VALUES (1, 'Alice'), (2, 'Bob'), (3, 'Charlie');\nINSERT INTO orders VALUES\n (1, 1, 100), (2, 1, 200), (3, 2, 150), (4, 2, 50);\n", "solution": "\nSELECT c.cust_id, c.name, COUNT(o.order_id) AS order_count, SUM(o.amount) AS total_spent\nFROM customers c\nLEFT JOIN orders o ON c.cust_id = o.cust_id\nGROUP BY c.cust_id, c.name\nORDER BY c.name;\n", "explanation": "\n<p>A fundamental aggregation query. Use LEFT JOIN to ensure customers with no orders appear.\nGROUP BY with aggregate functions is essential SQL.</p>\n", "hints": ["Use LEFT JOIN to include customers even if they have no orders.", "COUNT and SUM aggregate the orders.", "GROUP BY customer to get per-customer totals."], "order_matters": false}, {"id": "sqlz01", "title": "SELECT from World (Basic Filtering)", "difficulty": "Easy", "category": "Filtering & Selection", "companies": ["Educational - General SQL"], "source": "SQLZoo: SELECT from World Tutorial", "source_url": "https://sqlzoo.net/wiki/SELECT_from_World_Tutorial", "description": "\n<p>This problem is <strong>adapted from SQLZoo's SELECT from World tutorial</strong>. \nUse SELECT with WHERE to filter countries by criteria.</p>\n<p>Write a query to find countries with a large area (over 5 million sq km) or large population (over 250 million).\nReturn country name and area.</p>\n<p><strong>Learn more:</strong> <a href=\"https://sqlzoo.net/wiki/SELECT_from_World_Tutorial\">SQLZoo SELECT from World</a></p>\n", "schema": "\nCREATE TABLE world (\n    name       TEXT PRIMARY KEY,\n    continent  TEXT,\n    area       BIGINT,\n    population BIGINT,\n    gdp        BIGINT\n);\nINSERT INTO world VALUES\n ('Afghanistan', 'Asia', 652230, 25500100, NULL),\n ('Albania', 'Europe', 28748, 2876591, 12960000000),\n ('Algeria', 'Africa', 2381741, 37900000, 188681000000),\n ('Andorra', 'Europe', 468, 78115, 3712000000),\n ('Angola', 'Africa', 1246700, 20609294, NULL),\n ('Brazil', 'South America', 8514877, 200566000, 1839758000000),\n ('Canada', 'North America', 9984670, 33679000, 1736436000000),\n ('China', 'Asia', 9596961, 1365444697, 10982084000000),\n ('India', 'Asia', 3287263, 1295291143, 2073543000000),\n ('Russia', 'Europe', 17125191, 146000000, 1583800000000);\n", "solution": "\nSELECT name, area\nFROM world\nWHERE area > 5000000 OR population > 250000000\nORDER BY name;\n", "explanation": "\n<p>This is a fundamental WHERE clause with OR logic. The problem teaches:</p>\n<ol>\n<li>SELECT with multiple columns</li>\n<li>WHERE with compound conditions (OR)</li>\n<li>Comparison operators (>, <)</li>\n<li>ORDER BY for consistent output</li>\n</ol>\n<p><strong>Attribution:</strong> This problem is adapted from SQLZoo's SELECT from World tutorial, \na free educational resource for learning SQL. <a href=\"https://sqlzoo.net/wiki/SELECT_from_World_Tutorial\">Visit SQLZoo</a></p>\n", "hints": ["Use OR to combine two conditions.", "Remember that OR means either condition can be true.", "Use comparison operators: > (greater than), < (less than)."], "order_matters": false}, {"id": "sqlz02", "title": "COUNT and SUM Aggregates", "difficulty": "Easy", "category": "Aggregation", "companies": ["Educational - General SQL"], "source": "SQLZoo: Aggregate Functions", "source_url": "https://sqlzoo.net/wiki/SUM_and_COUNT", "description": "\n<p><strong>Adapted from SQLZoo's SUM and COUNT tutorial</strong>.</p>\n<p>A shipping company wants to know total volume (in tons) of all orders \nand the number of distinct customers who placed orders.</p>\n<p><strong>Return columns:</strong> <code>total_volume</code>, <code>customer_count</code></p>\n<p><strong>Learn more:</strong> <a href=\"https://sqlzoo.net/wiki/SUM_and_COUNT\">SQLZoo SUM and COUNT</a></p>\n", "schema": "\nCREATE TABLE shipments (\n    shipment_id INTEGER PRIMARY KEY,\n    customer_id INTEGER,\n    volume_tons DECIMAL,\n    ship_date TEXT\n);\nINSERT INTO shipments VALUES\n (1, 101, 15.5, '2024-01-05'),\n (2, 102, 22.0, '2024-01-10'),\n (3, 101, 18.5, '2024-01-15'),\n (4, 103, 30.0, '2024-01-20'),\n (5, 102, 25.0, '2024-01-25'),\n (6, 104, 12.0, '2024-02-01');\n", "solution": "\nSELECT SUM(volume_tons) AS total_volume,\n       COUNT(DISTINCT customer_id) AS customer_count\nFROM shipments;\n", "explanation": "\n<p>Key SQL concepts tested:</p>\n<ol>\n<li><code>SUM()</code> — aggregate function to total numeric values</li>\n<li><code>COUNT(DISTINCT ...)</code> — count unique values only</li>\n<li>Single-row aggregates return one row regardless of input size</li>\n</ol>\n<p><strong>Attribution:</strong> Inspired by SQLZoo's SUM and COUNT tutorial. \n<a href=\"https://sqlzoo.net/wiki/SUM_and_COUNT\">Visit SQLZoo</a></p>\n", "hints": ["Use SUM() to add up all values in a column.", "Use COUNT(DISTINCT column) to count unique values.", "Aggregate functions combine multiple rows into one result."], "order_matters": false}, {"id": "sqlz03", "title": "JOIN Tables Together", "difficulty": "Medium", "category": "Joins", "companies": ["Educational - General SQL"], "source": "SQLZoo: JOIN Operations", "source_url": "https://sqlzoo.net/wiki/The_JOIN_operation", "description": "\n<p><strong>Adapted from SQLZoo's JOIN tutorial</strong>.</p>\n<p>You have a database of schools and their match results. Write a query that shows \neach match with the names of both schools involved.</p>\n<p><strong>Return columns:</strong> <code>match_id</code>, <code>home_school</code>, <code>away_school</code>, <code>score</code></p>\n<p><strong>Learn more:</strong> <a href=\"https://sqlzoo.net/wiki/The_JOIN_operation\">SQLZoo JOIN Operations</a></p>\n", "schema": "\nCREATE TABLE schools (\n    school_id INTEGER PRIMARY KEY,\n    school_name TEXT NOT NULL\n);\nCREATE TABLE matches (\n    match_id INTEGER PRIMARY KEY,\n    home_school_id INTEGER NOT NULL,\n    away_school_id INTEGER NOT NULL,\n    score TEXT NOT NULL\n);\nINSERT INTO schools VALUES\n (1, 'Lincoln High'),\n (2, 'Central Academy'),\n (3, 'North Valley'),\n (4, 'Riverside High');\nINSERT INTO matches VALUES\n (1, 1, 2, '3-1'),\n (2, 3, 4, '2-2'),\n (3, 1, 3, '1-0'),\n (4, 2, 4, '4-1');\n", "solution": "\nSELECT m.match_id,\n       h.school_name AS home_school,\n       a.school_name AS away_school,\n       m.score\nFROM matches m\nJOIN schools h ON m.home_school_id = h.school_id\nJOIN schools a ON m.away_school_id = a.school_id\nORDER BY m.match_id;\n", "explanation": "\n<p>This demonstrates multiple JOINs: the same table (schools) is joined twice with different aliases.</p>\n<p>Key concepts:</p>\n<ol>\n<li>Table aliases (h, a, m) for clarity</li>\n<li>Multiple JOINs in one query</li>\n<li>JOIN syntax: <code>FROM table1 JOIN table2 ON condition</code></li>\n<li>Each JOIN adds rows from the joined table based on the condition</li>\n</ol>\n<p><strong>Attribution:</strong> Adapted from SQLZoo's JOIN tutorial, a free resource for SQL learners.\n<a href=\"https://sqlzoo.net/wiki/The_JOIN_operation\">Visit SQLZoo</a></p>\n", "hints": ["Use aliases (h, a) to refer to the schools table twice.", "Each JOIN connects on a foreign key relationship.", "The ON clause specifies how to match rows between tables."], "order_matters": false}, {"id": "sqlz04", "title": "LEFT JOIN for Unmatched Records", "difficulty": "Medium", "category": "Joins", "companies": ["Educational - General SQL"], "source": "SQLZoo: NULL and Joins", "source_url": "https://sqlzoo.net/wiki/NULL_and_JOINs", "description": "\n<p><strong>Adapted from SQLZoo's NULL and JOINs tutorial</strong>.</p>\n<p>A company has employees and their department assignments. Some employees \nhave no department assigned yet. Find all employees with their department names, \nincluding those without departments (showing NULL).</p>\n<p><strong>Return columns:</strong> <code>employee_name</code>, <code>department_name</code></p>\n<p><strong>Learn more:</strong> <a href=\"https://sqlzoo.net/wiki/NULL_and_JOINs\">SQLZoo NULL and JOINs</a></p>\n", "schema": "\nCREATE TABLE employees (\n    emp_id INTEGER PRIMARY KEY,\n    emp_name TEXT NOT NULL,\n    dept_id INTEGER\n);\nCREATE TABLE departments (\n    dept_id INTEGER PRIMARY KEY,\n    dept_name TEXT NOT NULL\n);\nINSERT INTO employees VALUES\n (1, 'Alice', 10),\n (2, 'Bob', 20),\n (3, 'Charlie', NULL),\n (4, 'Dana', 10),\n (5, 'Eve', NULL);\nINSERT INTO departments VALUES\n (10, 'Engineering'),\n (20, 'Sales'),\n (30, 'Marketing');\n", "solution": "\nSELECT e.emp_name,\n       d.dept_name\nFROM employees e\nLEFT JOIN departments d ON e.dept_id = d.dept_id\nORDER BY e.emp_name;\n", "explanation": "\n<p><strong>LEFT JOIN vs INNER JOIN:</strong></p>\n<ul>\n<li>INNER JOIN: Only returns rows where both tables have matching records</li>\n<li>LEFT JOIN: Returns ALL rows from the left table, with NULL where no match exists</li>\n</ul>\n<p>In this query, all employees are shown, and those without departments show NULL.</p>\n<p><strong>Attribution:</strong> Based on SQLZoo's NULL and JOINs tutorial. \n<a href=\"https://sqlzoo.net/wiki/NULL_and_JOINs\">Visit SQLZoo</a></p>\n", "hints": ["LEFT JOIN keeps all rows from the left table (employees).", "If no matching department exists, dept_name will be NULL.", "This is useful for finding unmatched records."], "order_matters": false}, {"id": "sqlz05", "title": "GROUP BY with HAVING", "difficulty": "Medium", "category": "Aggregation & Grouping", "companies": ["Educational - General SQL"], "source": "SQLZoo: GROUP BY and HAVING", "source_url": "https://sqlzoo.net/wiki/SUM_and_COUNT", "description": "\n<p><strong>Adapted from SQLZoo's GROUP BY and HAVING tutorial</strong>.</p>\n<p>An online retailer wants to find products in categories that have \ngenerated more than $50,000 in total revenue. Show category and total revenue.</p>\n<p><strong>Return columns:</strong> <code>category</code>, <code>total_revenue</code></p>\n<p><strong>Learn more:</strong> <a href=\"https://sqlzoo.net/wiki/SUM_and_COUNT\">SQLZoo GROUP BY and HAVING</a></p>\n", "schema": "\nCREATE TABLE sales (\n    sale_id INTEGER PRIMARY KEY,\n    product_id INTEGER,\n    category TEXT,\n    amount DECIMAL\n);\nINSERT INTO sales VALUES\n (1, 101, 'Electronics', 30000),\n (2, 102, 'Electronics', 35000),\n (3, 103, 'Electronics', 20000),\n (4, 201, 'Books', 2500),\n (5, 202, 'Books', 3000),\n (6, 301, 'Clothing', 10000),\n (7, 302, 'Clothing', 15000),\n (8, 303, 'Clothing', 20000),\n (9, 304, 'Clothing', 10000),\n (10, 401, 'Toys', 50000),\n (11, 402, 'Toys', 30000);\n", "solution": "\nSELECT category,\n       SUM(amount) AS total_revenue\nFROM sales\nGROUP BY category\nHAVING SUM(amount) > 50000\nORDER BY total_revenue DESC;\n", "explanation": "\n<p><strong>GROUP BY vs HAVING:</strong></p>\n<ul>\n<li>WHERE filters BEFORE grouping (on raw data)</li>\n<li>HAVING filters AFTER grouping (on aggregated results)</li>\n</ul>\n<p>In this query:</p>\n<ol>\n<li>GROUP BY category — combine sales by category</li>\n<li>HAVING SUM(amount) > 50000 — keep only categories with revenue > 50k</li>\n</ol>\n<p><strong>Attribution:</strong> Inspired by SQLZoo's GROUP BY and HAVING tutorial.\n<a href=\"https://sqlzoo.net/wiki/SUM_and_COUNT\">Visit SQLZoo</a></p>\n", "hints": ["GROUP BY groups rows; HAVING filters the groups.", "WHERE filters before grouping; HAVING filters after.", "Cannot use aggregate functions in WHERE, must use HAVING."], "order_matters": false}, {"id": "dbg01", "type": "debug", "title": "The Missing GROUP BY Column", "difficulty": "Easy", "category": "Aggregation", "companies": [], "description": "\n<p>Someone on the team wrote a query to count employees per department.\nIt runs in SQLite without an error — but it returns wrong/non-deterministic values for <code>name</code>.</p>\n<p>Your job: <strong>fix the bug</strong> so the query returns only <code>department</code> and <code>headcount</code>,\ncorrectly grouped.</p>\n<p><strong>Expected columns:</strong> <code>department</code>, <code>headcount</code> — ordered by <code>department</code>.</p>\n<div class=\"bug-banner\">🐛 Bug type: non-grouped column in SELECT</div>\n", "schema": "\nCREATE TABLE employees (\n    emp_id     INTEGER PRIMARY KEY,\n    name       TEXT NOT NULL,\n    department TEXT NOT NULL,\n    salary     INTEGER NOT NULL\n);\nINSERT INTO employees VALUES\n (1, 'Alice',   'Engineering', 95000),\n (2, 'Bob',     'Engineering', 88000),\n (3, 'Carol',   'Marketing',   72000),\n (4, 'Dave',    'Engineering', 105000),\n (5, 'Eve',     'Marketing',   68000),\n (6, 'Frank',   'HR',          61000),\n (7, 'Grace',   'HR',          63000),\n (8, 'Hank',    'Engineering', 91000);\n", "broken_sql": "SELECT department, name, COUNT(*) AS headcount\nFROM employees\nGROUP BY department\nORDER BY department;", "solution": "\nSELECT department, COUNT(*) AS headcount\nFROM employees\nGROUP BY department\nORDER BY department;\n", "explanation": "\n<p>In standard SQL, every column in SELECT must either be aggregated (via COUNT, SUM, etc.) or appear in GROUP BY.\nSQLite silently allows non-grouped columns and returns an arbitrary row's value — which is almost never correct.</p>\n<p>The fix: remove <code>name</code> from the SELECT list (or move it to GROUP BY if you actually need it per name).</p>\n", "hints": ["Look at every column in the SELECT list.", "Is every non-aggregate column also in GROUP BY?", "Remove any column from SELECT that you're not grouping by and don't need."], "order_matters": true}, {"id": "dbg02", "type": "debug", "title": "Aggregate in WHERE Clause", "difficulty": "Easy", "category": "Aggregation", "companies": ["Amazon", "Google"], "description": "\n<p>The query tries to find departments where the average salary exceeds 80,000.\nIt throws an error: <em>\"misuse of aggregate function AVG()\"</em>.</p>\n<p>Fix the query so it correctly returns departments with <code>avg_salary &gt; 80000</code>.</p>\n<p><strong>Expected columns:</strong> <code>department</code>, <code>avg_salary</code> — ordered by <code>avg_salary DESC</code>.</p>\n<div class=\"bug-banner\">🐛 Bug type: aggregate function in WHERE clause</div>\n", "schema": "\nCREATE TABLE employees (\n    emp_id     INTEGER PRIMARY KEY,\n    name       TEXT NOT NULL,\n    department TEXT NOT NULL,\n    salary     INTEGER NOT NULL\n);\nINSERT INTO employees VALUES\n (1, 'Alice',   'Engineering', 95000),\n (2, 'Bob',     'Engineering', 88000),\n (3, 'Carol',   'Marketing',   72000),\n (4, 'Dave',    'Engineering', 105000),\n (5, 'Eve',     'Marketing',   68000),\n (6, 'Frank',   'Finance',     84000),\n (7, 'Grace',   'Finance',     91000),\n (8, 'Hank',    'Engineering', 91000);\n", "broken_sql": "SELECT department, AVG(salary) AS avg_salary\nFROM employees\nWHERE AVG(salary) > 80000\nGROUP BY department\nORDER BY avg_salary DESC;", "solution": "\nSELECT department, AVG(salary) AS avg_salary\nFROM employees\nGROUP BY department\nHAVING AVG(salary) > 80000\nORDER BY avg_salary DESC;\n", "explanation": "\n<p><code>WHERE</code> filters individual rows <em>before</em> grouping happens, so aggregate functions are not available there.</p>\n<p><code>HAVING</code> filters <em>after</em> grouping — it's the correct clause for filtering on aggregate values.</p>\n<p>Memory trick: WHERE = row filter (pre-GROUP), HAVING = group filter (post-GROUP).</p>\n", "hints": ["WHERE runs before GROUP BY — aggregate functions don't exist yet at that stage.", "There is another SQL clause that filters groups after aggregation.", "Replace WHERE with HAVING."], "order_matters": true}, {"id": "dbg03", "type": "debug", "title": "NULL Comparison with =", "difficulty": "Easy", "category": "NULL Handling", "companies": ["Meta", "Microsoft"], "description": "\n<p>This query tries to find all employees who have no manager (i.e., <code>manager_id</code> is NULL).\nIt runs without error but <strong>returns 0 rows</strong>, even though 2 employees are top-level managers.</p>\n<p>Fix it to correctly return employees without a manager.</p>\n<p><strong>Expected columns:</strong> <code>name</code>, <code>manager_id</code>.</p>\n<div class=\"bug-banner\">🐛 Bug type: comparing NULL with = instead of IS NULL</div>\n", "schema": "\nCREATE TABLE employees (\n    emp_id     INTEGER PRIMARY KEY,\n    name       TEXT NOT NULL,\n    manager_id INTEGER    -- NULL means top-level (no manager)\n);\nINSERT INTO employees VALUES\n (1, 'Alice',   NULL),\n (2, 'Bob',     1),\n (3, 'Carol',   1),\n (4, 'Dave',    NULL),\n (5, 'Eve',     4),\n (6, 'Frank',   4);\n", "broken_sql": "SELECT name, manager_id\nFROM employees\nWHERE manager_id = NULL;", "solution": "\nSELECT name, manager_id\nFROM employees\nWHERE manager_id IS NULL;\n", "explanation": "\n<p>In SQL, NULL represents an unknown value. Comparing anything to NULL with <code>=</code> yields NULL (not TRUE or FALSE),\nso the WHERE condition never matches any row.</p>\n<p>The correct operators are <code>IS NULL</code> and <code>IS NOT NULL</code>.\nThis is one of the most common SQL bugs — interviewers test for it deliberately.</p>\n", "hints": ["Run the broken query — it returns 0 rows despite having NULLs in the table.", "NULL is not a value — it's the absence of one. = NULL never evaluates to true.", "Use IS NULL instead of = NULL."], "order_matters": false}, {"id": "dbg04", "type": "debug", "title": "INNER JOIN Drops Unmatched Rows", "difficulty": "Easy", "category": "Joins", "companies": ["Netflix", "Airbnb"], "description": "\n<p>The query counts orders per customer to identify engagement levels.\nThe requirement: <strong>include every customer</strong>, even those with zero orders.</p>\n<p>The current query silently excludes customers who have never ordered.\nFix it so all 6 customers appear, with <code>order_count = 0</code> for those with no orders.</p>\n<p><strong>Expected columns:</strong> <code>name</code>, <code>order_count</code> — ordered by <code>name</code>.</p>\n<div class=\"bug-banner\">🐛 Bug type: INNER JOIN excludes non-matching rows</div>\n", "schema": "\nCREATE TABLE customers (\n    customer_id INTEGER PRIMARY KEY,\n    name        TEXT NOT NULL\n);\nCREATE TABLE orders (\n    order_id    INTEGER PRIMARY KEY,\n    customer_id INTEGER NOT NULL,\n    amount      REAL NOT NULL\n);\nINSERT INTO customers VALUES\n (1, 'Alice'), (2, 'Bob'), (3, 'Carol'),\n (4, 'Dave'),  (5, 'Eve'), (6, 'Frank');\nINSERT INTO orders VALUES\n (1, 1, 120.50),\n (2, 1, 89.00),\n (3, 3, 45.00),\n (4, 2, 200.00),\n (5, 3, 75.50);\n", "broken_sql": "SELECT c.name, COUNT(o.order_id) AS order_count\nFROM customers c\nINNER JOIN orders o ON c.customer_id = o.customer_id\nGROUP BY c.customer_id, c.name\nORDER BY c.name;", "solution": "\nSELECT c.name, COUNT(o.order_id) AS order_count\nFROM customers c\nLEFT JOIN orders o ON c.customer_id = o.customer_id\nGROUP BY c.customer_id, c.name\nORDER BY c.name;\n", "explanation": "\n<p>INNER JOIN only returns rows where the join condition matches in <em>both</em> tables.\nCustomers with no orders have no matching rows in the <code>orders</code> table, so INNER JOIN drops them.</p>\n<p>LEFT JOIN keeps all rows from the left table (<code>customers</code>) and fills the right side with NULLs when there's no match.\n<code>COUNT(o.order_id)</code> correctly returns 0 for NULL order_ids (since COUNT ignores NULLs).</p>\n", "hints": ["How many rows does the broken query return? Compare to the total number of customers.", "Which join type keeps all rows from the left table, even without a match on the right?", "Change INNER JOIN to LEFT JOIN."], "order_matters": true}, {"id": "dbg05", "type": "debug", "title": "NOT IN with NULLs Always Returns Empty", "difficulty": "Medium", "category": "NULL Handling", "companies": ["Oracle", "SAP"], "description": "\n<p>The query tries to find employees who are not managers (not in the <code>manager_id</code> column).\nIt runs fine but <strong>returns 0 rows</strong>, even though most employees are not managers.</p>\n<p>Fix it to correctly return non-managers.</p>\n<p><strong>Expected columns:</strong> <code>name</code> — ordered by <code>name</code>.</p>\n<div class=\"bug-banner\">🐛 Bug type: NOT IN returns empty when subquery contains NULLs</div>\n", "schema": "\nCREATE TABLE employees (\n    emp_id     INTEGER PRIMARY KEY,\n    name       TEXT NOT NULL,\n    manager_id INTEGER   -- NULL for top-level employees\n);\nINSERT INTO employees VALUES\n (1, 'Alice',   NULL),\n (2, 'Bob',     1),\n (3, 'Carol',   1),\n (4, 'Dave',    NULL),\n (5, 'Eve',     4),\n (6, 'Frank',   4),\n (7, 'Grace',   2);\n", "broken_sql": "SELECT name\nFROM employees\nWHERE emp_id NOT IN (SELECT manager_id FROM employees)\nORDER BY name;", "solution": "\nSELECT name\nFROM employees\nWHERE emp_id NOT IN (\n    SELECT manager_id FROM employees WHERE manager_id IS NOT NULL\n)\nORDER BY name;\n", "explanation": "\n<p>When a subquery used with NOT IN contains even a single NULL, the entire NOT IN expression evaluates to NULL for every row —\nresulting in zero rows returned.</p>\n<p>This is because <code>x NOT IN (1, 2, NULL)</code> is equivalent to\n<code>x != 1 AND x != 2 AND x != NULL</code>. The last part (<code>x != NULL</code>) is always NULL, making the whole\nexpression NULL (not TRUE).</p>\n<p>The fix: filter NULLs out of the subquery with <code>WHERE manager_id IS NOT NULL</code>.</p>\n", "hints": ["Run SELECT DISTINCT manager_id FROM employees — notice the NULL value.", "x NOT IN (...NULL...) is always NULL, not TRUE, for any x.", "Filter out NULLs in the subquery: WHERE manager_id IS NOT NULL."], "order_matters": true}, {"id": "dbg06", "type": "debug", "title": "Wrong ORDER for RANK()", "difficulty": "Easy", "category": "Window Functions", "companies": ["LinkedIn", "Twitter"], "description": "\n<p>The query ranks employees by salary so that the highest-paid employee gets rank 1.\nBut the ranks come out reversed — the lowest salary gets rank 1.</p>\n<p>Fix the window function so <strong>rank 1 = highest salary</strong>.</p>\n<p><strong>Expected columns:</strong> <code>name</code>, <code>salary</code>, <code>salary_rank</code>\n— ordered by <code>salary_rank</code>.</p>\n<div class=\"bug-banner\">🐛 Bug type: wrong ORDER BY direction in OVER clause</div>\n", "schema": "\nCREATE TABLE employees (\n    emp_id  INTEGER PRIMARY KEY,\n    name    TEXT NOT NULL,\n    salary  INTEGER NOT NULL\n);\nINSERT INTO employees VALUES\n (1, 'Alice',   95000),\n (2, 'Bob',     88000),\n (3, 'Carol',   72000),\n (4, 'Dave',   105000),\n (5, 'Eve',     68000),\n (6, 'Frank',  105000);\n", "broken_sql": "SELECT name, salary,\n    RANK() OVER (ORDER BY salary ASC) AS salary_rank\nFROM employees\nORDER BY salary_rank;", "solution": "\nSELECT name, salary,\n    RANK() OVER (ORDER BY salary DESC) AS salary_rank\nFROM employees\nORDER BY salary_rank;\n", "explanation": "\n<p>RANK() assigns rank 1 to the first row according to the ORDER BY inside OVER().\nWith <code>ORDER BY salary ASC</code>, the smallest salary sorts first — so it gets rank 1.</p>\n<p>To rank highest-first, use <code>ORDER BY salary DESC</code>.\nNote that Dave and Frank both earn 105,000 and share rank 1; the next rank is 3 (RANK skips).</p>\n", "hints": ["Which salary ends up with rank 1 in the broken query?", "RANK() assigns rank 1 to the first row in the OVER ORDER BY.", "Change ASC to DESC inside the OVER clause."], "order_matters": true}, {"id": "dbg07", "type": "debug", "title": "Missing ON Clause Creates a Cross Join", "difficulty": "Medium", "category": "Joins", "companies": ["Uber", "DoorDash"], "description": "\n<p>The query is supposed to return sales with their product names, filtered to amounts over 50.\nInstead it returns a massive result — every sale paired with every product.</p>\n<p>This is a <strong>Cartesian product (cross join)</strong> caused by a missing ON clause.\nFix it to join on the correct key.</p>\n<p><strong>Expected columns:</strong> <code>sale_id</code>, <code>product_name</code>, <code>amount</code>\n— where <code>amount &gt; 50</code>, ordered by <code>sale_id</code>.</p>\n<div class=\"bug-banner\">🐛 Bug type: missing ON clause → unintended cross join</div>\n", "schema": "\nCREATE TABLE products (\n    product_id   INTEGER PRIMARY KEY,\n    product_name TEXT NOT NULL,\n    price        REAL NOT NULL\n);\nCREATE TABLE sales (\n    sale_id    INTEGER PRIMARY KEY,\n    product_id INTEGER NOT NULL,\n    amount     REAL NOT NULL,\n    sale_date  TEXT NOT NULL\n);\nINSERT INTO products VALUES\n (1, 'Laptop',   999.00),\n (2, 'Mouse',     29.99),\n (3, 'Keyboard',  79.00),\n (4, 'Monitor',  349.00);\nINSERT INTO sales VALUES\n (1, 1, 999.00, '2024-01-10'),\n (2, 2,  29.99, '2024-01-11'),\n (3, 3,  79.00, '2024-01-12'),\n (4, 4, 349.00, '2024-01-13'),\n (5, 1, 999.00, '2024-01-14'),\n (6, 2,  29.99, '2024-01-15');\n", "broken_sql": "SELECT s.sale_id, p.product_name, s.amount\nFROM sales s\nJOIN products p\nWHERE s.amount > 50\nORDER BY s.sale_id;", "solution": "\nSELECT s.sale_id, p.product_name, s.amount\nFROM sales s\nJOIN products p ON s.product_id = p.product_id\nWHERE s.amount > 50\nORDER BY s.sale_id;\n", "explanation": "\n<p>A JOIN without an ON clause (or WHERE-based join condition) produces a Cartesian product:\nevery row in the left table is paired with every row in the right table.</p>\n<p>Here 6 sales × 4 products = 24 rows — but only a fraction of those have the WHERE condition satisfied,\nso it \"looks\" like fewer rows but is still wrong.</p>\n<p>Always add <code>ON left.key = right.key</code> to define how tables relate.</p>\n", "hints": ["Count the rows in the broken query. Then count products × sales separately.", "A JOIN without ON means every row pairs with every other row.", "Add: ON s.product_id = p.product_id"], "order_matters": true}, {"id": "dbg08", "type": "debug", "title": "CASE WHEN Order Bug", "difficulty": "Medium", "category": "Conditional Logic", "companies": ["Stripe", "Square"], "description": "\n<p>The query classifies employees into <em>Senior</em> (≥5 years), <em>Mid</em> (2–4 years),\nand <em>Junior</em> (&lt;2 years) levels based on <code>years_exp</code>.</p>\n<p>The bug: nobody is classified as <em>Senior</em> — they all fall into <em>Mid</em> or <em>Junior</em>.</p>\n<p>Fix the CASE statement so Senior employees are correctly identified.</p>\n<p><strong>Expected columns:</strong> <code>name</code>, <code>years_exp</code>, <code>level</code>\n— ordered by <code>years_exp DESC</code>.</p>\n<div class=\"bug-banner\">🐛 Bug type: CASE WHEN conditions evaluated in wrong order</div>\n", "schema": "\nCREATE TABLE employees (\n    emp_id    INTEGER PRIMARY KEY,\n    name      TEXT NOT NULL,\n    years_exp INTEGER NOT NULL\n);\nINSERT INTO employees VALUES\n (1, 'Alice',   8),\n (2, 'Bob',     3),\n (3, 'Carol',   1),\n (4, 'Dave',    6),\n (5, 'Eve',     2),\n (6, 'Frank',   0),\n (7, 'Grace',   5);\n", "broken_sql": "SELECT name, years_exp,\n    CASE\n        WHEN years_exp >= 2 THEN 'Mid'\n        WHEN years_exp >= 5 THEN 'Senior'\n        ELSE 'Junior'\n    END AS level\nFROM employees\nORDER BY years_exp DESC;", "solution": "\nSELECT name, years_exp,\n    CASE\n        WHEN years_exp >= 5 THEN 'Senior'\n        WHEN years_exp >= 2 THEN 'Mid'\n        ELSE 'Junior'\n    END AS level\nFROM employees\nORDER BY years_exp DESC;\n", "explanation": "\n<p>CASE evaluates conditions top-to-bottom and returns the THEN value for the <em>first</em> true condition.\nWith <code>WHEN years_exp >= 2</code> first, any employee with 5+ years also satisfies <code>>= 2</code>\nand is immediately classified as Mid — the Senior branch is never reached.</p>\n<p>Rule: always put the <strong>most restrictive condition first</strong> (highest threshold first for >= checks).</p>\n", "hints": ["What is Alice's level in the broken query? She has 8 years of experience.", "CASE stops at the first true condition. Does >= 2 also match employees with >= 5 years?", "Reorder: put WHEN years_exp >= 5 before WHEN years_exp >= 2."], "order_matters": true}, {"id": "dbg09", "type": "debug", "title": "Date Range Off-by-One", "difficulty": "Easy", "category": "Date Functions", "companies": ["Booking.com", "Expedia"], "description": "\n<p>The query retrieves orders placed in <strong>January 2024</strong>.\nIt misses orders placed on January 31st because the date range ends on the 30th.</p>\n<p>Fix the BETWEEN range so all January 2024 orders are included.</p>\n<p><strong>Expected columns:</strong> <code>order_id</code>, <code>order_date</code>, <code>amount</code>\n— ordered by <code>order_date</code>.</p>\n<div class=\"bug-banner\">🐛 Bug type: off-by-one in BETWEEN date range</div>\n", "schema": "\nCREATE TABLE orders (\n    order_id   INTEGER PRIMARY KEY,\n    order_date TEXT NOT NULL,\n    amount     REAL NOT NULL\n);\nINSERT INTO orders VALUES\n (1, '2024-01-05',  120.00),\n (2, '2024-01-15',   89.50),\n (3, '2024-01-30',  200.00),\n (4, '2024-01-31',   55.00),\n (5, '2024-02-01',  310.00),\n (6, '2024-02-14',   45.00);\n", "broken_sql": "SELECT order_id, order_date, amount\nFROM orders\nWHERE order_date BETWEEN '2024-01-01' AND '2024-01-30'\nORDER BY order_date;", "solution": "\nSELECT order_id, order_date, amount\nFROM orders\nWHERE order_date BETWEEN '2024-01-01' AND '2024-01-31'\nORDER BY order_date;\n", "explanation": "\n<p>BETWEEN is inclusive on both ends: <code>BETWEEN '2024-01-01' AND '2024-01-30'</code> includes the 30th\nbut not the 31st. January has 31 days, so order #4 is missed.</p>\n<p>Two good practices: (1) use <code>BETWEEN '2024-01-01' AND '2024-01-31'</code>, or\n(2) use a half-open range: <code>order_date >= '2024-01-01' AND order_date < '2024-02-01'</code>.\nThe half-open pattern works cleanly for any month length.</p>\n", "hints": ["How many days does January have?", "BETWEEN is inclusive. What is the last date in the BETWEEN range?", "Change '2024-01-30' to '2024-01-31'."], "order_matters": true}, {"id": "dbg10", "type": "debug", "title": "Duplicate Rows from Multi-Table Join", "difficulty": "Medium", "category": "Joins", "companies": ["Shopify", "Amazon"], "description": "\n<p>The query finds customer names who purchased a product from the <em>electronics</em> category.\nIt returns duplicate names because some customers have multiple electronics orders.</p>\n<p>Fix the query to return each customer name only once.</p>\n<p><strong>Expected columns:</strong> <code>name</code> — ordered alphabetically, no duplicates.</p>\n<div class=\"bug-banner\">🐛 Bug type: many-to-many join fan-out causing duplicate rows</div>\n", "schema": "\nCREATE TABLE customers (\n    customer_id INTEGER PRIMARY KEY,\n    name        TEXT NOT NULL\n);\nCREATE TABLE orders (\n    order_id    INTEGER PRIMARY KEY,\n    customer_id INTEGER NOT NULL,\n    order_date  TEXT NOT NULL\n);\nCREATE TABLE order_items (\n    item_id    INTEGER PRIMARY KEY,\n    order_id   INTEGER NOT NULL,\n    product_id INTEGER NOT NULL,\n    quantity   INTEGER NOT NULL\n);\nCREATE TABLE products (\n    product_id INTEGER PRIMARY KEY,\n    name       TEXT NOT NULL,\n    category   TEXT NOT NULL\n);\nINSERT INTO customers VALUES\n (1, 'Alice'), (2, 'Bob'), (3, 'Carol'), (4, 'Dave');\nINSERT INTO orders VALUES\n (1, 1, '2024-02-01'), (2, 1, '2024-03-10'),\n (3, 2, '2024-02-15'), (4, 3, '2024-01-20');\nINSERT INTO products VALUES\n (1, 'Laptop',   'electronics'),\n (2, 'T-Shirt',  'clothing'),\n (3, 'Phone',    'electronics'),\n (4, 'Headphones','electronics');\nINSERT INTO order_items VALUES\n (1, 1, 1, 1),\n (2, 1, 3, 2),\n (3, 2, 4, 1),\n (4, 3, 2, 3),\n (5, 4, 1, 1);\n", "broken_sql": "SELECT c.name\nFROM customers c\nJOIN orders o      ON c.customer_id = o.customer_id\nJOIN order_items i ON o.order_id    = i.order_id\nJOIN products p    ON i.product_id  = p.product_id\nWHERE p.category = 'electronics'\nORDER BY c.name;", "solution": "\nSELECT DISTINCT c.name\nFROM customers c\nJOIN orders o      ON c.customer_id = o.customer_id\nJOIN order_items i ON o.order_id    = i.order_id\nJOIN products p    ON i.product_id  = p.product_id\nWHERE p.category = 'electronics'\nORDER BY c.name;\n", "explanation": "\n<p>When you JOIN through multiple tables and a customer has several electronics purchases,\nthe join creates one row per (customer, order, item, product) combination — the customer name appears once for each.</p>\n<p>The fix is DISTINCT, which deduplicates the final result set.\nAlternatively, you could restructure the query using EXISTS or a subquery that aggregates first.</p>\n", "hints": ["Count how many rows the broken query returns vs how many unique customers you expect.", "Alice has 3 electronics items across 2 orders — how many times does her name appear?", "Add DISTINCT after SELECT."], "order_matters": true}, {"id": "m19", "title": "Salary Percentile Band", "difficulty": "Medium", "category": "Window Functions", "companies": ["Microsoft", "Amazon", "Google"], "tsql": true, "description": "\n<p>HR at <strong>Vantage Systems</strong> wants every employee bucketed into a salary band for\nthe annual comp review.</p>\n<p>Using <code>NTILE(4)</code>, assign each employee to a quartile (1 = bottom 25 %, 4 = top 25 %)\nand label it as <code>Bottom 25%</code>, <code>Lower Mid</code>, <code>Upper Mid</code>, or\n<code>Top 25%</code>.</p>\n<p><strong>Return columns:</strong> <code>name</code>, <code>department</code>, <code>salary</code>,\n<code>quartile</code>, <code>salary_band</code> — ordered by salary descending.</p>\n", "schema": "\nCREATE TABLE employees (\n    emp_id     INT PRIMARY KEY,\n    name       VARCHAR(100) NOT NULL,\n    department VARCHAR(100) NOT NULL,\n    salary     INT NOT NULL\n);\nINSERT INTO employees VALUES\n (1,  'Mona Diaz',      'Engineering', 155000),\n (2,  'Kyle Renner',    'Engineering', 148000),\n (3,  'Suki Ito',       'Engineering', 121000),\n (4,  'Ira Glass',      'Engineering', 104000),\n (5,  'Gail Strand',    'Sales',       118000),\n (6,  'Pat Boyle',      'Sales',        98000),\n (7,  'Ravi Kapoor',    'Sales',        87000),\n (8,  'Fern Ellis',     'Design',      112000),\n (9,  'Drew Holt',      'Design',      109000),\n (10, 'Lena Park',      'Design',       95000),\n (11, 'Omar Haddad',    'Finance',     132000),\n (12, 'Iris Chen',      'Finance',     126000);\n", "solution": "\nSELECT name,\n       department,\n       salary,\n       NTILE(4) OVER (ORDER BY salary) AS quartile,\n       CASE NTILE(4) OVER (ORDER BY salary)\n           WHEN 1 THEN 'Bottom 25%'\n           WHEN 2 THEN 'Lower Mid'\n           WHEN 3 THEN 'Upper Mid'\n           ELSE        'Top 25%'\n       END AS salary_band\nFROM employees\nORDER BY salary DESC;\n", "explanation": "\n<p><code>NTILE(4)</code> divides the ordered result set into 4 equal buckets (as even as possible)\nand assigns each row a bucket number 1–4. It does <em>not</em> partition here — we rank globally\nacross the whole company. The <code>CASE</code> on the same window expression maps the number to a\nhuman-readable label.</p>\n<p>Common mistake: using <code>PARTITION BY department</code> — that would give quartiles <em>within\neach department</em>, not company-wide, which changes the meaning entirely.</p>\n", "hints": ["NTILE(n) splits the full ordered set into n buckets — no PARTITION BY needed for company-wide ranking.", "You can use the window expression twice: once for the number, once inside CASE.", "NTILE distributes rows as evenly as possible; with 12 rows and 4 buckets, each bucket gets exactly 3."], "order_matters": false}, {"id": "m20", "title": "3-Day Rolling Average Revenue", "difficulty": "Medium", "category": "Window Functions", "companies": ["Shopify", "Stripe", "Square"], "tsql": true, "description": "\n<p><strong>MerchantHub</strong> wants to smooth out day-to-day revenue spikes for its executive\ndashboard. Compute the 3-day rolling average (current day + 2 preceding days) for each date.</p>\n<p><strong>Return columns:</strong> <code>sale_date</code>, <code>daily_revenue</code>,\n<code>rolling_avg_3d</code> (rounded to 2 decimal places) — ordered by date ascending.</p>\n", "schema": "\nCREATE TABLE daily_revenue (\n    sale_date     DATE PRIMARY KEY,\n    daily_revenue DECIMAL(10,2) NOT NULL\n);\nINSERT INTO daily_revenue VALUES\n ('2025-01-01', 12400.00),\n ('2025-01-02',  9800.00),\n ('2025-01-03', 15200.00),\n ('2025-01-04', 11600.00),\n ('2025-01-05', 18900.00),\n ('2025-01-06', 14300.00),\n ('2025-01-07', 21000.00),\n ('2025-01-08', 16500.00);\n", "solution": "\nSELECT sale_date,\n       daily_revenue,\n       ROUND(AVG(CAST(daily_revenue AS FLOAT))\n             OVER (ORDER BY sale_date ROWS BETWEEN 2 PRECEDING AND CURRENT ROW), 2)\n           AS rolling_avg_3d\nFROM daily_revenue\nORDER BY sale_date;\n", "explanation": "\n<p><code>ROWS BETWEEN 2 PRECEDING AND CURRENT ROW</code> creates a sliding window of exactly 3 rows:\ntoday and the 2 days before it. For the first two dates the window is smaller (1 or 2 rows) — that\nis expected behaviour and mirrors how BI tools handle the boundary.</p>\n<p><code>RANGE BETWEEN 2 PRECEDING AND CURRENT ROW</code> would use value-based comparison, not\nrow-based — a subtle but important difference interviewers test.</p>\n", "hints": ["Use ROWS BETWEEN 2 PRECEDING AND CURRENT ROW inside AVG() OVER.", "ROWS = physical rows; RANGE = logical value range — they differ when there are ties.", "CAST to FLOAT before AVG to avoid integer division truncation."], "order_matters": true}, {"id": "m21", "title": "Cumulative Headcount by Hire Month", "difficulty": "Medium", "category": "Window Functions", "companies": ["LinkedIn", "Workday", "ADP"], "tsql": true, "description": "\n<p>People Ops at <strong>NovaCo</strong> tracks hiring momentum. For each month that had at least one\nnew hire, show the number of new hires that month and the running total headcount since the company's\nfounding.</p>\n<p><strong>Return columns:</strong> <code>hire_month</code> (format <code>YYYY-MM</code>),\n<code>new_hires</code>, <code>cumulative_headcount</code> — ordered by hire_month ascending.</p>\n", "schema": "\nCREATE TABLE employees (\n    emp_id    INT PRIMARY KEY,\n    name      VARCHAR(100) NOT NULL,\n    hire_date DATE NOT NULL\n);\nINSERT INTO employees VALUES\n (1,  'Alice Wong',    '2024-01-15'),\n (2,  'Brian Shah',    '2024-01-22'),\n (3,  'Cara Müller',   '2024-02-10'),\n (4,  'Diego Lopez',   '2024-03-05'),\n (5,  'Eva Novak',     '2024-03-18'),\n (6,  'Felix Adeyemi', '2024-03-29'),\n (7,  'Grace Kim',     '2024-04-02'),\n (8,  'Hugo Ferreira', '2024-05-14'),\n (9,  'Isla Brennan',  '2024-05-20'),\n (10, 'Jiro Sato',     '2024-06-01');\n", "solution": "\nWITH monthly AS (\n    SELECT FORMAT(hire_date, 'yyyy-MM') AS hire_month,\n           COUNT(*) AS new_hires\n    FROM employees\n    GROUP BY FORMAT(hire_date, 'yyyy-MM')\n)\nSELECT hire_month,\n       new_hires,\n       SUM(new_hires) OVER (ORDER BY hire_month\n                            ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW)\n           AS cumulative_headcount\nFROM monthly\nORDER BY hire_month;\n", "explanation": "\n<p><code>SUM() OVER (ORDER BY ... ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW)</code> is the\nrunning-total pattern. Grouping first in a CTE, then running the window over the aggregated rows,\navoids the common mistake of applying <code>SUM(COUNT(*))</code> directly — which SQL won't allow\nwithout nesting.</p>\n<p><code>FORMAT(hire_date, 'yyyy-MM')</code> is the T-SQL way to extract a year-month string.\nInterviewers also accept <code>CONVERT(VARCHAR(7), hire_date, 120)</code>.</p>\n", "hints": ["GROUP BY month first in a CTE, then apply the window function over the grouped results.", "SUM() OVER (ORDER BY month ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) = running total.", "FORMAT(hire_date, 'yyyy-MM') gives 'YYYY-MM' strings that sort lexicographically."], "order_matters": true}, {"id": "m22", "title": "Customers Who Have Never Ordered", "difficulty": "Medium", "category": "Joins", "companies": ["Amazon", "Shopify", "Etsy"], "tsql": true, "description": "\n<p>The marketing team at <strong>CartCo</strong> wants to send a re-engagement email to every\nregistered customer who has never placed an order.</p>\n<p><strong>Return columns:</strong> <code>customer_id</code>, <code>name</code>, <code>email</code>\n— ordered by name ascending.</p>\n", "schema": "\nCREATE TABLE customers (\n    customer_id INT PRIMARY KEY,\n    name        VARCHAR(100) NOT NULL,\n    email       VARCHAR(100) NOT NULL,\n    signup_date DATE NOT NULL\n);\nCREATE TABLE orders (\n    order_id    INT PRIMARY KEY,\n    customer_id INT NOT NULL,\n    order_date  DATE NOT NULL,\n    amount      DECIMAL(10,2) NOT NULL\n);\nINSERT INTO customers VALUES\n (1, 'Alice Brown',   'alice@example.com',   '2024-01-10'),\n (2, 'Bob Chen',      'bob@example.com',     '2024-02-14'),\n (3, 'Clara Davis',   'clara@example.com',   '2024-03-01'),\n (4, 'Daniel Evans',  'daniel@example.com',  '2024-03-22'),\n (5, 'Elena Flores',  'elena@example.com',   '2024-04-05'),\n (6, 'Frank Garcia',  'frank@example.com',   '2024-04-18');\nINSERT INTO orders VALUES\n (101, 1, '2024-02-01', 59.99),\n (102, 1, '2024-04-10', 120.00),\n (103, 3, '2024-03-15', 34.50),\n (104, 5, '2024-05-02', 89.00);\n", "solution": "\nSELECT c.customer_id, c.name, c.email\nFROM customers c\nLEFT JOIN orders o ON o.customer_id = c.customer_id\nWHERE o.order_id IS NULL\nORDER BY c.name;\n", "explanation": "\n<p>A LEFT JOIN keeps all customers regardless of whether they have orders. For customers with no\nmatching order row, every column from <code>orders</code> is NULL — so <code>WHERE o.order_id IS\nNULL</code> isolates the never-ordered group.</p>\n<p>Alternatives: <code>NOT EXISTS</code> (preferred for readability) and <code>NOT IN</code>\n(dangerous — fails silently if the subquery returns any NULL <code>order_id</code>). Mention all\nthree in an interview and explain why NOT IN can break.</p>\n", "hints": ["A LEFT JOIN includes every customer row — even those with no matching order.", "When the right side of a LEFT JOIN has no match, its columns are NULL.", "Filter WHERE order_id IS NULL to keep only those with no orders."], "order_matters": false}, {"id": "m23", "title": "Employee and Their Manager", "difficulty": "Medium", "category": "Joins", "companies": ["Microsoft", "Oracle", "SAP"], "tsql": true, "description": "\n<p><strong>Pinnacle Corp</strong> stores its org chart in a single self-referencing table. HR needs\na flat list of every employee paired with their manager's name. Employees without a manager (the\nCEO) should still appear with <code>NULL</code> for manager.</p>\n<p><strong>Return columns:</strong> <code>employee</code>, <code>manager</code>,\n<code>department</code> — ordered by department, then employee.</p>\n", "schema": "\nCREATE TABLE employees (\n    emp_id     INT PRIMARY KEY,\n    name       VARCHAR(100) NOT NULL,\n    department VARCHAR(100) NOT NULL,\n    manager_id INT\n);\nINSERT INTO employees VALUES\n (1,  'Sarah Lin',     'Executive',   NULL),\n (2,  'Tom Reyes',     'Engineering', 1),\n (3,  'Nadia Patel',   'Engineering', 2),\n (4,  'Leo Kwan',      'Engineering', 2),\n (5,  'Chloe Ortega',  'Sales',       1),\n (6,  'Marcus Webb',   'Sales',       5),\n (7,  'Priya Nair',    'Sales',       5),\n (8,  'Jin Park',      'Finance',     1),\n (9,  'Rosa Lima',     'Finance',     8);\n", "solution": "\nSELECT e.name AS employee,\n       m.name AS manager,\n       e.department\nFROM employees e\nLEFT JOIN employees m ON m.emp_id = e.manager_id\nORDER BY e.department, e.name;\n", "explanation": "\n<p>A self-join joins the table to itself: alias <code>e</code> for employees and <code>m</code> for\nmanagers. The join condition <code>m.emp_id = e.manager_id</code> links each employee to their\nmanager row. LEFT JOIN is essential — Sarah Lin has no manager, so an INNER JOIN would silently\ndrop her from the result.</p>\n", "hints": ["Join the table to itself with two aliases: one for the employee, one for the manager.", "The join condition is m.emp_id = e.manager_id.", "Use LEFT JOIN so the top of the hierarchy (no manager) still appears."], "order_matters": false}, {"id": "m24", "title": "Unshipped Orders", "difficulty": "Medium", "category": "Joins", "companies": ["Amazon", "FedEx", "DHL"], "tsql": true, "description": "\n<p>The operations team at <strong>SwiftShip</strong> needs a list of all orders that have been\nplaced but not yet shipped so they can prioritise fulfilment.</p>\n<p><strong>Return columns:</strong> <code>order_id</code>, <code>customer_id</code>,\n<code>order_date</code>, <code>amount</code> — ordered by order_date ascending.</p>\n", "schema": "\nCREATE TABLE orders (\n    order_id    INT PRIMARY KEY,\n    customer_id INT NOT NULL,\n    order_date  DATE NOT NULL,\n    amount      DECIMAL(10,2) NOT NULL\n);\nCREATE TABLE shipments (\n    shipment_id INT PRIMARY KEY,\n    order_id    INT NOT NULL,\n    shipped_at  DATE NOT NULL\n);\nINSERT INTO orders VALUES\n (1001, 1, '2025-02-01', 149.00),\n (1002, 2, '2025-02-03',  89.50),\n (1003, 1, '2025-02-05', 210.00),\n (1004, 3, '2025-02-07',  55.00),\n (1005, 4, '2025-02-08', 320.00),\n (1006, 2, '2025-02-10',  75.00);\nINSERT INTO shipments VALUES\n (9001, 1001, '2025-02-03'),\n (9002, 1002, '2025-02-06'),\n (9003, 1003, '2025-02-08');\n", "solution": "\nSELECT o.order_id, o.customer_id, o.order_date, o.amount\nFROM orders o\nWHERE NOT EXISTS (\n    SELECT 1 FROM shipments s WHERE s.order_id = o.order_id\n)\nORDER BY o.order_date;\n", "explanation": "\n<p><code>NOT EXISTS</code> is the cleanest and safest anti-join. It short-circuits on the first\nmatch and is NULL-safe (unlike <code>NOT IN</code>). The alternative LEFT JOIN approach works too:\n<code>LEFT JOIN shipments ON ... WHERE shipments.order_id IS NULL</code>.</p>\n<p>In interviews, always mention that <code>NOT IN (SELECT order_id ...)</code> breaks if any\n<code>order_id</code> in <code>shipments</code> is NULL — NOT EXISTS does not have this problem.</p>\n", "hints": ["You need orders with NO matching row in shipments — this is an anti-join.", "NOT EXISTS is the cleanest approach and is NULL-safe.", "Alternative: LEFT JOIN shipments WHERE shipments.order_id IS NULL."], "order_matters": false}, {"id": "m25", "title": "Frequently Bought Together", "difficulty": "Medium", "category": "Joins", "companies": ["Amazon", "eBay", "Walmart"], "tsql": true, "description": "\n<p>The recommendation team at <strong>BuyNest</strong> wants to find product pairs that appear in\nthe same order at least twice — the foundation of a \"customers also bought\" feature.</p>\n<p><strong>Return columns:</strong> <code>product_a</code>, <code>product_b</code>,\n<code>co_order_count</code> — ordered by co_order_count descending, then product_a,\nthen product_b.</p>\n", "schema": "\nCREATE TABLE order_items (\n    item_id    INT PRIMARY KEY,\n    order_id   INT NOT NULL,\n    product_id INT NOT NULL\n);\nINSERT INTO order_items VALUES\n (1,  101, 1), (2,  101, 2), (3,  101, 3),\n (4,  102, 1), (5,  102, 2), (6,  102, 4),\n (7,  103, 2), (8,  103, 3),\n (9,  104, 1), (10, 104, 2), (11, 104, 3),\n (12, 105, 1), (13, 105, 3),\n (14, 106, 3), (15, 106, 4);\n", "solution": "\nSELECT a.product_id AS product_a,\n       b.product_id AS product_b,\n       COUNT(*) AS co_order_count\nFROM order_items a\nJOIN order_items b\n    ON b.order_id   = a.order_id\n   AND b.product_id > a.product_id\nGROUP BY a.product_id, b.product_id\nHAVING COUNT(*) >= 2\nORDER BY co_order_count DESC, product_a, product_b;\n", "explanation": "\n<p>Self-joining <code>order_items</code> on the same <code>order_id</code> generates every pair of\nproducts in each order. The condition <code>b.product_id &gt; a.product_id</code> prevents counting\nboth (1,2) and (2,1) — each unordered pair appears exactly once. <code>HAVING COUNT(*) &gt;= 2</code>\nfilters to pairs that co-occur in at least two different orders.</p>\n", "hints": ["Self-join order_items on order_id to get every pair of products in the same order.", "b.product_id > a.product_id ensures each pair is counted once (no (2,1) if you already have (1,2)).", "HAVING COUNT(*) >= 2 keeps only frequently co-occurring pairs."], "order_matters": false}, {"id": "m26", "title": "Revenue by Day of Week", "difficulty": "Medium", "category": "Aggregation", "companies": ["Uber Eats", "DoorDash", "Grubhub"], "tsql": true, "description": "\n<p><strong>ForkFast</strong>, a food-delivery app, wants to know which days of the week generate\nthe most revenue to optimise driver incentives.</p>\n<p>For each day of the week, compute total orders and total revenue. Include all 7 days even if\nsome have no data (show 0).</p>\n<p><strong>Return columns:</strong> <code>day_of_week</code>, <code>total_orders</code>,\n<code>total_revenue</code> — ordered by the calendar day number (Sunday = 1).</p>\n", "schema": "\nCREATE TABLE orders (\n    order_id   INT PRIMARY KEY,\n    order_date DATE NOT NULL,\n    amount     DECIMAL(10,2) NOT NULL\n);\nINSERT INTO orders VALUES\n (1,  '2025-01-06', 34.50),\n (2,  '2025-01-06', 21.00),\n (3,  '2025-01-07', 88.00),\n (4,  '2025-01-08', 45.00),\n (5,  '2025-01-09', 62.50),\n (6,  '2025-01-10', 77.00),\n (7,  '2025-01-11', 110.00),\n (8,  '2025-01-12', 95.00),\n (9,  '2025-01-13', 40.00),\n (10, '2025-01-14', 130.00),\n (11, '2025-01-15', 58.00),\n (12, '2025-01-17', 72.00),\n (13, '2025-01-18', 115.00),\n (14, '2025-01-19', 48.00);\n", "solution": "\nSELECT DATENAME(weekday, order_date)       AS day_of_week,\n       COUNT(*)                            AS total_orders,\n       SUM(amount)                         AS total_revenue\nFROM orders\nGROUP BY DATENAME(weekday, order_date),\n         DATEPART(weekday, order_date)\nORDER BY DATEPART(weekday, order_date);\n", "explanation": "\n<p><code>DATENAME(weekday, date)</code> returns the full name ('Monday', 'Tuesday', …).\n<code>DATEPART(weekday, date)</code> returns the integer (1 = Sunday by default in SQL Server).\nYou must include <code>DATEPART</code> in the GROUP BY so the ORDER BY works — or use a subquery\nto alias it first. Grouping by name alone would silently merge Monday dates with Monday dates but\nORDER BY the name alphabetically ('Friday' before 'Monday'), not in calendar order.</p>\n", "hints": ["DATENAME(weekday, date) gives the day name; DATEPART(weekday, date) gives the number.", "Include DATEPART in the GROUP BY so you can ORDER BY it for correct calendar order.", "In SQL Server, DATEPART(weekday, ...) returns 1 for Sunday by default."], "order_matters": true}, {"id": "m27", "title": "Users Active on Both Free and Paid Tiers", "difficulty": "Medium", "category": "Aggregation", "companies": ["Slack", "Notion", "Dropbox"], "tsql": true, "description": "\n<p><strong>FlowApp</strong> has a freemium model. The growth team wants to identify users who have\ntriggered events on <em>both</em> the free and paid tiers — these are the strongest upgrade\ncandidates.</p>\n<p><strong>Return columns:</strong> <code>user_id</code>, <code>free_events</code>,\n<code>paid_events</code> — ordered by user_id.</p>\n", "schema": "\nCREATE TABLE events (\n    event_id   INT PRIMARY KEY,\n    user_id    INT NOT NULL,\n    event_type VARCHAR(20) NOT NULL,  -- 'free' or 'paid'\n    event_date DATE NOT NULL\n);\nINSERT INTO events VALUES\n (1,  101, 'free',  '2025-01-02'),\n (2,  101, 'paid',  '2025-01-05'),\n (3,  101, 'free',  '2025-01-10'),\n (4,  102, 'free',  '2025-01-03'),\n (5,  102, 'free',  '2025-01-08'),\n (6,  103, 'paid',  '2025-01-04'),\n (7,  103, 'paid',  '2025-01-09'),\n (8,  103, 'free',  '2025-01-12'),\n (9,  104, 'free',  '2025-01-06'),\n (10, 105, 'paid',  '2025-01-07');\n", "solution": "\nSELECT user_id,\n       COUNT(CASE WHEN event_type = 'free' THEN 1 END) AS free_events,\n       COUNT(CASE WHEN event_type = 'paid' THEN 1 END) AS paid_events\nFROM events\nGROUP BY user_id\nHAVING COUNT(CASE WHEN event_type = 'free' THEN 1 END) > 0\n   AND COUNT(CASE WHEN event_type = 'paid' THEN 1 END) > 0\nORDER BY user_id;\n", "explanation": "\n<p>Conditional aggregation with <code>COUNT(CASE WHEN ...)</code> counts matching rows without\npivoting to a subquery. The <code>HAVING</code> clause filters groups where both counts are\npositive — users who touched both tiers. This is far more readable than two separate subqueries\njoined back together.</p>\n", "hints": ["Use COUNT(CASE WHEN event_type = 'free' THEN 1 END) to count free events per user.", "HAVING filters after GROUP BY — use it to keep only users where both counts > 0.", "You can reuse the same conditional count expression in both SELECT and HAVING."], "order_matters": false}, {"id": "m28", "title": "Category Revenue Share", "difficulty": "Medium", "category": "Aggregation", "companies": ["Walmart", "Target", "Costco"], "tsql": true, "description": "\n<p>Finance at <strong>RetailCore</strong> wants to see what percentage of total company revenue\neach product category contributes this quarter.</p>\n<p><strong>Return columns:</strong> <code>category</code>, <code>category_revenue</code>,\n<code>pct_of_total</code> (rounded to 2 decimal places) — ordered by category_revenue descending.</p>\n", "schema": "\nCREATE TABLE sales (\n    sale_id    INT PRIMARY KEY,\n    category   VARCHAR(50) NOT NULL,\n    revenue    DECIMAL(10,2) NOT NULL,\n    sale_date  DATE NOT NULL\n);\nINSERT INTO sales VALUES\n (1,  'Electronics', 4200.00, '2025-01-05'),\n (2,  'Electronics', 3100.00, '2025-01-12'),\n (3,  'Clothing',    1800.00, '2025-01-08'),\n (4,  'Clothing',    2200.00, '2025-01-15'),\n (5,  'Home',        1500.00, '2025-01-10'),\n (6,  'Home',         900.00, '2025-01-18'),\n (7,  'Sports',      1100.00, '2025-01-07'),\n (8,  'Sports',       700.00, '2025-01-20'),\n (9,  'Beauty',       600.00, '2025-01-09'),\n (10, 'Beauty',       400.00, '2025-01-22');\n", "solution": "\nSELECT category,\n       SUM(revenue) AS category_revenue,\n       ROUND(SUM(revenue) * 100.0 / SUM(SUM(revenue)) OVER (), 2) AS pct_of_total\nFROM sales\nGROUP BY category\nORDER BY category_revenue DESC;\n", "explanation": "\n<p><code>SUM(SUM(revenue)) OVER ()</code> is the window-function idiom for \"grand total over\ngrouped results\". The outer <code>SUM</code> is the window function; the inner <code>SUM(revenue)</code>\nis the per-group aggregate already computed by GROUP BY. Without a window function, you'd need a\nself-join or scalar subquery — both slower and harder to read.</p>\n", "hints": ["GROUP BY category first, then divide each group's SUM by the grand total.", "SUM(SUM(revenue)) OVER () gives the grand total across all groups in one pass.", "Multiply by 100.0 before dividing to force decimal arithmetic."], "order_matters": false}, {"id": "m29", "title": "Transaction Status Pivot", "difficulty": "Medium", "category": "Aggregation", "companies": ["Stripe", "PayPal", "Adyen"], "tsql": true, "description": "\n<p>The payments team at <strong>ClearPay</strong> wants a per-merchant summary showing how many\ntransactions ended in each status, plus the failure rate percentage.</p>\n<p><strong>Return columns:</strong> <code>merchant_id</code>, <code>success_count</code>,\n<code>failed_count</code>, <code>pending_count</code>, <code>failure_rate_pct</code>\n(rounded to 2 dp) — ordered by failure_rate_pct descending.</p>\n", "schema": "\nCREATE TABLE transactions (\n    txn_id      INT PRIMARY KEY,\n    merchant_id INT NOT NULL,\n    status      VARCHAR(20) NOT NULL,  -- 'success', 'failed', 'pending'\n    amount      DECIMAL(10,2) NOT NULL,\n    txn_date    DATE NOT NULL\n);\nINSERT INTO transactions VALUES\n (1,  10, 'success', 120.00, '2025-01-03'),\n (2,  10, 'success',  85.00, '2025-01-04'),\n (3,  10, 'failed',   60.00, '2025-01-04'),\n (4,  10, 'pending',  45.00, '2025-01-05'),\n (5,  20, 'success', 200.00, '2025-01-03'),\n (6,  20, 'failed',  150.00, '2025-01-04'),\n (7,  20, 'failed',   90.00, '2025-01-05'),\n (8,  20, 'failed',   70.00, '2025-01-06'),\n (9,  30, 'success',  55.00, '2025-01-03'),\n (10, 30, 'success',  40.00, '2025-01-05'),\n (11, 30, 'pending',  35.00, '2025-01-06');\n", "solution": "\nSELECT merchant_id,\n       COUNT(CASE WHEN status = 'success' THEN 1 END) AS success_count,\n       COUNT(CASE WHEN status = 'failed'  THEN 1 END) AS failed_count,\n       COUNT(CASE WHEN status = 'pending' THEN 1 END) AS pending_count,\n       ROUND(COUNT(CASE WHEN status = 'failed' THEN 1 END) * 100.0 / COUNT(*), 2)\n           AS failure_rate_pct\nFROM transactions\nGROUP BY merchant_id\nORDER BY failure_rate_pct DESC;\n", "explanation": "\n<p>Conditional aggregation (<code>COUNT(CASE WHEN status = 'x' THEN 1 END)</code>) is the T-SQL\npivot pattern without the <code>PIVOT</code> operator. It's more readable and doesn't require\nknowing distinct values in advance. <code>COUNT(*)</code> in the denominator counts all rows\n(including pending), so the failure rate is failures divided by all transactions.</p>\n", "hints": ["COUNT(CASE WHEN status = 'failed' THEN 1 END) counts only failed rows.", "Divide by COUNT(*) for the total row count per merchant.", "Multiply the numerator by 100.0 before dividing to get a percentage."], "order_matters": false}, {"id": "m30", "title": "Week-over-Week Order Volume", "difficulty": "Medium", "category": "Date/Time", "companies": ["Amazon", "Instacart", "Shipt"], "tsql": true, "description": "\n<p>The ops team at <strong>QuickBasket</strong> monitors weekly order trends. For each ISO week in\nthe data, show order count, the previous week's count, and the change.</p>\n<p><strong>Return columns:</strong> <code>yr</code>, <code>wk</code>,\n<code>orders_this_week</code>, <code>orders_last_week</code>, <code>wow_change</code>\n— ordered by yr, wk ascending. Exclude the first week (no prior week to compare).</p>\n", "schema": "\nCREATE TABLE orders (\n    order_id   INT PRIMARY KEY,\n    order_date DATE NOT NULL,\n    amount     DECIMAL(10,2) NOT NULL\n);\nINSERT INTO orders VALUES\n (1,  '2025-01-06', 50.00), (2,  '2025-01-07', 80.00), (3,  '2025-01-08', 60.00),\n (4,  '2025-01-13', 90.00), (5,  '2025-01-14', 40.00), (6,  '2025-01-15', 70.00), (7, '2025-01-16', 55.00),\n (8,  '2025-01-20', 110.00),(9,  '2025-01-21', 85.00), (10, '2025-01-22', 95.00),\n (11, '2025-01-27', 45.00), (12, '2025-01-28', 60.00), (13, '2025-01-29', 75.00), (14, '2025-01-30', 88.00), (15, '2025-01-31', 50.00);\n", "solution": "\nWITH weekly AS (\n    SELECT DATEPART(year, order_date) AS yr,\n           DATEPART(week, order_date) AS wk,\n           COUNT(*) AS orders_this_week\n    FROM orders\n    GROUP BY DATEPART(year, order_date), DATEPART(week, order_date)\n),\nwith_lag AS (\n    SELECT yr, wk, orders_this_week,\n           LAG(orders_this_week) OVER (ORDER BY yr, wk) AS orders_last_week\n    FROM weekly\n)\nSELECT yr, wk, orders_this_week, orders_last_week,\n       orders_this_week - orders_last_week AS wow_change\nFROM with_lag\nWHERE orders_last_week IS NOT NULL\nORDER BY yr, wk;\n", "explanation": "\n<p>Aggregate by week first in a CTE, then apply <code>LAG()</code> in a second CTE to look back\none row. The <code>WHERE orders_last_week IS NOT NULL</code> drops the first week which has nothing\nto compare against. This two-CTE pattern (aggregate then window) is cleaner than trying to nest\nwindow functions inside aggregations.</p>\n", "hints": ["GROUP BY DATEPART(year, ...), DATEPART(week, ...) to get weekly buckets.", "LAG(orders_this_week) OVER (ORDER BY yr, wk) gives the previous week's count.", "Filter WHERE orders_last_week IS NOT NULL to exclude the first week."], "order_matters": true}, {"id": "m31", "title": "Days Between Consecutive Orders", "difficulty": "Medium", "category": "Date/Time", "companies": ["Shopify", "BigCommerce", "WooCommerce"], "tsql": true, "description": "\n<p>The retention team at <strong>OrderFlow</strong> wants to understand customer purchase cadence.\nFor each order (excluding the first per customer), show how many days since that customer's\nprevious order.</p>\n<p><strong>Return columns:</strong> <code>customer_id</code>, <code>order_date</code>,\n<code>prev_order_date</code>, <code>days_since_last_order</code> — ordered by customer_id,\norder_date.</p>\n", "schema": "\nCREATE TABLE orders (\n    order_id    INT PRIMARY KEY,\n    customer_id INT NOT NULL,\n    order_date  DATE NOT NULL,\n    amount      DECIMAL(10,2) NOT NULL\n);\nINSERT INTO orders VALUES\n (1,  1, '2025-01-05', 80.00),\n (2,  1, '2025-01-18', 120.00),\n (3,  1, '2025-02-10', 95.00),\n (4,  2, '2025-01-09', 45.00),\n (5,  2, '2025-01-22', 60.00),\n (6,  3, '2025-01-15', 200.00),\n (7,  3, '2025-02-02', 175.00),\n (8,  3, '2025-02-20', 310.00),\n (9,  4, '2025-01-28', 55.00);\n", "solution": "\nWITH ordered AS (\n    SELECT customer_id,\n           order_date,\n           LAG(order_date) OVER (PARTITION BY customer_id ORDER BY order_date) AS prev_order_date\n    FROM orders\n)\nSELECT customer_id,\n       order_date,\n       prev_order_date,\n       DATEDIFF(day, prev_order_date, order_date) AS days_since_last_order\nFROM ordered\nWHERE prev_order_date IS NOT NULL\nORDER BY customer_id, order_date;\n", "explanation": "\n<p><code>LAG(order_date) OVER (PARTITION BY customer_id ORDER BY order_date)</code> retrieves each\ncustomer's previous order date. <code>DATEDIFF(day, prev, curr)</code> then gives the gap in days.\nFiltering <code>WHERE prev_order_date IS NOT NULL</code> drops each customer's first order since\nthere is nothing to compare it against.</p>\n", "hints": ["LAG(order_date) OVER (PARTITION BY customer_id ORDER BY order_date) gives the previous order date.", "DATEDIFF(day, prev_order_date, order_date) computes the gap.", "Filter out NULLs — each customer's first order has no previous order."], "order_matters": false}, {"id": "m32", "title": "Orders Placed in the Last 30 Days", "difficulty": "Medium", "category": "Date/Time", "companies": ["DoorDash", "Uber Eats", "Postmates"], "tsql": true, "description": "\n<p>The growth team at <strong>NomNom</strong> wants to see all orders placed within the last 30\ndays relative to <code>2025-03-01</code> (today in this scenario), along with customer names.</p>\n<p><strong>Return columns:</strong> <code>order_id</code>, <code>customer_name</code>,\n<code>order_date</code>, <code>amount</code> — ordered by order_date descending.</p>\n", "schema": "\nCREATE TABLE customers (\n    customer_id INT PRIMARY KEY,\n    name        VARCHAR(100) NOT NULL\n);\nCREATE TABLE orders (\n    order_id    INT PRIMARY KEY,\n    customer_id INT NOT NULL,\n    order_date  DATE NOT NULL,\n    amount      DECIMAL(10,2) NOT NULL\n);\nINSERT INTO customers VALUES (1,'Rosa Linden'),(2,'Max Okada'),(3,'Ines Farah'),(4,'Coby Mitchell');\nINSERT INTO orders VALUES\n (1, 1, '2025-01-15',  89.00),\n (2, 2, '2025-01-28', 134.00),\n (3, 1, '2025-02-03',  55.00),\n (4, 3, '2025-02-10', 210.00),\n (5, 4, '2025-02-14',  77.00),\n (6, 2, '2025-02-18',  92.00),\n (7, 1, '2025-02-22', 145.00),\n (8, 3, '2025-02-27',  38.00),\n (9, 4, '2025-03-01',  60.00);\n", "solution": "\nSELECT o.order_id,\n       c.name AS customer_name,\n       o.order_date,\n       o.amount\nFROM orders o\nJOIN customers c ON c.customer_id = o.customer_id\nWHERE o.order_date >= DATEADD(day, -30, CAST('2025-03-01' AS DATE))\nORDER BY o.order_date DESC;\n", "explanation": "\n<p><code>DATEADD(day, -30, CAST('2025-03-01' AS DATE))</code> computes 30 days before the\nreference date. In production you would use <code>GETDATE()</code> or <code>GETUTCDATE()</code>\ninstead of a hard-coded date. Using <code>&gt;=</code> rather than <code>&gt;</code> includes\norders placed exactly 30 days ago — whether to include the boundary is a real product question\nto clarify with the interviewer.</p>\n", "hints": ["DATEADD(day, -30, '2025-03-01') gives the cutoff date.", "Use >= to include orders placed exactly 30 days before the reference date.", "In production replace the hard-coded date with GETDATE()."], "order_matters": false}, {"id": "m33", "title": "Customer Age at First Purchase", "difficulty": "Medium", "category": "Date/Time", "companies": ["Spotify", "Netflix", "Hulu"], "tsql": true, "description": "\n<p>The data science team at <strong>Streamly</strong> wants to build an age-at-acquisition\nfeature. For each customer who has placed at least one order, return their age (in years) at\nthe date of their first purchase.</p>\n<p><strong>Return columns:</strong> <code>name</code>, <code>birth_date</code>,\n<code>first_purchase_date</code>, <code>age_at_first_purchase</code> — ordered by\nage_at_first_purchase ascending.</p>\n", "schema": "\nCREATE TABLE customers (\n    customer_id INT PRIMARY KEY,\n    name        VARCHAR(100) NOT NULL,\n    birth_date  DATE NOT NULL\n);\nCREATE TABLE orders (\n    order_id    INT PRIMARY KEY,\n    customer_id INT NOT NULL,\n    order_date  DATE NOT NULL\n);\nINSERT INTO customers VALUES\n (1, 'Liam Torres',    '1998-06-14'),\n (2, 'Ava Okafor',     '1985-11-30'),\n (3, 'Noah Williams',  '2000-03-22'),\n (4, 'Emma Suzuki',    '1992-08-05'),\n (5, 'Oliver Reyes',   '1978-01-17');\nINSERT INTO orders VALUES\n (1, 1, '2024-07-10'),\n (2, 1, '2024-09-15'),\n (3, 2, '2024-01-05'),\n (4, 3, '2024-04-20'),\n (5, 4, '2024-03-01'),\n (6, 4, '2024-11-11'),\n (7, 5, '2024-06-30');\n", "solution": "\nSELECT c.name,\n       c.birth_date,\n       MIN(o.order_date) AS first_purchase_date,\n       DATEDIFF(year, c.birth_date, MIN(o.order_date)) AS age_at_first_purchase\nFROM customers c\nJOIN orders o ON o.customer_id = c.customer_id\nGROUP BY c.customer_id, c.name, c.birth_date\nORDER BY age_at_first_purchase;\n", "explanation": "\n<p><code>MIN(o.order_date)</code> inside the aggregate gives the first purchase date per customer.\n<code>DATEDIFF(year, birth_date, first_purchase_date)</code> computes whole years elapsed — note\nthis counts year-boundary crossings, not whether the birthday has occurred yet in that year.\nFor precise age use <code>DATEDIFF(year, ...)</code> minus a correction for whether the birthday\nhas passed.</p>\n", "hints": ["MIN(order_date) per customer gives the first purchase date.", "DATEDIFF(year, birth_date, first_purchase_date) gives approximate age in years.", "You must GROUP BY all non-aggregated customer columns."], "order_matters": false}, {"id": "m34", "title": "Most Recent Order per Customer", "difficulty": "Medium", "category": "Deduplication", "companies": ["Amazon", "Walmart", "Target"], "tsql": true, "description": "\n<p>Customer success at <strong>CartCo</strong> wants the most recent order for each customer —\none row per customer, keeping the order with the latest <code>order_date</code>. If two orders\nshare the same date, keep the one with the higher <code>order_id</code>.</p>\n<p><strong>Return columns:</strong> <code>customer_id</code>, <code>order_id</code>,\n<code>order_date</code>, <code>amount</code> — ordered by order_date descending.</p>\n", "schema": "\nCREATE TABLE orders (\n    order_id    INT PRIMARY KEY,\n    customer_id INT NOT NULL,\n    order_date  DATE NOT NULL,\n    amount      DECIMAL(10,2) NOT NULL\n);\nINSERT INTO orders VALUES\n (1,  1, '2025-01-10', 120.00),\n (2,  1, '2025-02-14',  88.50),\n (3,  1, '2025-02-14', 200.00),\n (4,  2, '2025-01-22',  45.00),\n (5,  2, '2025-02-05',  60.00),\n (6,  3, '2025-01-30', 310.00),\n (7,  4, '2025-02-18',  75.00),\n (8,  4, '2025-01-05',  90.00);\n", "solution": "\nWITH ranked AS (\n    SELECT customer_id, order_id, order_date, amount,\n           ROW_NUMBER() OVER (\n               PARTITION BY customer_id\n               ORDER BY order_date DESC, order_id DESC\n           ) AS rn\n    FROM orders\n)\nSELECT customer_id, order_id, order_date, amount\nFROM ranked\nWHERE rn = 1\nORDER BY order_date DESC;\n", "explanation": "\n<p><code>ROW_NUMBER() OVER (PARTITION BY customer_id ORDER BY order_date DESC, order_id DESC)</code>\nassigns rank 1 to the most recent order per customer, breaking ties by the higher order_id.\nFiltering <code>WHERE rn = 1</code> keeps exactly one row per customer. This is the canonical\n\"latest record per entity\" pattern in DE work — memorise it.</p>\n", "hints": ["PARTITION BY customer_id restarts the numbering per customer.", "ORDER BY order_date DESC, order_id DESC puts the latest (and highest ID on ties) first.", "WHERE rn = 1 keeps exactly one row per customer."], "order_matters": false}, {"id": "m35", "title": "Deduplicate Users by Email", "difficulty": "Medium", "category": "Deduplication", "companies": ["HubSpot", "Salesforce", "Mailchimp"], "tsql": true, "description": "\n<p>A data import at <strong>LeadGen Co</strong> created duplicate user accounts sharing the same\nemail address. Keep the earliest-created account per email and return only those canonical records.</p>\n<p><strong>Return columns:</strong> <code>user_id</code>, <code>email</code>,\n<code>created_at</code> — ordered by email ascending.</p>\n", "schema": "\nCREATE TABLE users (\n    user_id    INT PRIMARY KEY,\n    email      VARCHAR(100) NOT NULL,\n    name       VARCHAR(100) NOT NULL,\n    created_at DATE NOT NULL\n);\nINSERT INTO users VALUES\n (1,  'alice@acme.com',  'Alice A', '2024-01-10'),\n (2,  'bob@acme.com',    'Bob B',   '2024-02-05'),\n (3,  'alice@acme.com',  'Alice Z', '2024-03-15'),\n (4,  'carol@acme.com',  'Carol C', '2024-01-22'),\n (5,  'bob@acme.com',    'Bob Q',   '2024-04-01'),\n (6,  'dave@acme.com',   'Dave D',  '2024-02-28'),\n (7,  'alice@acme.com',  'Alice M', '2024-05-09');\n", "solution": "\nWITH ranked AS (\n    SELECT user_id, email, created_at,\n           ROW_NUMBER() OVER (PARTITION BY email ORDER BY created_at, user_id) AS rn\n    FROM users\n)\nSELECT user_id, email, created_at\nFROM ranked\nWHERE rn = 1\nORDER BY email;\n", "explanation": "\n<p><code>PARTITION BY email ORDER BY created_at, user_id</code> numbers accounts within each\nemail group, earliest first (using user_id as tiebreaker). <code>WHERE rn = 1</code> keeps only\nthe canonical account. The tiebreaker on <code>user_id</code> makes the deduplication\ndeterministic when two accounts share the same <code>created_at</code>.</p>\n", "hints": ["PARTITION BY email groups accounts by email address.", "ORDER BY created_at ASC (oldest first) so rn=1 is the earliest account.", "Add user_id as a tiebreaker so the result is deterministic."], "order_matters": false}, {"id": "m36", "title": "Current SCD Type 2 Record", "difficulty": "Medium", "category": "Deduplication", "companies": ["Snowflake", "Databricks", "dbt"], "tsql": true, "description": "\n<p><strong>DataVault Co</strong> stores customer plan history using Slowly Changing Dimension\nType 2 — each change creates a new row with a <code>valid_from</code> date, while the current\nrecord has <code>valid_to = NULL</code>.</p>\n<p>Return each customer's current active record.</p>\n<p><strong>Return columns:</strong> <code>customer_id</code>, <code>name</code>,\n<code>plan_tier</code>, <code>valid_from</code> — ordered by customer_id.</p>\n", "schema": "\nCREATE TABLE customer_history (\n    history_id  INT PRIMARY KEY,\n    customer_id INT NOT NULL,\n    name        VARCHAR(100) NOT NULL,\n    plan_tier   VARCHAR(50) NOT NULL,\n    valid_from  DATE NOT NULL,\n    valid_to    DATE\n);\nINSERT INTO customer_history VALUES\n (1, 1, 'Alice',  'free',       '2024-01-01', '2024-06-01'),\n (2, 1, 'Alice',  'standard',   '2024-06-01', '2024-11-01'),\n (3, 1, 'Alice',  'premium',    '2024-11-01', NULL),\n (4, 2, 'Bob',    'free',       '2024-03-01', '2024-09-01'),\n (5, 2, 'Bob',    'standard',   '2024-09-01', NULL),\n (6, 3, 'Carol',  'premium',    '2024-02-01', NULL);\n", "solution": "\nSELECT customer_id, name, plan_tier, valid_from\nFROM customer_history\nWHERE valid_to IS NULL\nORDER BY customer_id;\n", "explanation": "\n<p>In a well-formed SCD2 table, exactly one row per entity has <code>valid_to IS NULL</code> —\nthe currently active record. This simple filter is O(n) and index-friendly. An alternative is\n<code>ROW_NUMBER() OVER (PARTITION BY customer_id ORDER BY valid_from DESC) = 1</code>, which\nhandles tables where <code>valid_to</code> may never be NULL but is useful when the SCD2 is\n\"closed\" (all rows have end dates) and you want the last one.</p>\n", "hints": ["In SCD2, the current record is the one with valid_to IS NULL.", "This is a simple WHERE filter — no window function needed if the table is well-formed.", "Alternative: ROW_NUMBER() OVER (PARTITION BY customer_id ORDER BY valid_from DESC) = 1."], "order_matters": false}, {"id": "m37", "title": "Current Login Streak per User", "difficulty": "Medium", "category": "Gaps & Islands", "companies": ["Duolingo", "Strava", "Headspace"], "tsql": true, "description": "\n<p><strong>LearnLoop</strong> awards streak badges. For each user, compute their <em>current</em>\nlogin streak — the number of consecutive calendar days ending on their most recent login date.</p>\n<p><strong>Return columns:</strong> <code>user_id</code>, <code>streak_start</code>,\n<code>streak_end</code>, <code>current_streak</code> — ordered by current_streak descending.</p>\n", "schema": "\nCREATE TABLE logins (\n    login_id   INT PRIMARY KEY,\n    user_id    INT NOT NULL,\n    login_date DATE NOT NULL\n);\nINSERT INTO logins VALUES\n (1,  1, '2025-01-10'), (2,  1, '2025-01-11'), (3,  1, '2025-01-12'),\n (4,  1, '2025-01-13'), (5,  1, '2025-01-14'),\n (6,  2, '2025-01-08'), (7,  2, '2025-01-09'),\n (8,  2, '2025-01-12'), (9,  2, '2025-01-13'), (10, 2, '2025-01-14'),\n (11, 3, '2025-01-01'), (12, 3, '2025-01-02'), (13, 3, '2025-01-14');\n", "solution": "\nWITH daily AS (\n    SELECT DISTINCT user_id, login_date FROM logins\n),\nanchored AS (\n    SELECT user_id, login_date,\n           DATEDIFF(day, '2000-01-01', login_date)\n               - ROW_NUMBER() OVER (PARTITION BY user_id ORDER BY login_date) AS grp\n    FROM daily\n),\nislands AS (\n    SELECT user_id, grp,\n           MIN(login_date) AS streak_start,\n           MAX(login_date) AS streak_end,\n           COUNT(*)        AS streak_len\n    FROM anchored\n    GROUP BY user_id, grp\n),\nlast_login AS (\n    SELECT user_id, MAX(login_date) AS last_date FROM daily GROUP BY user_id\n)\nSELECT i.user_id, i.streak_start, i.streak_end, i.streak_len AS current_streak\nFROM islands i\nJOIN last_login l ON l.user_id = i.user_id AND l.last_date = i.streak_end\nORDER BY current_streak DESC;\n", "explanation": "\n<p>The gaps-and-islands trick: subtracting a sequential row number from the date (as a day count)\ngives the same constant for every date in a consecutive run — that constant becomes the group key.\nOnly the island whose <code>streak_end</code> equals the user's most recent login date is the\n<em>current</em> streak. User 3 has two islands; only the second one (ending 2025-01-14) is\nreturned.</p>\n", "hints": ["Deduplicate logins to one row per user per date first.", "date_as_number - ROW_NUMBER() is constant for consecutive dates — use it as a group key.", "Join back to last login date to keep only the island touching today."], "order_matters": false}, {"id": "m38", "title": "Missing Sales Dates", "difficulty": "Medium", "category": "Gaps & Islands", "companies": ["Walmart", "Target", "Kroger"], "tsql": true, "description": "\n<p>The data quality team at <strong>RetailCore</strong> needs to find every calendar date between\nthe first and last sale date that has <em>no</em> sales record — these are gaps in the pipeline\nthat need investigation.</p>\n<p><strong>Return column:</strong> <code>missing_date</code> — ordered ascending.</p>\n", "schema": "\nCREATE TABLE daily_sales (\n    sale_date DATE PRIMARY KEY,\n    revenue   DECIMAL(10,2) NOT NULL\n);\nINSERT INTO daily_sales VALUES\n ('2025-01-01', 1200.00),\n ('2025-01-02',  980.00),\n ('2025-01-04', 1500.00),\n ('2025-01-05', 1100.00),\n ('2025-01-08',  870.00),\n ('2025-01-09', 2100.00),\n ('2025-01-10',  960.00);\n", "solution": "\nWITH bounds AS (\n    SELECT MIN(sale_date) AS start_date, MAX(sale_date) AS end_date FROM daily_sales\n),\nspine AS (\n    SELECT DATEADD(day, n.number, b.start_date) AS dt\n    FROM bounds b\n    CROSS JOIN (\n        SELECT TOP 1000 ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) - 1 AS number\n        FROM sys.all_objects\n    ) n\n    WHERE DATEADD(day, n.number, b.start_date) <= b.end_date\n)\nSELECT spine.dt AS missing_date\nFROM spine\nLEFT JOIN daily_sales ds ON ds.sale_date = spine.dt\nWHERE ds.sale_date IS NULL\nORDER BY missing_date;\n", "explanation": "\n<p>Generate a complete date spine between the first and last sale date using a tally-table trick:\n<code>ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) - 1</code> creates sequential integers 0, 1, 2 …,\nand <code>DATEADD(day, n, start)</code> converts each integer to a date. LEFT JOIN to the actual\nsales table and filter <code>WHERE sales.date IS NULL</code> to surface the missing dates.</p>\n", "hints": ["Generate a date spine using ROW_NUMBER() + DATEADD to cover every calendar day.", "LEFT JOIN the spine to actual sales; WHERE sale_date IS NULL reveals the gaps.", "sys.all_objects typically has thousands of rows — enough for any reasonable date range."], "order_matters": true}, {"id": "m39", "title": "7-Day Retention Rate by Signup Date", "difficulty": "Medium", "category": "Retention & Cohorts", "companies": ["Meta", "TikTok", "Snap"], "tsql": true, "description": "\n<p>Product at <strong>Chirper</strong> tracks Day-7 retention: the fraction of users who return\nto the app within 7 days of signing up (days 1–7 inclusive).</p>\n<p>For each signup date, return the cohort size and the Day-7 retention rate.</p>\n<p><strong>Return columns:</strong> <code>signup_date</code>, <code>cohort_size</code>,\n<code>retained_d7</code>, <code>retention_pct</code> (rounded to 2 dp) — ordered by signup_date.</p>\n", "schema": "\nCREATE TABLE users (\n    user_id    INT PRIMARY KEY,\n    signup_date DATE NOT NULL\n);\nCREATE TABLE events (\n    event_id   INT PRIMARY KEY,\n    user_id    INT NOT NULL,\n    event_date DATE NOT NULL\n);\nINSERT INTO users VALUES\n (1,'2025-01-01'),(2,'2025-01-01'),(3,'2025-01-01'),(4,'2025-01-01'),\n (5,'2025-01-02'),(6,'2025-01-02'),(7,'2025-01-02'),\n (8,'2025-01-03'),(9,'2025-01-03'),(10,'2025-01-03');\nINSERT INTO events VALUES\n (1,1,'2025-01-04'),(2,2,'2025-01-07'),(3,4,'2025-01-06'),\n (4,5,'2025-01-05'),(5,6,'2025-01-09'),\n (6,8,'2025-01-05'),(7,9,'2025-01-10'),(8,10,'2025-01-03');\n", "solution": "\nWITH cohort AS (\n    SELECT u.user_id, u.signup_date,\n           MAX(CASE WHEN DATEDIFF(day, u.signup_date, e.event_date) BETWEEN 1 AND 7 THEN 1 ELSE 0 END)\n               AS retained_d7\n    FROM users u\n    LEFT JOIN events e ON e.user_id = u.user_id\n    GROUP BY u.user_id, u.signup_date\n)\nSELECT signup_date,\n       COUNT(*) AS cohort_size,\n       SUM(retained_d7) AS retained_d7,\n       ROUND(SUM(retained_d7) * 100.0 / COUNT(*), 2) AS retention_pct\nFROM cohort\nGROUP BY signup_date\nORDER BY signup_date;\n", "explanation": "\n<p>The inner CTE computes a per-user binary flag: did this user return on days 1–7 after signup?\n<code>MAX(CASE WHEN ...)</code> collapses multiple events per user to a single 1 or 0.\nLEFT JOIN is critical — users who never returned must still appear in the cohort (with a 0),\notherwise they would be silently excluded and the rate would be artificially inflated.</p>\n", "hints": ["LEFT JOIN events to keep users who never returned.", "DATEDIFF(day, signup_date, event_date) BETWEEN 1 AND 7 identifies Day-7 returners.", "MAX(CASE WHEN ...) collapses multiple events per user to a 0/1 flag."], "order_matters": false}, {"id": "m40", "title": "Weekly Active Users", "difficulty": "Medium", "category": "Retention & Cohorts", "companies": ["Meta", "Twitter", "LinkedIn"], "tsql": true, "description": "\n<p>Product Analytics at <strong>Pulse</strong> tracks Weekly Active Users (WAU) — the number of\ndistinct users with at least one event in each calendar week.</p>\n<p><strong>Return columns:</strong> <code>yr</code>, <code>wk</code>, <code>wau</code> — ordered\nby yr, wk ascending.</p>\n", "schema": "\nCREATE TABLE events (\n    event_id   INT PRIMARY KEY,\n    user_id    INT NOT NULL,\n    event_date DATE NOT NULL\n);\nINSERT INTO events VALUES\n (1,101,'2025-01-06'),(2,102,'2025-01-07'),(3,101,'2025-01-08'),(4,103,'2025-01-09'),\n (5,101,'2025-01-13'),(6,104,'2025-01-14'),(7,102,'2025-01-15'),(8,103,'2025-01-16'),(9,105,'2025-01-16'),\n (10,101,'2025-01-20'),(11,106,'2025-01-21'),(12,104,'2025-01-22'),\n (13,102,'2025-01-27'),(14,101,'2025-01-28'),(15,107,'2025-01-29'),(16,105,'2025-01-30');\n", "solution": "\nSELECT DATEPART(year, event_date) AS yr,\n       DATEPART(week, event_date) AS wk,\n       COUNT(DISTINCT user_id)    AS wau\nFROM events\nGROUP BY DATEPART(year, event_date), DATEPART(week, event_date)\nORDER BY yr, wk;\n", "explanation": "\n<p><code>COUNT(DISTINCT user_id)</code> counts unique users per week regardless of how many events\nthey triggered. <code>DATEPART(week, date)</code> extracts the ISO-like week number from the date.\nThis is the foundational WAU query — in production it is often extended with a rolling 7-day window\nusing window functions to avoid week-boundary artefacts.</p>\n", "hints": ["DATEPART(week, event_date) extracts the week number.", "COUNT(DISTINCT user_id) counts each user once per week.", "GROUP BY both year and week to handle multi-year data correctly."], "order_matters": true}, {"id": "m41", "title": "Employees Without a Manager", "difficulty": "Medium", "category": "Filtering & NULL", "companies": ["Oracle", "SAP", "Workday"], "tsql": true, "description": "\n<p>The HR system at <strong>Pinnacle Corp</strong> stores <code>manager_id = NULL</code> for\nemployees at the top of the hierarchy. Return all employees who report to no one.</p>\n<p><strong>Return columns:</strong> <code>emp_id</code>, <code>name</code>,\n<code>department</code>, <code>hire_date</code> — ordered by name.</p>\n", "schema": "\nCREATE TABLE employees (\n    emp_id     INT PRIMARY KEY,\n    name       VARCHAR(100) NOT NULL,\n    department VARCHAR(100) NOT NULL,\n    manager_id INT,\n    hire_date  DATE NOT NULL\n);\nINSERT INTO employees VALUES\n (1, 'Sarah Lin',    'Executive',   NULL, '2018-03-01'),\n (2, 'Tom Reyes',    'Engineering', 1,    '2019-07-15'),\n (3, 'Nadia Patel',  'Engineering', 2,    '2020-01-10'),\n (4, 'Chloe Ortega', 'Sales',       1,    '2019-11-20'),\n (5, 'Marcus Webb',  'Sales',       4,    '2021-05-03'),\n (6, 'Jin Park',     'Finance',     NULL, '2018-09-01'),\n (7, 'Rosa Lima',    'Finance',     6,    '2022-02-14');\n", "solution": "\nSELECT emp_id, name, department, hire_date\nFROM employees\nWHERE manager_id IS NULL\nORDER BY name;\n", "explanation": "\n<p><code>IS NULL</code> is the correct predicate — <code>= NULL</code> always evaluates to\nUNKNOWN in SQL and returns no rows. Two employees have no manager here: Sarah Lin (CEO) and Jin\nPark (CFO). In interviews, always say \"IS NULL\" explicitly and explain why <code>= NULL</code>\nnever works.</p>\n", "hints": ["Use IS NULL — not = NULL. = NULL is always UNKNOWN in SQL.", "NULL represents the absence of a value, not the value NULL itself."], "order_matters": false}, {"id": "m42", "title": "First Non-NULL Contact Method", "difficulty": "Medium", "category": "Filtering & NULL", "companies": ["Salesforce", "HubSpot", "Zendesk"], "tsql": true, "description": "\n<p>The CRM at <strong>ConnectCo</strong> stores multiple contact fields per customer. Return each\ncustomer's preferred contact method — the first non-NULL value across mobile, home phone, work\nphone, then email — and label which field was used.</p>\n<p><strong>Return columns:</strong> <code>customer_id</code>, <code>name</code>,\n<code>preferred_contact</code>, <code>contact_type</code> — ordered by name.</p>\n", "schema": "\nCREATE TABLE customers (\n    customer_id  INT PRIMARY KEY,\n    name         VARCHAR(100) NOT NULL,\n    mobile_phone VARCHAR(20),\n    home_phone   VARCHAR(20),\n    work_phone   VARCHAR(20),\n    email        VARCHAR(100)\n);\nINSERT INTO customers VALUES\n (1, 'Alice Brown',  '555-0101', NULL,       NULL,       'alice@co.com'),\n (2, 'Bob Chen',     NULL,       '555-0202', NULL,       'bob@co.com'),\n (3, 'Clara Davis',  NULL,       NULL,       '555-0303', 'clara@co.com'),\n (4, 'Daniel Evans', NULL,       NULL,       NULL,       'daniel@co.com'),\n (5, 'Elena Flores', '555-0505', '555-0506', '555-0507', 'elena@co.com');\n", "solution": "\nSELECT customer_id, name,\n       COALESCE(mobile_phone, home_phone, work_phone, email) AS preferred_contact,\n       CASE\n           WHEN mobile_phone IS NOT NULL THEN 'mobile'\n           WHEN home_phone   IS NOT NULL THEN 'home'\n           WHEN work_phone   IS NOT NULL THEN 'work'\n           ELSE 'email'\n       END AS contact_type\nFROM customers\nORDER BY name;\n", "explanation": "\n<p><code>COALESCE(a, b, c, d)</code> returns the first non-NULL argument — it short-circuits,\nso it is also efficient. The parallel <code>CASE</code> expression labels which source was used.\nYou cannot use <code>COALESCE</code> alone to get the label because it only returns the value,\nnot which branch fired. This pattern (COALESCE for the value + CASE for the label) is common in\ndata cleaning pipelines.</p>\n", "hints": ["COALESCE(a, b, c, d) returns the first non-NULL — ordered by priority.", "Use a parallel CASE expression to label which field was chosen."], "order_matters": false}, {"id": "m43", "title": "Orders With Incomplete Shipping Address", "difficulty": "Medium", "category": "Filtering & NULL", "companies": ["FedEx", "UPS", "USPS"], "tsql": true, "description": "\n<p>The fulfilment team at <strong>SwiftShip</strong> cannot process orders that are missing one or\nmore address fields. Find all such orders and show the missing fields replaced by\n<code>'(missing)'</code> so the ops team can see exactly what is absent.</p>\n<p><strong>Return columns:</strong> <code>order_id</code>, <code>customer_id</code>,\n<code>street</code>, <code>city</code>, <code>zip_code</code> — ordered by order_id.</p>\n", "schema": "\nCREATE TABLE orders (\n    order_id    INT PRIMARY KEY,\n    customer_id INT NOT NULL,\n    order_date  DATE NOT NULL,\n    street      VARCHAR(200),\n    city        VARCHAR(100),\n    zip_code    VARCHAR(10)\n);\nINSERT INTO orders VALUES\n (1, 1, '2025-01-05', '123 Main St',  'Austin',   '78701'),\n (2, 2, '2025-01-07', NULL,           'Denver',   '80201'),\n (3, 3, '2025-01-09', '456 Oak Ave',  NULL,       '90210'),\n (4, 4, '2025-01-10', '789 Pine Rd',  'Seattle',  NULL),\n (5, 5, '2025-01-12', NULL,           NULL,       '10001'),\n (6, 6, '2025-01-14', '321 Elm St',   'Chicago',  '60601');\n", "solution": "\nSELECT order_id,\n       customer_id,\n       ISNULL(street,   '(missing)') AS street,\n       ISNULL(city,     '(missing)') AS city,\n       ISNULL(zip_code, '(missing)') AS zip_code\nFROM orders\nWHERE street IS NULL OR city IS NULL OR zip_code IS NULL\nORDER BY order_id;\n", "explanation": "\n<p><code>WHERE street IS NULL OR city IS NULL OR zip_code IS NULL</code> catches rows where\n<em>any</em> address field is missing. <code>ISNULL(col, '(missing)')</code> replaces NULLs with\na readable placeholder in the output — useful for operational dashboards where data-entry staff\nneed to see what is blank. In T-SQL, <code>ISNULL</code> takes exactly 2 arguments;\n<code>COALESCE</code> accepts any number.</p>\n", "hints": ["Filter WHERE any address field IS NULL.", "ISNULL(col, '(missing)') replaces NULL with a label in the output."], "order_matters": false}, {"id": "m44", "title": "Orphaned Order Items", "difficulty": "Medium", "category": "Data Quality", "companies": ["Amazon", "Shopify", "Etsy"], "tsql": true, "description": "\n<p>A truncated load at <strong>CartCo</strong> left <code>order_items</code> rows referencing\norders that no longer exist in the <code>orders</code> table. Find all orphaned items.</p>\n<p><strong>Return columns:</strong> <code>item_id</code>, <code>order_id</code>,\n<code>product_id</code>, <code>quantity</code> — ordered by item_id.</p>\n", "schema": "\nCREATE TABLE orders (\n    order_id   INT PRIMARY KEY,\n    order_date DATE NOT NULL\n);\nCREATE TABLE order_items (\n    item_id    INT PRIMARY KEY,\n    order_id   INT NOT NULL,\n    product_id INT NOT NULL,\n    quantity   INT NOT NULL\n);\nINSERT INTO orders VALUES (1001,'2025-01-05'),(1002,'2025-01-06'),(1003,'2025-01-07');\nINSERT INTO order_items VALUES\n (1, 1001, 101, 2),\n (2, 1001, 102, 1),\n (3, 1002, 103, 3),\n (4, 1004, 104, 1),\n (5, 1005, 101, 2),\n (6, 1003, 102, 1);\n", "solution": "\nSELECT oi.item_id, oi.order_id, oi.product_id, oi.quantity\nFROM order_items oi\nLEFT JOIN orders o ON o.order_id = oi.order_id\nWHERE o.order_id IS NULL\nORDER BY oi.item_id;\n", "explanation": "\n<p>A LEFT JOIN from <code>order_items</code> to <code>orders</code> keeps every item row; when\nno matching order exists, all order columns are NULL. <code>WHERE o.order_id IS NULL</code>\nisolates the orphans. This data quality check should run after every load that truncates the\norders table.</p>\n", "hints": ["LEFT JOIN order_items → orders; NULL on the order side means the reference is broken.", "Alternatively use NOT EXISTS — both are equivalent for anti-join checks."], "order_matters": false}, {"id": "m45", "title": "Accounts Sharing a Phone Number", "difficulty": "Medium", "category": "Data Quality", "companies": ["Twilio", "Vonage", "Bandwidth"], "tsql": true, "description": "\n<p>The fraud team at <strong>SafeWallet</strong> wants to flag phone numbers linked to more than\none account — a common signal for account farming.</p>\n<p><strong>Return columns:</strong> <code>phone_number</code>, <code>account_count</code>,\n<code>account_ids</code> (comma-separated list) — ordered by account_count descending.</p>\n", "schema": "\nCREATE TABLE accounts (\n    account_id   INT PRIMARY KEY,\n    name         VARCHAR(100) NOT NULL,\n    phone_number VARCHAR(20)\n);\nINSERT INTO accounts VALUES\n (1,  'Alice A',  '555-0101'),\n (2,  'Bob B',    '555-0202'),\n (3,  'Carol C',  '555-0101'),\n (4,  'Dave D',   '555-0303'),\n (5,  'Eve E',    '555-0202'),\n (6,  'Frank F',  '555-0101'),\n (7,  'Grace G',  '555-0404'),\n (8,  'Hank H',   NULL);\n", "solution": "\nSELECT phone_number,\n       COUNT(*)  AS account_count,\n       STRING_AGG(CAST(account_id AS VARCHAR), ', ')\n           WITHIN GROUP (ORDER BY account_id) AS account_ids\nFROM accounts\nWHERE phone_number IS NOT NULL\nGROUP BY phone_number\nHAVING COUNT(*) > 1\nORDER BY account_count DESC;\n", "explanation": "\n<p><code>STRING_AGG(value, separator) WITHIN GROUP (ORDER BY ...)</code> is the T-SQL aggregate\nthat concatenates values into a delimited string. The <code>WHERE phone_number IS NOT NULL</code>\nguard is essential — NULL phone numbers must not be grouped together as if they represent the same\nnumber. <code>HAVING COUNT(*) &gt; 1</code> keeps only multi-account phone numbers.</p>\n", "hints": ["GROUP BY phone_number, HAVING COUNT(*) > 1 finds shared numbers.", "STRING_AGG(CAST(account_id AS VARCHAR), ', ') WITHIN GROUP (ORDER BY account_id) builds the list.", "Filter WHERE phone_number IS NOT NULL before grouping."], "order_matters": false}, {"id": "h15", "title": "Year-over-Year Revenue by Category", "difficulty": "Hard", "category": "Window Functions", "companies": ["Amazon", "Microsoft", "Google"], "tsql": true, "description": "\n<p>Finance at <strong>RetailCore</strong> tracks yearly revenue by product category and wants to\nsee how each category grew (or shrank) versus the prior year.</p>\n<p>Return one row per category per year (only for years that have a prior year to compare),\nshowing the revenue, prior-year revenue, and the YoY growth percentage.</p>\n<p><strong>Return columns:</strong> <code>category</code>, <code>yr</code>,\n<code>annual_revenue</code>, <code>prev_year_revenue</code>, <code>yoy_growth_pct</code>\n(rounded to 2 dp) — ordered by category, yr.</p>\n", "schema": "\nCREATE TABLE product_sales (\n    sale_id   INT PRIMARY KEY,\n    category  VARCHAR(50) NOT NULL,\n    revenue   DECIMAL(10,2) NOT NULL,\n    sale_date DATE NOT NULL\n);\nINSERT INTO product_sales VALUES\n (1,'Electronics',4200.00,'2023-03-15'),(2,'Electronics',3800.00,'2023-09-20'),\n (3,'Electronics',5100.00,'2024-02-10'),(4,'Electronics',4600.00,'2024-11-05'),\n (5,'Clothing',1800.00,'2023-04-12'),(6,'Clothing',2200.00,'2023-10-08'),\n (7,'Clothing',2600.00,'2024-03-22'),(8,'Clothing',3100.00,'2024-08-17'),\n (9,'Home',1200.00,'2023-05-01'),(10,'Home',1400.00,'2023-12-15'),\n (11,'Home',1100.00,'2024-04-09'),(12,'Home',1900.00,'2024-09-30');\n", "solution": "\nWITH yearly AS (\n    SELECT category,\n           YEAR(sale_date)  AS yr,\n           SUM(revenue)     AS annual_revenue\n    FROM product_sales\n    GROUP BY category, YEAR(sale_date)\n),\nwith_lag AS (\n    SELECT category, yr, annual_revenue,\n           LAG(annual_revenue) OVER (PARTITION BY category ORDER BY yr) AS prev_year_revenue\n    FROM yearly\n)\nSELECT category, yr, annual_revenue, prev_year_revenue,\n       ROUND((annual_revenue - prev_year_revenue) * 100.0\n             / NULLIF(prev_year_revenue, 0), 2) AS yoy_growth_pct\nFROM with_lag\nWHERE prev_year_revenue IS NOT NULL\nORDER BY category, yr;\n", "explanation": "\n<p><code>LAG() OVER (PARTITION BY category ORDER BY yr)</code> pulls the previous year's revenue\nfor each category independently. <code>NULLIF(prev_year_revenue, 0)</code> prevents\ndivision-by-zero when a category had zero revenue in the prior year. The outer\n<code>WHERE prev_year_revenue IS NOT NULL</code> drops the first year per category since there\nis nothing to compare it to.</p>\n", "hints": ["Aggregate by category and year first, then apply LAG in a second CTE.", "PARTITION BY category ensures LAG looks back within the same category.", "NULLIF(prev, 0) prevents division-by-zero if prior revenue was zero."], "order_matters": false}, {"id": "h16", "title": "Top vs Bottom Spender Deciles", "difficulty": "Hard", "category": "Window Functions", "companies": ["Stripe", "PayPal", "Square"], "tsql": true, "description": "\n<p>The revenue team at <strong>ClearPay</strong> wants to quantify how much more the top-spending\ncustomers spend versus the bottom tier.</p>\n<p>Using <code>NTILE(10)</code>, bucket customers by total spend. Return a single row with:\nthe average spend of the top decile (decile 10), the average spend of the bottom decile (decile 1),\nand the ratio (top ÷ bottom), rounded to 2 decimal places.</p>\n<p><strong>Return columns:</strong> <code>avg_top_decile</code>, <code>avg_bottom_decile</code>,\n<code>ratio</code>.</p>\n", "schema": "\nCREATE TABLE orders (\n    order_id    INT PRIMARY KEY,\n    customer_id INT NOT NULL,\n    amount      DECIMAL(10,2) NOT NULL,\n    order_date  DATE NOT NULL\n);\nINSERT INTO orders VALUES\n (1,101,50.00,'2025-01-01'),(2,101,80.00,'2025-01-05'),\n (3,102,200.00,'2025-01-02'),(4,102,150.00,'2025-01-08'),\n (5,103,30.00,'2025-01-03'),\n (6,104,500.00,'2025-01-04'),(7,104,450.00,'2025-01-09'),(8,104,380.00,'2025-01-12'),\n (9,105,25.00,'2025-01-05'),\n (10,106,90.00,'2025-01-06'),\n (11,107,310.00,'2025-01-07'),\n (12,108,15.00,'2025-01-08'),\n (13,109,700.00,'2025-01-09'),(14,109,620.00,'2025-01-14'),\n (15,110,40.00,'2025-01-10'),\n (16,111,180.00,'2025-01-11'),\n (17,112,22.00,'2025-01-12'),\n (18,113,850.00,'2025-01-13'),(19,113,920.00,'2025-01-16'),\n (20,114,60.00,'2025-01-14');\n", "solution": "\nWITH customer_spend AS (\n    SELECT customer_id, SUM(amount) AS total_spent\n    FROM orders\n    GROUP BY customer_id\n),\ndeciled AS (\n    SELECT customer_id, total_spent,\n           NTILE(10) OVER (ORDER BY total_spent) AS decile\n    FROM customer_spend\n)\nSELECT ROUND(AVG(CASE WHEN decile = 10 THEN total_spent END), 2) AS avg_top_decile,\n       ROUND(AVG(CASE WHEN decile =  1 THEN total_spent END), 2) AS avg_bottom_decile,\n       ROUND(AVG(CASE WHEN decile = 10 THEN total_spent END)\n             / NULLIF(AVG(CASE WHEN decile = 1 THEN total_spent END), 0), 2) AS ratio\nFROM deciled;\n", "explanation": "\n<p>NTILE(10) partitions customers into 10 equal buckets ordered by total spend. Decile 1 = lowest\nspenders, decile 10 = highest. Conditional aggregation with AVG(CASE ...) extracts the averages\nfor each extreme. The ratio tells you the spend multiplier between the top and bottom of your\ncustomer base.</p>\n", "hints": ["Aggregate total spend per customer first, then apply NTILE(10).", "NTILE(10) with no PARTITION BY ranks across all customers.", "AVG(CASE WHEN decile = 10 THEN total_spent END) averages only decile-10 customers."], "order_matters": false}, {"id": "h17", "title": "First and Last Event per User", "difficulty": "Hard", "category": "Window Functions", "companies": ["Amplitude", "Mixpanel", "Segment"], "tsql": true, "description": "\n<p>The analytics team at <strong>EventFlow</strong> wants a one-row summary per user showing their\nvery first event type, last event type, first event timestamp, last event timestamp, and how many\ndays they were active between first and last event.</p>\n<p><strong>Return columns:</strong> <code>user_id</code>, <code>first_event</code>,\n<code>first_event_time</code>, <code>last_event</code>, <code>last_event_time</code>,\n<code>active_days</code> — ordered by active_days descending.</p>\n", "schema": "\nCREATE TABLE user_events (\n    event_id   INT PRIMARY KEY,\n    user_id    INT NOT NULL,\n    event_type VARCHAR(50) NOT NULL,\n    event_time VARCHAR(19) NOT NULL\n);\nINSERT INTO user_events VALUES\n (1, 1,'signup',   '2025-01-01 09:00:00'),\n (2, 1,'purchase', '2025-01-05 14:30:00'),\n (3, 1,'review',   '2025-01-20 11:00:00'),\n (4, 2,'signup',   '2025-01-03 08:00:00'),\n (5, 2,'purchase', '2025-01-03 18:00:00'),\n (6, 3,'signup',   '2025-01-10 10:00:00'),\n (7, 3,'view',     '2025-01-12 15:00:00'),\n (8, 3,'purchase', '2025-01-25 09:30:00'),\n (9, 3,'refund',   '2025-02-01 12:00:00');\n", "solution": "\nWITH bounds AS (\n    SELECT DISTINCT\n           user_id,\n           FIRST_VALUE(event_type) OVER (PARTITION BY user_id ORDER BY event_time)\n               AS first_event,\n           FIRST_VALUE(event_time) OVER (PARTITION BY user_id ORDER BY event_time)\n               AS first_event_time,\n           FIRST_VALUE(event_type) OVER (PARTITION BY user_id ORDER BY event_time DESC)\n               AS last_event,\n           FIRST_VALUE(event_time) OVER (PARTITION BY user_id ORDER BY event_time DESC)\n               AS last_event_time\n    FROM user_events\n)\nSELECT user_id, first_event, first_event_time, last_event, last_event_time,\n       DATEDIFF(day, CAST(first_event_time AS DATE), CAST(last_event_time AS DATE))\n           AS active_days\nFROM bounds\nORDER BY active_days DESC;\n", "explanation": "\n<p>The double-FIRST_VALUE trick: run <code>FIRST_VALUE</code> once with ascending order (gives\nthe earliest event) and once with descending order (gives the latest). <code>DISTINCT</code>\ncollapses the per-row repetition down to one row per user. Avoid <code>LAST_VALUE</code> —\nits default frame (<code>RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW</code>) stops at the\ncurrent row, not the partition end, so it never returns the actual last value unless you add\n<code>ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING</code>.</p>\n", "hints": ["Use FIRST_VALUE twice: once ORDER BY event_time ASC, once ORDER BY event_time DESC.", "DISTINCT collapses the repeated window values to one row per user.", "Avoid LAST_VALUE — its default frame stops at the current row."], "order_matters": false}, {"id": "h18", "title": "Friend-of-a-Friend Connections", "difficulty": "Hard", "category": "Joins", "companies": ["LinkedIn", "Meta", "Twitter"], "tsql": true, "description": "\n<p><strong>ConnectSphere</strong> wants to surface 2nd-degree connections — users you are not\ndirectly friends with but share a mutual friend.</p>\n<p>For each user, return every 2nd-degree connection (not already a direct friend and not the\nuser themselves), and the minimum degree of connection.</p>\n<p><strong>Return columns:</strong> <code>user_id</code>, <code>connection_id</code>,\n<code>degree</code> — ordered by user_id, degree, connection_id.</p>\n", "schema": "\nCREATE TABLE friendships (\n    user_id   INT NOT NULL,\n    friend_id INT NOT NULL,\n    PRIMARY KEY (user_id, friend_id)\n);\nINSERT INTO friendships VALUES\n (1,2),(2,1),(1,3),(3,1),(2,4),(4,2),(3,5),(5,3),(4,5),(5,4),(5,6),(6,5);\n", "solution": "\nWITH direct AS (\n    SELECT user_id, friend_id, 1 AS degree FROM friendships\n),\nsecond AS (\n    SELECT d1.user_id, d2.friend_id AS connection_id, 2 AS degree\n    FROM direct d1\n    JOIN direct d2 ON d2.user_id = d1.friend_id\n    WHERE d2.friend_id <> d1.user_id\n      AND NOT EXISTS (\n          SELECT 1 FROM direct df\n          WHERE df.user_id = d1.user_id AND df.friend_id = d2.friend_id\n      )\n)\nSELECT user_id, connection_id, MIN(degree) AS degree\nFROM second\nGROUP BY user_id, connection_id\nORDER BY user_id, degree, connection_id;\n", "explanation": "\n<p>Join the friendships table to itself: for each friend-of-a-friend path (user → friend → stranger),\nexclude direct connections (NOT EXISTS) and self-loops (<code>d2.friend_id &lt;&gt; d1.user_id</code>).\n<code>MIN(degree)</code> handles the case where two paths of the same degree reach the same\nconnection. Recursive CTEs can generalise this to N degrees, but a two-level join is cleaner for\nexactly 2nd-degree.</p>\n", "hints": ["Self-join friendships twice: user→friend, then friend→stranger.", "Exclude direct connections with NOT EXISTS.", "Exclude self (d2.friend_id != d1.user_id)."], "order_matters": false}, {"id": "h19", "title": "Bill of Materials Explosion", "difficulty": "Hard", "category": "Joins", "companies": ["Boeing", "Siemens", "Caterpillar"], "tsql": true, "description": "\n<p><strong>ManufactureX</strong> stores its product bill of materials recursively: each component\ncan itself be made of sub-components. Expand the full hierarchy for all components, showing the\ndepth and the path from root to leaf.</p>\n<p><strong>Return columns:</strong> <code>component_id</code>, <code>component_name</code>,\n<code>parent_id</code>, <code>level</code>, <code>path</code> — ordered by path.</p>\n", "schema": "\nCREATE TABLE components (\n    component_id   INT PRIMARY KEY,\n    component_name VARCHAR(100) NOT NULL,\n    parent_id      INT\n);\nINSERT INTO components VALUES\n (1, 'Bicycle',      NULL),\n (2, 'Frame',        1),\n (3, 'Wheels',       1),\n (4, 'Drivetrain',   1),\n (5, 'Fork',         2),\n (6, 'Seat Stay',    2),\n (7, 'Front Wheel',  3),\n (8, 'Rear Wheel',   3),\n (9, 'Chain',        4),\n (10,'Cassette',     4);\n", "solution": "\nWITH bom AS (\n    SELECT component_id, component_name, parent_id,\n           1 AS level,\n           CAST(component_name AS VARCHAR(500)) AS path\n    FROM components\n    WHERE parent_id IS NULL\n    UNION ALL\n    SELECT c.component_id, c.component_name, c.parent_id,\n           b.level + 1,\n           CAST(b.path + ' > ' + c.component_name AS VARCHAR(500))\n    FROM components c\n    JOIN bom b ON b.component_id = c.parent_id\n)\nSELECT component_id, component_name, parent_id, level, path\nFROM bom\nORDER BY path;\n", "explanation": "\n<p>A recursive CTE in T-SQL does not need the <code>RECURSIVE</code> keyword (unlike PostgreSQL).\nThe anchor member selects root components (<code>parent_id IS NULL</code>); the recursive member\njoins each child to its already-expanded parent. The string concatenation builds the path.\n<code>CAST(...AS VARCHAR(500))</code> is required because recursive CTEs in SQL Server need\ndeterministic column types — the result of string concatenation must be explicitly typed.</p>\n", "hints": ["T-SQL recursive CTEs don't need the RECURSIVE keyword — just WITH ... UNION ALL.", "Anchor: WHERE parent_id IS NULL. Recursive: JOIN components ON parent_id = b.component_id.", "Cast the path column to a fixed-length type (VARCHAR(500)) for SQL Server compatibility."], "order_matters": false}, {"id": "h20", "title": "Detect Many-to-Many Join Fan-out", "difficulty": "Hard", "category": "Joins", "companies": ["dbt", "Fivetran", "Airbyte"], "tsql": true, "description": "\n<p>A common data pipeline bug: joining through a bridge table multiplies rows unexpectedly.\nAt <strong>DataVault Co</strong>, each order can have multiple tags. Find customers whose\norder count is inflated when tags are joined — i.e. where the naive join count differs from\nthe true order count.</p>\n<p><strong>Return columns:</strong> <code>customer_id</code>, <code>name</code>,\n<code>order_count_inflated</code>, <code>order_count_true</code>, <code>inflation_factor</code>\n— ordered by inflation_factor descending.</p>\n", "schema": "\nCREATE TABLE customers (customer_id INT PRIMARY KEY, name VARCHAR(100) NOT NULL);\nCREATE TABLE orders (order_id INT PRIMARY KEY, customer_id INT NOT NULL);\nCREATE TABLE order_tags (tag_id INT PRIMARY KEY, order_id INT NOT NULL, tag VARCHAR(50) NOT NULL);\nINSERT INTO customers VALUES (1,'Alice'),(2,'Bob'),(3,'Carol');\nINSERT INTO orders VALUES (101,1),(102,1),(103,2),(104,3);\nINSERT INTO order_tags VALUES\n (1,101,'urgent'),(2,101,'gift'),(3,101,'fragile'),\n (4,102,'urgent'),\n (5,103,'gift'),(6,103,'fragile');\n", "solution": "\nSELECT c.customer_id,\n       c.name,\n       COUNT(o.order_id)          AS order_count_inflated,\n       COUNT(DISTINCT o.order_id) AS order_count_true,\n       CAST(COUNT(o.order_id) AS FLOAT)\n           / NULLIF(COUNT(DISTINCT o.order_id), 0) AS inflation_factor\nFROM customers c\nJOIN orders o     ON o.customer_id  = c.customer_id\nJOIN order_tags t ON t.order_id     = o.order_id\nGROUP BY c.customer_id, c.name\nHAVING COUNT(o.order_id) <> COUNT(DISTINCT o.order_id)\nORDER BY inflation_factor DESC;\n", "explanation": "\n<p>Joining through <code>order_tags</code> multiplies each order row by the number of tags it has.\n<code>COUNT(order_id)</code> counts every multiplied row; <code>COUNT(DISTINCT order_id)</code>\ncounts unique orders. When they differ, you have fan-out. The ratio shows how many times each\n\"true\" order is over-counted. In production, always use COUNT DISTINCT or pre-aggregate the\nbridge table before joining.</p>\n", "hints": ["COUNT(col) vs COUNT(DISTINCT col) reveals the fan-out.", "HAVING COUNT(o.order_id) <> COUNT(DISTINCT o.order_id) filters only affected customers.", "The ratio COUNT(col) / COUNT(DISTINCT col) is the inflation factor."], "order_matters": false}, {"id": "h21", "title": "30-Day Conversion Rate by Signup Channel", "difficulty": "Hard", "category": "Aggregation", "companies": ["HubSpot", "Salesforce", "Marketo"], "tsql": true, "description": "\n<p>Marketing at <strong>GrowthBase</strong> acquires users through several channels. Compute the\n30-day purchase conversion rate per channel — the percentage of users from each channel who made\nat least one purchase within 30 days of signing up.</p>\n<p><strong>Return columns:</strong> <code>channel</code>, <code>total_signups</code>,\n<code>conversions</code>, <code>conversion_rate_pct</code> (rounded to 2 dp) — ordered by\nconversion_rate_pct descending.</p>\n", "schema": "\nCREATE TABLE users (\n    user_id    INT PRIMARY KEY,\n    channel    VARCHAR(50) NOT NULL,\n    signup_date DATE NOT NULL\n);\nCREATE TABLE events (\n    event_id   INT PRIMARY KEY,\n    user_id    INT NOT NULL,\n    event_type VARCHAR(50) NOT NULL,\n    event_date DATE NOT NULL\n);\nINSERT INTO users VALUES\n (1,'organic','2025-01-01'),(2,'organic','2025-01-01'),(3,'organic','2025-01-02'),\n (4,'paid_search','2025-01-01'),(5,'paid_search','2025-01-02'),(6,'paid_search','2025-01-03'),\n (7,'referral','2025-01-01'),(8,'referral','2025-01-02');\nINSERT INTO events VALUES\n (1,1,'purchase','2025-01-15'),(2,2,'view','2025-01-10'),\n (3,3,'purchase','2025-01-20'),\n (4,4,'purchase','2025-01-05'),(5,5,'purchase','2025-01-18'),(6,6,'view','2025-01-12'),\n (7,7,'purchase','2025-01-08'),(8,8,'purchase','2025-01-22');\n", "solution": "\nWITH cohort AS (\n    SELECT u.user_id, u.channel,\n           MAX(CASE WHEN e.event_type = 'purchase'\n                     AND DATEDIFF(day, u.signup_date, e.event_date) BETWEEN 1 AND 30\n                    THEN 1 ELSE 0 END) AS converted\n    FROM users u\n    LEFT JOIN events e ON e.user_id = u.user_id\n    GROUP BY u.user_id, u.channel\n)\nSELECT channel,\n       COUNT(*) AS total_signups,\n       SUM(converted) AS conversions,\n       ROUND(SUM(converted) * 100.0 / COUNT(*), 2) AS conversion_rate_pct\nFROM cohort\nGROUP BY channel\nORDER BY conversion_rate_pct DESC;\n", "explanation": "\n<p>The inner CTE produces one row per user with a 0/1 converted flag. LEFT JOIN is required —\nusers who never purchased must appear with converted = 0, not be excluded. The outer aggregation\ngroups by channel. <code>DATEDIFF(day, signup, event) BETWEEN 1 AND 30</code> restricts the\nwindow to the first 30 days; day 0 (the signup day itself) is excluded by starting at 1.</p>\n", "hints": ["LEFT JOIN events to keep users who never converted.", "MAX(CASE WHEN purchase AND within 30 days THEN 1 ELSE 0 END) gives a per-user conversion flag.", "DATEDIFF(day, signup_date, event_date) BETWEEN 1 AND 30 defines the window."], "order_matters": false}, {"id": "h22", "title": "Accessory Attachment Rate", "difficulty": "Hard", "category": "Aggregation", "companies": ["Apple", "Sony", "Bose"], "tsql": true, "description": "\n<p>The product team at <strong>GadgetHub</strong> wants to know what fraction of customers who\nbought a <code>Camera</code> also bought at least one <code>Accessory</code> in any order\n(not necessarily the same order). This is the accessory attachment rate.</p>\n<p><strong>Return columns:</strong> <code>camera_buyers</code>,\n<code>also_bought_accessory</code>, <code>attachment_rate_pct</code> (rounded to 2 dp).</p>\n", "schema": "\nCREATE TABLE orders (order_id INT PRIMARY KEY, customer_id INT NOT NULL);\nCREATE TABLE order_items (item_id INT PRIMARY KEY, order_id INT NOT NULL, product_id INT NOT NULL);\nCREATE TABLE products (product_id INT PRIMARY KEY, name VARCHAR(100) NOT NULL, category VARCHAR(50) NOT NULL);\nINSERT INTO products VALUES\n (1,'Canon EOS','Camera'),(2,'Sony Alpha','Camera'),\n (3,'Camera Bag','Accessory'),(4,'Memory Card','Accessory'),(5,'Tripod','Accessory'),\n (6,'Laptop','Electronics');\nINSERT INTO orders VALUES (101,1),(102,1),(103,2),(104,3),(105,4),(106,5);\nINSERT INTO order_items VALUES\n (1,101,1),(2,102,3),(3,102,4),\n (4,103,2),\n (5,104,1),(6,104,5),\n (7,105,2),\n (8,106,6);\n", "solution": "\nWITH buyers AS (\n    SELECT o.customer_id,\n           MAX(CASE WHEN p.category = 'Camera'    THEN 1 ELSE 0 END) AS bought_camera,\n           MAX(CASE WHEN p.category = 'Accessory' THEN 1 ELSE 0 END) AS bought_accessory\n    FROM orders o\n    JOIN order_items oi ON oi.order_id    = o.order_id\n    JOIN products    p  ON p.product_id   = oi.product_id\n    GROUP BY o.customer_id\n)\nSELECT SUM(bought_camera) AS camera_buyers,\n       SUM(CASE WHEN bought_camera = 1 AND bought_accessory = 1 THEN 1 END) AS also_bought_accessory,\n       ROUND(SUM(CASE WHEN bought_camera = 1 AND bought_accessory = 1 THEN 1 END) * 100.0\n             / NULLIF(SUM(bought_camera), 0), 2) AS attachment_rate_pct\nFROM buyers;\n", "explanation": "\n<p>The inner CTE computes two binary flags per customer: did they ever buy a Camera, and did they\never buy an Accessory. The outer query then counts how many camera buyers also bought an accessory.\nNULLIF prevents division-by-zero if no one bought a camera. The attachment rate is a standard\nretail KPI — \"of customers who bought X, what fraction also bought Y?\"</p>\n", "hints": ["Compute bought_camera and bought_accessory as MAX(CASE WHEN) flags per customer.", "Outer query: SUM(bought_camera) = camera buyers; SUM(both = 1) = converters.", "NULLIF(SUM(bought_camera), 0) prevents division-by-zero."], "order_matters": false}, {"id": "h23", "title": "Month-over-Month Category Revenue Change", "difficulty": "Hard", "category": "Aggregation", "companies": ["Walmart", "Amazon", "Shopify"], "tsql": true, "description": "\n<p>Finance at <strong>RetailCore</strong> monitors monthly revenue momentum. For each category,\nshow each month's revenue, the prior month's revenue, the absolute change, and the percentage\nchange — excluding the first month per category (no prior month to compare).</p>\n<p><strong>Return columns:</strong> <code>category</code>, <code>month</code>,\n<code>monthly_revenue</code>, <code>prev_month_revenue</code>, <code>change</code>,\n<code>pct_change</code> (rounded to 2 dp) — ordered by category, month.</p>\n", "schema": "\nCREATE TABLE product_sales (\n    sale_id   INT PRIMARY KEY,\n    category  VARCHAR(50) NOT NULL,\n    revenue   DECIMAL(10,2) NOT NULL,\n    sale_date DATE NOT NULL\n);\nINSERT INTO product_sales VALUES\n (1,'Electronics',4200.00,'2025-01-10'),(2,'Electronics',3100.00,'2025-01-25'),\n (3,'Electronics',5800.00,'2025-02-12'),(4,'Electronics',4400.00,'2025-02-28'),\n (5,'Electronics',6100.00,'2025-03-15'),\n (6,'Clothing',1800.00,'2025-01-08'),(7,'Clothing',2500.00,'2025-02-14'),\n (8,'Clothing',2100.00,'2025-03-22');\n", "solution": "\nWITH monthly AS (\n    SELECT category,\n           FORMAT(sale_date, 'yyyy-MM') AS month,\n           SUM(revenue) AS monthly_revenue\n    FROM product_sales\n    GROUP BY category, FORMAT(sale_date, 'yyyy-MM')\n),\nwith_prev AS (\n    SELECT category, month, monthly_revenue,\n           LAG(monthly_revenue) OVER (PARTITION BY category ORDER BY month) AS prev_month_revenue\n    FROM monthly\n)\nSELECT category, month, monthly_revenue, prev_month_revenue,\n       monthly_revenue - prev_month_revenue AS change,\n       ROUND((monthly_revenue - prev_month_revenue) * 100.0\n             / NULLIF(prev_month_revenue, 0), 2) AS pct_change\nFROM with_prev\nWHERE prev_month_revenue IS NOT NULL\nORDER BY category, month;\n", "explanation": "\n<p>Two CTEs: first aggregate to monthly totals per category; then apply LAG partitioned by\ncategory to get the prior month. FORMAT('yyyy-MM') sorts lexicographically, so the LAG ordering\nis correct. NULLIF on the denominator handles categories with zero revenue in a prior month.\nThe WHERE clause removes the first month per category (no comparison available).</p>\n", "hints": ["FORMAT(sale_date, 'yyyy-MM') groups by month and sorts lexicographically.", "LAG(monthly_revenue) OVER (PARTITION BY category ORDER BY month) gives the prior month.", "Filter WHERE prev_month_revenue IS NOT NULL to exclude the first month per category."], "order_matters": false}, {"id": "h24", "title": "Business Days to Ship", "difficulty": "Hard", "category": "Date/Time", "companies": ["FedEx", "UPS", "Amazon"], "tsql": true, "description": "\n<p>The SLA team at <strong>SwiftShip</strong> measures fulfilment speed in business days\n(Monday–Friday only). For each shipped order, compute the number of business days between the\norder date and the ship date.</p>\n<p><strong>Return columns:</strong> <code>order_id</code>, <code>order_date</code>,\n<code>ship_date</code>, <code>business_days</code> — ordered by business_days descending.</p>\n", "schema": "\nCREATE TABLE orders (\n    order_id   INT PRIMARY KEY,\n    order_date DATE NOT NULL,\n    ship_date  DATE\n);\nINSERT INTO orders VALUES\n (1, '2025-01-06', '2025-01-08'),\n (2, '2025-01-06', '2025-01-10'),\n (3, '2025-01-07', '2025-01-13'),\n (4, '2025-01-09', '2025-01-14'),\n (5, '2025-01-10', '2025-01-16'),\n (6, '2025-01-13', NULL);\n", "solution": "\nWITH tally AS (\n    SELECT TOP 30 ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS n\n    FROM sys.all_objects\n),\nshipped AS (\n    SELECT order_id, order_date, ship_date,\n           DATEDIFF(day, order_date, ship_date) AS total_days\n    FROM orders\n    WHERE ship_date IS NOT NULL\n)\nSELECT s.order_id, s.order_date, s.ship_date,\n       (\n           SELECT COUNT(*)\n           FROM tally t\n           WHERE t.n <= s.total_days\n             AND DATEPART(weekday, DATEADD(day, t.n, s.order_date)) NOT IN (1, 7)\n       ) AS business_days\nFROM shipped s\nORDER BY business_days DESC;\n", "explanation": "\n<p>A tally CTE generates integers 1 through 30 (enough for any reasonable ship window). For each\norder, count how many of those offsets land on a weekday. <code>DATEPART(weekday, ...)</code>\nreturns 1 for Sunday and 7 for Saturday in SQL Server's default setting, so filtering\n<code>NOT IN (1, 7)</code> keeps only Monday–Friday. Counting matching offsets ≤ total_days\ngives the business-day gap.</p>\n", "hints": ["Generate a tally table of integers 1..N using TOP + ROW_NUMBER() from sys.all_objects.", "For each offset n, compute DATEADD(day, n, order_date) and check DATEPART(weekday).", "In SQL Server, weekday 1 = Sunday, 7 = Saturday — filter NOT IN (1, 7)."], "order_matters": false}, {"id": "h25", "title": "User Activity Segments", "difficulty": "Hard", "category": "Date/Time", "companies": ["Intercom", "Braze", "Customer.io"], "tsql": true, "description": "\n<p>The lifecycle team at <strong>EngageIQ</strong> classifies users by how recently they were\nlast active relative to <code>2025-03-01</code>:</p>\n<ul>\n<li><strong>Active</strong>: last seen ≤ 7 days ago</li>\n<li><strong>At Risk</strong>: 8–30 days ago</li>\n<li><strong>Churning</strong>: 31–90 days ago</li>\n<li><strong>Churned</strong>: &gt; 90 days ago</li>\n</ul>\n<p><strong>Return columns:</strong> <code>user_id</code>, <code>name</code>,\n<code>last_login_date</code>, <code>days_inactive</code>, <code>segment</code>\n— ordered by days_inactive ascending.</p>\n", "schema": "\nCREATE TABLE users (user_id INT PRIMARY KEY, name VARCHAR(100) NOT NULL);\nCREATE TABLE user_logins (login_id INT PRIMARY KEY, user_id INT NOT NULL, login_date DATE NOT NULL);\nINSERT INTO users VALUES (1,'Alice'),(2,'Bob'),(3,'Carol'),(4,'Dave'),(5,'Eve');\nINSERT INTO user_logins VALUES\n (1,1,'2025-02-27'),(2,1,'2025-02-28'),\n (3,2,'2025-02-10'),\n (4,3,'2025-01-20'),\n (5,4,'2024-11-15'),\n (6,5,'2025-02-22'),(7,5,'2025-02-25');\n", "solution": "\nWITH last_login AS (\n    SELECT user_id, MAX(login_date) AS last_login_date\n    FROM user_logins\n    GROUP BY user_id\n)\nSELECT u.user_id, u.name, ll.last_login_date,\n       DATEDIFF(day, ll.last_login_date, '2025-03-01') AS days_inactive,\n       CASE\n           WHEN DATEDIFF(day, ll.last_login_date, '2025-03-01') <= 7  THEN 'Active'\n           WHEN DATEDIFF(day, ll.last_login_date, '2025-03-01') <= 30 THEN 'At Risk'\n           WHEN DATEDIFF(day, ll.last_login_date, '2025-03-01') <= 90 THEN 'Churning'\n           ELSE 'Churned'\n       END AS segment\nFROM users u\nJOIN last_login ll ON ll.user_id = u.user_id\nORDER BY days_inactive ASC;\n", "explanation": "\n<p>MAX(login_date) per user in a CTE gives the most recent login. DATEDIFF(day, last, reference)\ncomputes inactivity in days. The CASE statement uses cascading thresholds — each condition is\nevaluated in order, so there is no need for range predicates like BETWEEN; once a condition\nmatches, the rest are skipped. In production, replace the hard-coded date with GETDATE().</p>\n", "hints": ["MAX(login_date) per user gives the most recent login.", "DATEDIFF(day, last_login_date, '2025-03-01') gives days inactive.", "Cascading CASE WHEN with <= thresholds is cleaner than BETWEEN for ordered buckets."], "order_matters": false}, {"id": "h26", "title": "Peak Hour by Day of Week", "difficulty": "Hard", "category": "Date/Time", "companies": ["Uber", "Lyft", "DoorDash"], "tsql": true, "description": "\n<p>Operations at <strong>SpeedRide</strong> wants to know, for each day of the week, which hour\nof the day sees the most ride requests — to align driver incentives.</p>\n<p><strong>Return columns:</strong> <code>day_of_week</code>, <code>hour_of_day</code>,\n<code>peak_requests</code> — ordered by the calendar day number (1 = Sunday).</p>\n", "schema": "\nCREATE TABLE rides (\n    ride_id      INT PRIMARY KEY,\n    request_time VARCHAR(19) NOT NULL\n);\nINSERT INTO rides VALUES\n (1,'2025-01-06 08:15:00'),(2,'2025-01-06 08:42:00'),(3,'2025-01-06 12:10:00'),\n (4,'2025-01-07 07:55:00'),(5,'2025-01-07 08:05:00'),(6,'2025-01-07 08:30:00'),(7,'2025-01-07 18:20:00'),\n (8,'2025-01-08 09:00:00'),(9,'2025-01-08 17:45:00'),(10,'2025-01-08 17:58:00'),(11,'2025-01-08 18:10:00'),\n (12,'2025-01-09 08:00:00'),(13,'2025-01-09 08:20:00'),\n (14,'2025-01-10 07:50:00'),(15,'2025-01-10 08:10:00'),(16,'2025-01-10 08:25:00'),(17,'2025-01-10 12:30:00'),\n (18,'2025-01-11 10:00:00'),(19,'2025-01-11 14:00:00'),\n (20,'2025-01-12 11:00:00'),(21,'2025-01-12 15:00:00'),(22,'2025-01-12 15:30:00');\n", "solution": "\nWITH hourly AS (\n    SELECT DATENAME(weekday, CAST(request_time AS DATETIME))  AS day_of_week,\n           DATEPART(weekday,  CAST(request_time AS DATETIME)) AS day_num,\n           DATEPART(hour,     CAST(request_time AS DATETIME)) AS hour_of_day,\n           COUNT(*) AS request_count\n    FROM rides\n    GROUP BY DATENAME(weekday, CAST(request_time AS DATETIME)),\n             DATEPART(weekday,  CAST(request_time AS DATETIME)),\n             DATEPART(hour,     CAST(request_time AS DATETIME))\n),\nranked AS (\n    SELECT day_of_week, day_num, hour_of_day, request_count,\n           ROW_NUMBER() OVER (PARTITION BY day_of_week ORDER BY request_count DESC) AS rn\n    FROM hourly\n)\nSELECT day_of_week, hour_of_day, request_count AS peak_requests\nFROM ranked\nWHERE rn = 1\nORDER BY day_num;\n", "explanation": "\n<p>Two steps: first aggregate to (day, hour) buckets; then rank hours within each day by request\ncount. ROW_NUMBER() = 1 picks the single peak hour per day. Including <code>day_num</code> in the\nGROUP BY alongside <code>day_of_week</code> ensures the ORDER BY can sort by calendar position\nrather than alphabetically.</p>\n", "hints": ["GROUP BY day-of-week AND hour-of-day to get hourly buckets per day.", "ROW_NUMBER() OVER (PARTITION BY day_of_week ORDER BY count DESC) = 1 picks the peak hour.", "Include DATEPART(weekday) in GROUP BY so you can ORDER BY it for calendar order."], "order_matters": false}, {"id": "h27", "title": "Latest Event per User-Device Pair", "difficulty": "Hard", "category": "Deduplication", "companies": ["Apple", "Google", "Samsung"], "tsql": true, "description": "\n<p>The device team at <strong>PulseApp</strong> wants the most recent event for every\n(user, device) combination — this represents the current state of each device in the fleet.</p>\n<p><strong>Return columns:</strong> <code>user_id</code>, <code>device_id</code>,\n<code>event_type</code>, <code>event_time</code> — ordered by user_id, device_id.</p>\n", "schema": "\nCREATE TABLE device_events (\n    event_id   INT PRIMARY KEY,\n    user_id    INT NOT NULL,\n    device_id  VARCHAR(20) NOT NULL,\n    event_type VARCHAR(50) NOT NULL,\n    event_time VARCHAR(19) NOT NULL\n);\nINSERT INTO device_events VALUES\n (1, 1,'DEV-001','login',  '2025-01-10 08:00:00'),\n (2, 1,'DEV-001','action', '2025-01-10 09:15:00'),\n (3, 1,'DEV-001','logout', '2025-01-10 17:30:00'),\n (4, 1,'DEV-002','login',  '2025-01-11 10:00:00'),\n (5, 1,'DEV-002','action', '2025-01-11 11:45:00'),\n (6, 2,'DEV-003','login',  '2025-01-12 14:00:00'),\n (7, 2,'DEV-003','logout', '2025-01-12 15:30:00'),\n (8, 2,'DEV-003','login',  '2025-01-13 09:00:00');\n", "solution": "\nWITH ranked AS (\n    SELECT user_id, device_id, event_type, event_time,\n           ROW_NUMBER() OVER (\n               PARTITION BY user_id, device_id\n               ORDER BY event_time DESC\n           ) AS rn\n    FROM device_events\n)\nSELECT user_id, device_id, event_type, event_time\nFROM ranked\nWHERE rn = 1\nORDER BY user_id, device_id;\n", "explanation": "\n<p>Partitioning by <em>both</em> user_id and device_id restarts the row number for each\nuser-device pair independently. ORDER BY event_time DESC puts the most recent event first.\nWHERE rn = 1 keeps exactly one row per pair. This two-level partition is common in IoT pipelines\nwhere the deduplication key is a composite of entity and sub-entity.</p>\n", "hints": ["PARTITION BY user_id, device_id creates one group per user-device pair.", "ORDER BY event_time DESC puts the latest event first in each group.", "WHERE rn = 1 keeps one row per pair."], "order_matters": false}, {"id": "h28", "title": "Deduplicate by Source Priority", "difficulty": "Hard", "category": "Deduplication", "companies": ["Salesforce", "HubSpot", "Fivetran"], "tsql": true, "description": "\n<p>Customer records at <strong>DataVault Co</strong> arrive from three sources:\n<code>crm</code> (most trusted), <code>web</code>, and <code>import</code> (least trusted).\nWhen the same customer appears in multiple sources, keep the record from the most trusted source.\n</p>\n<p><strong>Return columns:</strong> <code>customer_id</code>, <code>name</code>,\n<code>email</code>, <code>source</code> — ordered by customer_id.</p>\n", "schema": "\nCREATE TABLE customer_records (\n    record_id   INT PRIMARY KEY,\n    customer_id INT NOT NULL,\n    name        VARCHAR(100) NOT NULL,\n    email       VARCHAR(100) NOT NULL,\n    source      VARCHAR(20) NOT NULL\n);\nINSERT INTO customer_records VALUES\n (1, 1,'Alice A','alice@co.com','import'),\n (2, 1,'Alice A','alice@co.com','crm'),\n (3, 2,'Bob B',  'bob@co.com',  'web'),\n (4, 2,'Bob B',  'bob@co.com',  'crm'),\n (5, 3,'Carol C','carol@co.com','import'),\n (6, 3,'Carol C','carol@co.com','web'),\n (7, 4,'Dave D', 'dave@co.com', 'crm');\n", "solution": "\nWITH ranked AS (\n    SELECT customer_id, name, email, source,\n           ROW_NUMBER() OVER (\n               PARTITION BY customer_id\n               ORDER BY CASE source\n                   WHEN 'crm'    THEN 1\n                   WHEN 'web'    THEN 2\n                   WHEN 'import' THEN 3\n                   ELSE 4\n               END\n           ) AS rn\n    FROM customer_records\n)\nSELECT customer_id, name, email, source\nFROM ranked\nWHERE rn = 1\nORDER BY customer_id;\n", "explanation": "\n<p>Embedding a CASE expression inside the ORDER BY of ROW_NUMBER() controls the deduplication\npriority without a separate lookup table. The CASE assigns a sort position: crm=1 (best) sorts\nfirst, so rn=1 is always the most trusted source. This pattern is the foundation of \"master\ndata management\" deduplication in production pipelines.</p>\n", "hints": ["PARTITION BY customer_id groups duplicates; ORDER BY priority assigns rank 1 to the best source.", "Use CASE inside ORDER BY to translate source names to priority numbers.", "WHERE rn = 1 keeps only the most trusted record per customer."], "order_matters": false}, {"id": "h29", "title": "Overlapping Session Detection", "difficulty": "Hard", "category": "Gaps & Islands", "companies": ["Zoom", "Teams", "Webex"], "tsql": true, "description": "\n<p>The capacity team at <strong>MeetUp</strong> needs to find all pairs of sessions for the same\nuser that overlap in time — evidence of a double-booking bug.</p>\n<p><strong>Return columns:</strong> <code>user_id</code>, <code>session_a</code>,\n<code>session_b</code>, <code>a_start</code>, <code>a_end</code>, <code>b_start</code>,\n<code>b_end</code> — ordered by user_id, a_start.</p>\n", "schema": "\nCREATE TABLE sessions (\n    session_id INT PRIMARY KEY,\n    user_id    INT NOT NULL,\n    start_time VARCHAR(19) NOT NULL,\n    end_time   VARCHAR(19) NOT NULL\n);\nINSERT INTO sessions VALUES\n (1, 1,'2025-01-10 09:00:00','2025-01-10 10:00:00'),\n (2, 1,'2025-01-10 09:30:00','2025-01-10 11:00:00'),\n (3, 1,'2025-01-10 11:30:00','2025-01-10 12:30:00'),\n (4, 2,'2025-01-10 14:00:00','2025-01-10 15:00:00'),\n (5, 2,'2025-01-10 14:45:00','2025-01-10 16:00:00'),\n (6, 3,'2025-01-10 10:00:00','2025-01-10 11:00:00'),\n (7, 3,'2025-01-10 11:00:00','2025-01-10 12:00:00');\n", "solution": "\nSELECT a.user_id,\n       a.session_id AS session_a, b.session_id AS session_b,\n       a.start_time AS a_start,  a.end_time   AS a_end,\n       b.start_time AS b_start,  b.end_time   AS b_end\nFROM sessions a\nJOIN sessions b\n    ON  b.user_id    = a.user_id\n    AND b.session_id > a.session_id\n    AND b.start_time < a.end_time\n    AND b.end_time   > a.start_time\nORDER BY a.user_id, a.start_time;\n", "explanation": "\n<p>Two sessions overlap when one starts before the other ends AND ends after the other starts.\nThe standard interval overlap test is: <code>A.start &lt; B.end AND A.end &gt; B.start</code>.\n<code>b.session_id &gt; a.session_id</code> ensures each pair appears once (avoids (A,B) and\n(B,A)). Note session 6 and 7 touch at exactly 11:00 — touching boundaries are not overlapping\nhere because of the strict inequalities.</p>\n", "hints": ["Two intervals [A.start, A.end) and [B.start, B.end) overlap when A.start < B.end AND A.end > B.start.", "b.session_id > a.session_id prevents duplicating each pair.", "Strict < and > means touching boundaries are NOT considered overlapping."], "order_matters": false}, {"id": "h30", "title": "Longest Consecutive Sales Streak", "difficulty": "Hard", "category": "Gaps & Islands", "companies": ["Walmart", "Target", "Kroger"], "tsql": true, "description": "\n<p>The ops team at <strong>RetailCore</strong> wants to find the longest unbroken streak of\nconsecutive calendar days on which at least one sale was recorded.</p>\n<p><strong>Return columns:</strong> <code>streak_start</code>, <code>streak_end</code>,\n<code>streak_length</code>.</p>\n", "schema": "\nCREATE TABLE sales (\n    sale_id   INT PRIMARY KEY,\n    sale_date DATE NOT NULL,\n    amount    DECIMAL(10,2) NOT NULL\n);\nINSERT INTO sales VALUES\n (1,'2025-01-01',100.00),(2,'2025-01-02',200.00),(3,'2025-01-02',150.00),\n (4,'2025-01-03',300.00),(5,'2025-01-05',180.00),(6,'2025-01-06',220.00),\n (7,'2025-01-07',410.00),(8,'2025-01-08',90.00),(9,'2025-01-08',130.00),\n (10,'2025-01-10',270.00);\n", "solution": "\nWITH daily AS (\n    SELECT DISTINCT sale_date FROM sales\n),\nanchored AS (\n    SELECT sale_date,\n           DATEDIFF(day, '2000-01-01', sale_date)\n               - ROW_NUMBER() OVER (ORDER BY sale_date) AS grp\n    FROM daily\n),\nislands AS (\n    SELECT MIN(sale_date) AS streak_start,\n           MAX(sale_date) AS streak_end,\n           COUNT(*)       AS streak_length\n    FROM anchored\n    GROUP BY grp\n)\nSELECT TOP 1 streak_start, streak_end, streak_length\nFROM islands\nORDER BY streak_length DESC;\n", "explanation": "\n<p>Deduplicate to one row per day with DISTINCT. Subtract a sequential row number from the day\ncount (days since a fixed anchor date) — consecutive dates produce the same constant, forming\nthe island group key. Aggregate each island for start, end, and length. TOP 1 ORDER BY length\nDESC returns the longest streak.</p>\n", "hints": ["DISTINCT first to collapse multiple sales on the same day to one row.", "DATEDIFF(day, anchor, sale_date) - ROW_NUMBER() is constant for consecutive dates.", "GROUP BY that constant, then pick the island with MAX COUNT(*)."], "order_matters": false}, {"id": "h31", "title": "Merge Overlapping Date Ranges", "difficulty": "Hard", "category": "Gaps & Islands", "companies": ["Snowflake", "Databricks", "dbt"], "tsql": true, "description": "\n<p>A subscription history table at <strong>DataVault Co</strong> may contain overlapping active\nperiods for the same customer (a known data quality issue). Merge all overlapping or adjacent\nranges per customer into a single continuous period.</p>\n<p><strong>Return columns:</strong> <code>customer_id</code>, <code>merged_start</code>,\n<code>merged_end</code> — ordered by customer_id, merged_start.</p>\n", "schema": "\nCREATE TABLE subscriptions (\n    sub_id      INT PRIMARY KEY,\n    customer_id INT NOT NULL,\n    start_date  DATE NOT NULL,\n    end_date    DATE NOT NULL\n);\nINSERT INTO subscriptions VALUES\n (1, 1,'2025-01-01','2025-01-15'),\n (2, 1,'2025-01-10','2025-01-20'),\n (3, 1,'2025-01-22','2025-01-31'),\n (4, 2,'2025-01-05','2025-01-12'),\n (5, 2,'2025-01-12','2025-01-18'),\n (6, 2,'2025-01-25','2025-02-05'),\n (7, 3,'2025-01-01','2025-01-31');\n", "solution": "\nWITH ordered AS (\n    SELECT customer_id, start_date, end_date,\n           MAX(end_date) OVER (\n               PARTITION BY customer_id\n               ORDER BY start_date\n               ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING\n           ) AS prev_max_end\n    FROM subscriptions\n),\nisland_start AS (\n    SELECT customer_id, start_date, end_date,\n           CASE WHEN start_date <= ISNULL(prev_max_end, start_date)\n                THEN 0 ELSE 1 END AS is_new_island\n    FROM ordered\n),\nislands AS (\n    SELECT customer_id, start_date, end_date,\n           SUM(is_new_island) OVER (PARTITION BY customer_id ORDER BY start_date) AS island_id\n    FROM island_start\n)\nSELECT customer_id,\n       MIN(start_date) AS merged_start,\n       MAX(end_date)   AS merged_end\nFROM islands\nGROUP BY customer_id, island_id\nORDER BY customer_id, merged_start;\n", "explanation": "\n<p>The key insight: a new island starts when the current range's start_date is greater than the\nrunning maximum end_date of all preceding ranges. Step 1: compute the running MAX of end_date\nusing a window with ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING. Step 2: flag each row\nwhere start_date exceeds that running max. Step 3: SUM the flag as a running counter — all rows\nin the same island share the same counter value. Step 4: GROUP BY island_id and take MIN/MAX.</p>\n", "hints": ["A new island begins when start_date > running MAX(end_date) of all previous ranges.", "Compute running MAX with ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING.", "SUM(is_new_island) OVER (ORDER BY start_date) creates an island ID."], "order_matters": false}, {"id": "h32", "title": "D7 and D30 Retention by Signup Week", "difficulty": "Hard", "category": "Retention & Cohorts", "companies": ["Meta", "Snap", "Discord"], "tsql": true, "description": "\n<p>The product team at <strong>Chirper</strong> tracks both Day-7 and Day-30 retention for each\nweekly signup cohort. Return one row per signup week showing cohort size, D7 retention rate,\nand D30 retention rate.</p>\n<p><strong>Return columns:</strong> <code>signup_yr</code>, <code>signup_wk</code>,\n<code>cohort_size</code>, <code>d7_retention_pct</code>, <code>d30_retention_pct</code>\n— ordered by signup_yr, signup_wk.</p>\n", "schema": "\nCREATE TABLE users (user_id INT PRIMARY KEY, signup_date DATE NOT NULL);\nCREATE TABLE events (event_id INT PRIMARY KEY, user_id INT NOT NULL, event_date DATE NOT NULL);\nINSERT INTO users VALUES\n (1,'2025-01-06'),(2,'2025-01-06'),(3,'2025-01-06'),(4,'2025-01-06'),\n (5,'2025-01-13'),(6,'2025-01-13'),(7,'2025-01-13');\nINSERT INTO events VALUES\n (1,1,'2025-01-10'),(2,2,'2025-01-13'),(3,3,'2025-02-05'),\n (4,1,'2025-02-07'),(5,4,'2025-01-08'),\n (6,5,'2025-01-18'),(7,6,'2025-02-12'),(8,7,'2025-01-20');\n", "solution": "\nWITH cohort AS (\n    SELECT u.user_id,\n           DATEPART(year, u.signup_date) AS signup_yr,\n           DATEPART(week, u.signup_date) AS signup_wk,\n           u.signup_date,\n           MAX(CASE WHEN DATEDIFF(day, u.signup_date, e.event_date) BETWEEN 1 AND 7\n                    THEN 1 ELSE 0 END) AS d7,\n           MAX(CASE WHEN DATEDIFF(day, u.signup_date, e.event_date) BETWEEN 1 AND 30\n                    THEN 1 ELSE 0 END) AS d30\n    FROM users u\n    LEFT JOIN events e ON e.user_id = u.user_id\n    GROUP BY u.user_id, DATEPART(year, u.signup_date),\n             DATEPART(week, u.signup_date), u.signup_date\n)\nSELECT signup_yr, signup_wk,\n       COUNT(*) AS cohort_size,\n       ROUND(SUM(d7)  * 100.0 / COUNT(*), 2) AS d7_retention_pct,\n       ROUND(SUM(d30) * 100.0 / COUNT(*), 2) AS d30_retention_pct\nFROM cohort\nGROUP BY signup_yr, signup_wk\nORDER BY signup_yr, signup_wk;\n", "explanation": "\n<p>The inner CTE computes two binary flags per user using MAX(CASE WHEN ...) — one for D7 return\nand one for D30 return. LEFT JOIN keeps all users including those who never returned. A user can\nsatisfy D30 without satisfying D7 if they returned between days 8 and 30. The outer GROUP BY\nrolls up by week cohort.</p>\n", "hints": ["Two MAX(CASE WHEN) flags per user: D7 = return within 7 days, D30 = return within 30 days.", "LEFT JOIN events — users with no return must count as 0, not be excluded.", "Group outer query by signup week; SUM the flags for retention counts."], "order_matters": false}, {"id": "h33", "title": "Reactivated Users", "difficulty": "Hard", "category": "Retention & Cohorts", "companies": ["Netflix", "Spotify", "Duolingo"], "tsql": true, "description": "\n<p>The growth team at <strong>StreamOn</strong> defines a reactivated user as someone who had a\ngap of 30 or more consecutive inactive days and then returned. For each reactivation event, show\nwho came back, when, and how long the gap was.</p>\n<p><strong>Return columns:</strong> <code>user_id</code>, <code>name</code>,\n<code>reactivation_date</code>, <code>gap_days</code> — ordered by gap_days descending.</p>\n", "schema": "\nCREATE TABLE users (user_id INT PRIMARY KEY, name VARCHAR(100) NOT NULL);\nCREATE TABLE events (event_id INT PRIMARY KEY, user_id INT NOT NULL, event_date DATE NOT NULL);\nINSERT INTO users VALUES (1,'Alice'),(2,'Bob'),(3,'Carol'),(4,'Dave');\nINSERT INTO events VALUES\n (1,1,'2025-01-05'),(2,1,'2025-01-10'),(3,1,'2025-02-20'),\n (4,2,'2025-01-03'),(5,2,'2025-01-08'),(6,2,'2025-01-12'),\n (7,3,'2025-01-01'),(8,3,'2025-02-15'),(9,3,'2025-03-01'),\n (10,4,'2025-01-20'),(11,4,'2025-03-10');\n", "solution": "\nWITH daily AS (\n    SELECT DISTINCT user_id, event_date FROM events\n),\nwith_prev AS (\n    SELECT user_id, event_date,\n           LAG(event_date) OVER (PARTITION BY user_id ORDER BY event_date) AS prev_date\n    FROM daily\n)\nSELECT w.user_id, u.name,\n       w.event_date AS reactivation_date,\n       DATEDIFF(day, w.prev_date, w.event_date) AS gap_days\nFROM with_prev w\nJOIN users u ON u.user_id = w.user_id\nWHERE DATEDIFF(day, w.prev_date, w.event_date) >= 30\nORDER BY gap_days DESC;\n", "explanation": "\n<p>Deduplicate to one row per user per day, then LAG to get the previous activity date per user.\nDATEDIFF(day, prev, curr) &gt;= 30 identifies gaps of a month or more — those are reactivation\nevents. Alice's gap from Jan 10 to Feb 20 is 41 days (reactivated); Dave's gap from Jan 20 to\nMar 10 is 49 days. Bob has no 30+ day gap.</p>\n", "hints": ["DISTINCT events first to get one row per user per day.", "LAG(event_date) OVER (PARTITION BY user_id ORDER BY event_date) gives the previous activity date.", "WHERE DATEDIFF(day, prev_date, event_date) >= 30 identifies reactivations."], "order_matters": false}, {"id": "h34", "title": "Churn Risk Feature Table", "difficulty": "Hard", "category": "Retention & Cohorts", "companies": ["Braze", "Intercom", "Customer.io"], "tsql": true, "description": "\n<p>The ML team at <strong>EngageIQ</strong> needs a feature table for a churn prediction model.\nFor each user, compute: days since last event (as of <code>2025-03-01</code>), total events,\nnumber of distinct active days, purchase count, average order value, and a churn risk label.</p>\n<p><strong>Return columns:</strong> <code>user_id</code>, <code>name</code>,\n<code>days_inactive</code>, <code>total_events</code>, <code>active_days</code>,\n<code>purchase_count</code>, <code>avg_order_value</code>, <code>churn_risk</code>\n— ordered by days_inactive descending.</p>\n", "schema": "\nCREATE TABLE users (user_id INT PRIMARY KEY, name VARCHAR(100) NOT NULL);\nCREATE TABLE events (\n    event_id   INT PRIMARY KEY,\n    user_id    INT NOT NULL,\n    event_type VARCHAR(50) NOT NULL,\n    event_date DATE NOT NULL,\n    amount     DECIMAL(10,2)\n);\nINSERT INTO users VALUES (1,'Alice'),(2,'Bob'),(3,'Carol'),(4,'Dave');\nINSERT INTO events VALUES\n (1,1,'view',     '2025-02-28',NULL),\n (2,1,'purchase', '2025-02-25',89.00),\n (3,1,'purchase', '2025-02-20',120.00),\n (4,2,'view',     '2025-01-15',NULL),\n (5,2,'purchase', '2025-01-10',45.00),\n (6,3,'view',     '2024-11-01',NULL),\n (7,4,'purchase', '2025-02-10',200.00),\n (8,4,'view',     '2025-02-14',NULL),\n (9,4,'purchase', '2025-02-20',150.00);\n", "solution": "\nWITH features AS (\n    SELECT u.user_id, u.name,\n           DATEDIFF(day, MAX(e.event_date), '2025-03-01') AS days_inactive,\n           COUNT(e.event_id) AS total_events,\n           COUNT(DISTINCT e.event_date) AS active_days,\n           SUM(CASE WHEN e.event_type = 'purchase' THEN 1 ELSE 0 END) AS purchase_count,\n           AVG(CASE WHEN e.event_type = 'purchase' THEN e.amount END) AS avg_order_value\n    FROM users u\n    LEFT JOIN events e ON e.user_id = u.user_id\n    GROUP BY u.user_id, u.name\n)\nSELECT user_id, name, days_inactive, total_events, active_days, purchase_count,\n       ISNULL(avg_order_value, 0) AS avg_order_value,\n       CASE\n           WHEN days_inactive > 60 OR days_inactive IS NULL THEN 'High'\n           WHEN days_inactive > 30                          THEN 'Medium'\n           ELSE 'Low'\n       END AS churn_risk\nFROM features\nORDER BY days_inactive DESC;\n", "explanation": "\n<p>This is a feature engineering query — a common take-home challenge. Each metric is computed\nwith a single pass over the events table using conditional aggregation. ISNULL converts NULL\navg_order_value (users with no purchases) to 0 so the ML model receives a numeric value.\nLEFT JOIN is required so users with no events appear with NULL feature values (to be handled\ndownstream).</p>\n", "hints": ["One pass: use multiple conditional aggregations (SUM(CASE WHEN ...), AVG(CASE WHEN ...)).", "DATEDIFF(day, MAX(event_date), '2025-03-01') gives days since last activity.", "ISNULL(avg_order_value, 0) replaces NULL for users with no purchases."], "order_matters": false}, {"id": "h35", "title": "Fill Missing Prices from Category Average", "difficulty": "Hard", "category": "Filtering & NULL", "companies": ["Amazon", "Walmart", "Shopify"], "tsql": true, "description": "\n<p>Some products at <strong>CatalogCo</strong> are missing prices due to a bad import. For the\nanalytics dashboard, replace NULL prices with the average price of that product's category\n(computed from non-NULL rows only).</p>\n<p><strong>Return columns:</strong> <code>product_id</code>, <code>name</code>,\n<code>category</code>, <code>original_price</code>, <code>effective_price</code>\n(rounded to 2 dp) — ordered by category, name.</p>\n", "schema": "\nCREATE TABLE products (\n    product_id INT PRIMARY KEY,\n    name       VARCHAR(100) NOT NULL,\n    category   VARCHAR(50) NOT NULL,\n    price      DECIMAL(10,2)\n);\nINSERT INTO products VALUES\n (1,'Laptop Pro',    'Electronics', 1299.99),\n (2,'Wireless Mouse','Electronics', 49.99),\n (3,'Keyboard',      'Electronics', NULL),\n (4,'Monitor',       'Electronics', 399.99),\n (5,'Running Shoes', 'Sports',      89.99),\n (6,'Yoga Mat',      'Sports',      NULL),\n (7,'Water Bottle',  'Sports',      24.99),\n (8,'Coffee Maker',  'Kitchen',     NULL),\n (9,'Blender',       'Kitchen',     79.99),\n (10,'Toaster',      'Kitchen',     39.99);\n", "solution": "\nWITH cat_avg AS (\n    SELECT category,\n           AVG(CAST(price AS FLOAT)) AS avg_price\n    FROM products\n    WHERE price IS NOT NULL\n    GROUP BY category\n)\nSELECT p.product_id, p.name, p.category,\n       p.price AS original_price,\n       ROUND(ISNULL(p.price, CAST(a.avg_price AS DECIMAL(10,2))), 2) AS effective_price\nFROM products p\nLEFT JOIN cat_avg a ON a.category = p.category\nORDER BY p.category, p.name;\n", "explanation": "\n<p>Compute category averages excluding NULLs in a CTE (AVG ignores NULLs automatically). LEFT\nJOIN back to the product table so products whose entire category has no prices (edge case) still\nappear. ISNULL(price, category_avg) replaces NULL prices. This is a standard data-cleaning\npattern in staging layers.</p>\n", "hints": ["AVG ignores NULL values automatically — no WHERE needed inside the aggregate.", "LEFT JOIN cat_avg so products in a category with no valid prices still appear.", "ISNULL(price, avg_price) fills the gap."], "order_matters": false}, {"id": "h36", "title": "The NOT IN NULL Trap", "difficulty": "Hard", "category": "Filtering & NULL", "companies": ["dbt", "Fivetran", "Airbyte"], "tsql": true, "description": "\n<p>The data team at <strong>DataVault Co</strong> wants customers who have <em>never</em> placed\nan international order (ship_country &lt;&gt; 'US'). One column in <code>orders.ship_country</code>\nis NULL for some rows.</p>\n<p>Write the correct query using <code>NOT EXISTS</code>. Also demonstrate why\n<code>NOT IN</code> would return 0 rows in this case by using it in a comment.</p>\n<p><strong>Return columns:</strong> <code>customer_id</code>, <code>name</code>\n— ordered by name.</p>\n", "schema": "\nCREATE TABLE customers (customer_id INT PRIMARY KEY, name VARCHAR(100) NOT NULL);\nCREATE TABLE orders (\n    order_id     INT PRIMARY KEY,\n    customer_id  INT NOT NULL,\n    ship_country VARCHAR(10)\n);\nINSERT INTO customers VALUES (1,'Alice'),(2,'Bob'),(3,'Carol'),(4,'Dave');\nINSERT INTO orders VALUES\n (101,1,'US'),(102,1,'US'),(103,1,'CA'),\n (104,2,'US'),(105,2,'US'),\n (106,3,'US'),(107,3,NULL),\n (108,4,'US');\n", "solution": "\n-- Correct: NOT EXISTS is NULL-safe\nSELECT c.customer_id, c.name\nFROM customers c\nWHERE NOT EXISTS (\n    SELECT 1 FROM orders o\n    WHERE o.customer_id = c.customer_id\n      AND o.ship_country <> 'US'\n)\nORDER BY c.name;\n-- Note: NOT IN (SELECT ship_country FROM orders WHERE ship_country <> 'US')\n-- would return 0 rows because ship_country has a NULL, and\n-- x NOT IN (..., NULL) evaluates to UNKNOWN, not TRUE.\n", "explanation": "\n<p>When <code>NOT IN</code>'s subquery returns any NULL, every row in the outer query evaluates\nto UNKNOWN (not TRUE or FALSE) — so no rows are returned. This is the most dangerous NULL trap\nin SQL. NOT EXISTS avoids it because it tests for the existence of a row, not equality. Bob and\nDave have only US orders. Carol has one NULL ship_country order, but no confirmed non-US order,\nso she qualifies. Only Alice, who has a CA order, is excluded.</p>\n", "hints": ["NOT IN fails silently when the subquery contains any NULL.", "NOT EXISTS is NULL-safe — use it for anti-joins when the lookup column can be NULL.", "The condition inside NOT EXISTS is o.ship_country <> 'US', which skips NULLs naturally."], "order_matters": false}, {"id": "h37", "title": "Pipeline Health Check", "difficulty": "Hard", "category": "Data Quality", "companies": ["dbt", "Fivetran", "Databricks"], "tsql": true, "description": "\n<p>The data engineering team at <strong>DataVault Co</strong> runs a suite of data quality checks\nafter each pipeline load. Write a single query that returns one row per check with the check name\nand the number of violations found:</p>\n<ol>\n<li><strong>orphaned_order_items</strong>: items whose order_id has no matching order</li>\n<li><strong>orders_without_items</strong>: orders with no line items</li>\n<li><strong>items_with_zero_quantity</strong>: line items where quantity &lt;= 0</li>\n</ol>\n<p><strong>Return columns:</strong> <code>check_name</code>, <code>violation_count</code>\n— ordered by check_name.</p>\n", "schema": "\nCREATE TABLE orders (order_id INT PRIMARY KEY, customer_id INT NOT NULL, order_date DATE NOT NULL);\nCREATE TABLE order_items (\n    item_id    INT PRIMARY KEY,\n    order_id   INT NOT NULL,\n    product_id INT NOT NULL,\n    quantity   INT NOT NULL\n);\nINSERT INTO orders VALUES\n (1001,1,'2025-01-05'),(1002,2,'2025-01-06'),(1003,3,'2025-01-07'),(1004,4,'2025-01-08');\nINSERT INTO order_items VALUES\n (1,1001,101,2),(2,1001,102,1),\n (3,1002,103,3),\n (4,1005,104,1),\n (5,1006,101,0),\n (6,1003,102,-1);\n", "solution": "\nSELECT 'items_with_zero_quantity' AS check_name,\n       COUNT(*) AS violation_count\nFROM order_items\nWHERE quantity <= 0\nUNION ALL\nSELECT 'orders_without_items',\n       COUNT(*)\nFROM orders o\nWHERE NOT EXISTS (SELECT 1 FROM order_items oi WHERE oi.order_id = o.order_id)\nUNION ALL\nSELECT 'orphaned_order_items',\n       COUNT(*)\nFROM order_items oi\nWHERE NOT EXISTS (SELECT 1 FROM orders o WHERE o.order_id = oi.order_id)\nORDER BY check_name;\n", "explanation": "\n<p>UNION ALL stitches multiple independent checks into a single result set — a common pattern\nfor data quality dashboards. Each branch targets one specific invariant. NOT EXISTS is used for\nreferential integrity checks (safer than LEFT JOIN IS NULL when dealing with NULLable keys).\nIn production, this query runs as a dbt test or a post-load assertion job.</p>\n", "hints": ["UNION ALL three separate checks into one result set.", "Use NOT EXISTS for referential integrity checks — it's NULL-safe.", "WHERE quantity <= 0 catches both zero and negative quantities."], "order_matters": false}];
